pub struct GameSession {
    score: i32,
    session_id: String,
}

impl GameSession {
    pub fn new(session_id: String, score: i32) -> GameSession {
        GameSession { score, session_id }
    }

    pub fn get_score(&self) -> i32 {
        self.score
    }

    pub fn get_session_id(&self) -> &str {
        &self.session_id
    }
}

pub struct EventLogger {
    heap: BinaryHeap<GameSession>,
}

impl EventLogger {
    pub fn new() -> EventLogger {
        EventLogger {
            heap: BinaryHeap::new(),
        }
    }

    pub fn push(&mut self, session: GameSession) {
        self.heap.push(session);
    }

    pub fn pop(&mut self) -> Option<GameSession> {
        self.heap.pop()
    }

    pub fn get_leaderboard(&self) -> Vec<(String, i32)> {
        self.heap
            .into_iter()
            .map(|session| (session.session_id.clone(), session.score))
