pub struct EventLogger {
    heap: BinaryHeap<i32>,
}

impl EventLogger {
    pub fn new() -> Self {
        EventLogger {
            heap: BinaryHeap::new(),
        }
    }

    pub fn push(&mut self, score: i32) {
        if self.heap.len() >= 500 {
            self.heap.pop();
        }
        self.heap.push(score);
    }

    pub fn pop(&mut self) -> Option<i32> {
        self.heap.pop()
    }

    pub fn peek(&self) -> Option<&i32> {
        self.heap.peek()
    }
}

fn main() {
    let mut logger = EventLogger::new();

    logger.push(100);
    logger.push(200);
    logger.push(300);

    println!("{:?}", logger.peek()); // prints Some &300

    println!("{:?}", logger.pop()); // prints Some 300

    logger.push(400);
    logger.push(500);

    println!("{:?}", logger.peek()); // prints Some &500
}
