        self.heap.push(score);
    }

    pub fn pop(&mut self) -> Option<i32> {
        assert!(!self.heap.is_empty());
        self.heap.pop()
    }

    pub fn peek(&self) -> Option<&i32> {
        self.heap.peek()
    }
}

fn main() {
    let mut logger = EventLogger::new();
    logger.push(100);
    logger.push(200);
    logger.push(50);

    println!("{:?}", logger.peek()); // prints Some &50

    println!("{:?}", logger.pop()); // prints Some 50
    println!("{:?}", logger.peek()); // prints Some &100

