import java.util.concurrent.BlockingQueue;
import java.util.concurrent.LinkedBlockingQueue;
import java.util.concurrent.TimeUnit;

public class RealTimeMessaging {
    private final BlockingQueue<Message> priorityQueue;

    public RealTimeMessaging() {
        this.priorityQueue = new LinkedBlockingQueue<>();
    }

    public void addMessage(Message message) {
        priorityQueue.add(message);
    }

    public Message getNextMessage() {
        try {
            return priorityQueue.poll(1, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return null;
        }
    }

    public static class Message implements Comparable<Message> {
        private final String content;
        private final int urgency;

        public Message(String content, int urgency) {
            this.content = content;
            this.urgency = urgency;
        }

        public String getContent() {
            return content;
        }

        public int getUrgency() {
            return urgency;
        }

        @Override
        public int compareTo(Message other) {
            return Integer.compare(other.urgency, urgency);
        }
    }

    public static void main(String[] args) {
        RealTimeMessaging messagingSystem = new RealTimeMessaging();
        messagingSystem.addMessage(new Message("Message 1", 1));
        messagingSystem.addMessage(new Message("Message 2", 2));
        messagingSystem.addMessage(new Message("Message 3", 3));

        while (true) {
            Message nextMessage = messagingSystem.getNextMessage();
            if (nextMessage != null) {
                System.out.println("Received message: " + nextMessage.getContent());
            } else {
                break;
            }
        }
    }
}
