public class RealTimeMessaging {
    private PriorityQueue<Message> queue;
    private int maxCapacity = 100;

    public RealTimeMessaging() {
        this.queue = new PriorityQueue<>();
    }

    public void offer(Message message) {
        if (queue.size() < maxCapacity) {
            queue.add(message);
        } else {
            System.out.println("Queue is full. Dropping message with priority " + message.getPriority());
        }
    }

    public Message poll() {
        if (!queue.isEmpty()) {
            return queue.poll();
        } else {
            return null;
        }
    }

    public static class Message implements Comparable<Message> {
        private String content;
        private int priority;

        public Message(String content, int priority) {
            this.content = content;
            this.priority = priority;
        }

        public String getContent() {
            return content;
        }

        public int getPriority() {
            return priority;
        }

        @Override
        public int compareTo(Message other) {
            return Integer.compare(other.priority, this.priority);
        }
    }

    public static void main(String[] args) {
        RealTimeMessaging messagingSystem = new RealTimeMessaging();

        // Adding messages to the system
        messagingSystem.offer(new RealTimeMessaging.Message("Message 1", 3));
        messagingSystem.offer(new RealTimeMessaging.Message("Message 2", 1));
        messagingSystem.offer(new RealTimeMessaging.Message("Message 3", 2));

        // Retrieving and processing messages
