import java.util.PriorityQueue;

public class RealTimeMessaging {
    private PriorityQueue<Message> queue;
    private int maxCapacity = 100;

    public RealTimeMessaging() {
        this.queue = new PriorityQueue<>();
    }

    public void offer(Message message) {
        if (queue.size() >= maxCapacity) {
            throw new RuntimeException("Queue is full. Cannot add more messages.");
        }
        queue.add(message);
    }

    public Message poll() {
        if (queue.isEmpty()) {
            throw new RuntimeException("Queue is empty. No messages available for processing.");
        }
        return queue.poll();
    }

    public Message peek() {
        if (queue.isEmpty()) {
            throw new RuntimeException("Queue is empty. No messages available for processing.");
        }
        return queue.peek();
    }

    public static class Message implements Comparable<Message> {
        private String content;
        private int priority;

        public Message(String content, int priority) {
            this.content = content;
            this.priority = priority;
        }

        @Override
        public int compareTo(Message other) {
            return Integer.compare(other.priority, this.priority);
        }

        public String getContent() {
            return content;
        }

        public int getPriority() {
            return priority;
        }
    }

    public static void main(String[] args) {
        RealTimeMessaging messagingSystem = new RealTimeMessaging();

        // Adding messages to the system
        messagingSystem.offer(new RealTimeMessaging.Message("Critical error", 1));
        messagingSystem.offer(new RealTimeMessaging.Message("Low priority task", 3));
        messagingSystem.offer(new RealTimeMessaging.Message("High priority task", 2));

        // Retrieving and processing messages
        System.out.println(messagingSystem.poll().getContent());  // High priority task
        System.out.println(messagingSystem.poll().getContent());  // Critical error
        System.out.println(messagingSystem.poll().getContent());  // Low priority task

        // Attempting to add a message when the queue is full
        try {
            messagingSystem.offer(new RealTimeMessaging.Message("New message", 4));
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}
