import java.util.PriorityQueue;

public class RealTimeMessaging {
    private PriorityQueue<Message> queue;
    private int capacity;

    public RealTimeMessaging() {
        this.queue = new PriorityQueue<>();
        this.capacity = 100;
    }

    public void offer(String message, int priority) {
        if (queue.size() >= capacity) {
            throw new RuntimeException("Queue is full. Cannot add more messages.");
        }
        queue.add(new Message(message, priority));
    }

    public String poll() {
        if (queue.isEmpty()) {
            throw new RuntimeException("Queue is empty. No messages to process.");
        }
        return queue.poll().getMessage();
    }

    public String peek() {
        if (queue.isEmpty()) {
            throw new RuntimeException("Queue is empty. No messages to monitor.");
        }
        return queue.peek().getMessage();
    }

    private static class Message implements Comparable<Message> {
        private final String message;
        private final int priority;

        public Message(String message, int priority) {
            this.message = message;
            this.priority = priority;
        }

        public String getMessage() {
            return message;
        }

        @Override
        public int compareTo(Message other) {
            return Integer.compare(other.priority, priority);
        }
    }

    public static void main(String[] args) {
        RealTimeMessaging messagingSystem = new RealTimeMessaging();

        messagingSystem.offer("Critical error: Server down", 1);
        messagingSystem.offer("Warning: Low disk space", 2);
        messagingSystem.offer("Info: New user registered", 3);

        System.out.println(messagingSystem.poll()); // Critical error: Server down
        System.out.println(messagingSystem.peek()); // Warning: Low disk space
        System.out.println(messagingSystem.poll()); // Warning: Low disk space
    }
}
