package main

import (
    "fmt"
    "sync"
    "time"
)

type AttendanceTracker struct {
    students []string
    mu       sync.RWMutex
}

func NewAttendanceTracker() *AttendanceTracker {
    return &AttendanceTracker{
        students: make([]string, 0),
    }
}

func (at *AttendanceTracker) AddStudent(name string) {
    at.mu.Lock()
    at.students = append(at.students, name)
    at.mu.Unlock()
}

func (at *AttendanceTracker) GetStudents() {
    at.mu.RLock()
    defer at.mu.RUnlock()
    fmt.Println(at.students)
}

func (at *AttendanceTracker) GetStudentCount() int {
    at.mu.RLock()
    defer at.mu.RUnlock()
    return len(at.students)
}

func (at *AttendanceTracker) GenerateReport() {
    at.mu.RLock()
    defer at.mu.RUnlock()
    fmt.Println("Student Report:")
    fmt.Println("Total Students:", at.GetStudentCount())
    fmt.Println("Current Students:")
    at.GetStudents()
}

func main() {
    tracker := NewAttendanceTracker()

    go func() {
        for i := 1; i <= 10; i++ {
            tracker.AddStudent(fmt.Sprintf("Student %d", i))
            time.Sleep(1 * time.Second)
        }
    }()

    for i := 1; i <= 5; i++ {
        tracker.GenerateReport()
        time.Sleep(2 * time.Second)
    }
