package main

import (
    "fmt"
    "sync"
    "time"
)

var maxCapacity = 50
var studentList = make([]string, 0)
var mutex = &sync.Mutex{}
var reportMutex = &sync.Mutex{}

func updateStudentList(name string) {
    if len(studentList) < maxCapacity {
        mutex.Lock()
        defer mutex.Unlock()
        studentList = append(studentList, name)
    } else {
        fmt.Println("Maximum capacity reached. New student added to waiting list.")
    }
}

func generateReport() {
    mutex.Lock()
    defer mutex.Unlock()
    reportMutex.Lock()
    defer reportMutex.Unlock()
    report := make([]string, len(studentList))
    copy(report, studentList)
    fmt.Println("Current Student List:")
    for _, student := range studentList {
        fmt.Println(student)
    }
    fmt.Println("Total Students Present:", len(report))
}

func main() {
    go func() {
        time.Sleep(2 * time.Second)
        updateStudentList("John Doe")
        updateStudentList("Jane Doe")
        updateStudentList("Bob Smith")
    }()
    generateReport()
}
