package main

import (
	"fmt"
	"sync"
)

var maxCapacity = 50
var attendanceList []string
var mu sync.Mutex
var presentStudents int

func updateAttendance(name string) {
	mu.Lock()
	if len(attendanceList) < maxCapacity {
		attendanceList = append(attendanceList, name)
		presentStudents++
	} else {
		attendanceList = append(attendanceList, name)
		fmt.Println("Maximum capacity reached. Old student removed.")
		attendanceList = attendanceList[1:]
	}
	mu.Unlock()
}

func copyAttendance() []string {
	return append([]string{}, attendanceList...)
}

func getPresentStudents() int {
	mu.Lock()
	defer mu.Unlock()
	return presentStudents
}

func removeStudent(name string) bool {
	mu.Lock()
	index := -1
	for i, student := range attendanceList {
		if student == name {
			index = i
			break
		}
	}
	if index != -1 {
		attendanceList = append(attendanceList[:index], attendanceList[index+1:]...)
		presentStudents--
		return true
	}
	mu.Unlock()
	return false
}

func main() {
	updateAttendance("John")
	updateAttendance("Alice")
	updateAttendance("Bob")
	fmt.Println(copyAttendance())
	fmt.Println(getPresentStudents())
	fmt.Println(removeStudent("Alice"))
	fmt.Println(copyAttendance())
	fmt.Println(getPresentStudents())
}
