package main

import (
	"fmt"
	"sync"
)

type AttendanceMonitor struct {
	stack  []string
	mu     sync.Mutex
	maxSize int
}

func NewAttendanceMonitor(maxSize int) *AttendanceMonitor {
	return &AttendanceMonitor{
		stack:  make([]string, maxSize),
		mu:     sync.Mutex{},
		maxSize: maxSize,
	}
}

func (m *AttendanceMonitor) AddStudent(student string) {
	m.mu.Lock()
	defer m.mu.Unlock()

	for len(m.stack) < m.maxSize {
		m.stack = append(m.stack, student)
		return
	}
	fmt.Println("Maximum student limit reached.")
}

func (m *AttendanceMonitor) RemoveStudent(student string) bool {
	m.mu.Lock()
	defer m.mu.Unlock()

	for i, s := range m.stack {
		if s == student {
			m.stack = append(m.stack[:i], m.stack[i+1:]...)
			return true
		}
	}
	return false
}

func (m *AttendanceMonitor) GetStudentCount() int {
	m.mu.Lock()
	defer m.mu.Unlock()
	return len(m.stack)
}

func (m *AttendanceMonitor) GetStackCopy() []string {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.stack[:]
}

func main() {
	monitor := NewAttendanceMonitor(50)

	// Add students
	monitor.AddStudent("John")
	monitor.AddStudent("Alice")
	monitor.AddStudent("Bob")

	// Remove a student
	monitor.RemoveStudent("Alice")

	// Get student count
	fmt.Println(monitor.GetStudentCount())

	// Get stack copy for report generation
	copyStack := monitor.GetStackCopy()
	fmt.Println(copyStack)
}
