use std::collections::VecDeque;
use std::time::{SystemTime, UNIX_EPOCH};

struct DocumentTracker {
    history: VecDeque<(String, SystemTime)>,
}

impl DocumentTracker {
    fn new() -> Self {
        Self {
            history: VecDeque::new(),
        }
    }

    fn add_version(&mut self, document: String, timestamp: SystemTime) -> Result<(), &'static str> {
        if self.history.len() >= 100 {
            return Err("Document version limit exceeded");
        }

        let existing_version = self.history.iter().find(|&(ref doc, ref ts)| doc == document && ts == timestamp);
        if existing_version.is_some() {
            return Err("Duplicate timestamp found for the same document");
        }

        self.history.push_back((document, timestamp));
        self.history.make_contiguous();
        self.history.sort_by_key(|&(ref doc, ref ts)| ts);

        Ok(())
    }
}

fn main() {
    let mut tracker = DocumentTracker::new();

    // Test adding versions with unique timestamps
    println!("{}", tracker.add_version("doc1".to_string(), SystemTime::now()).unwrap());
    println!("{}", tracker.add_version("doc2".to_string(), SystemTime::now().add_secs(1)).unwrap());

    // Test adding versions with duplicate timestamps
    println!("{}", tracker.add_version("doc1".to_string(), SystemTime::now()).unwrap()); // Should fail

    // Test adding versions when exceeding the 100-version capacity
    for _ in 0..101 {
        println!("{}", tracker.add_version("doc3".to_string(), SystemTime::now()).unwrap());
    } // Should fail
}
