var reservations = make(map[string][]Reservation)
var maxReservations = 50
var mu sync.Mutex
var totalReservations int

type Reservation struct {
	Date string
	Table int
}

func manageReservations(name string, date string, table int) bool {
	mu.Lock()
	defer mu.Unlock()

	if len(reservations[name]) >= maxReservations {
		return false
	}

	for _, r := range reservations[name] {
		if r.Date == date && r.Table == table {
			return false
		}
	}

	reservations[name] = append(reservations[name], Reservation{Date: date, Table: table})
	totalReservations++

	if totalReservations > maxReservations {
		delete(reservations, name)
		totalReservations--
	}

	return true
}

func cancelReservation(name string, date string, table int) bool {
	mu.Lock()
	defer mu.Unlock()

	for i, r := range reservations[name] {
		if r.Date == date && r.Table == table {
			reservations[name] = append(reservations[name][:i], reservations[name][i+1:]...)
			totalReservations--
			delete(reservations, name)
			return true
		}
	}

	return false
}

func printReservations() {
	mu.Lock()
	defer mu.Unlock()

	fmt.Println("Reservations:")
	for name, reservations := range reservations {
		fmt.Printf("%s:\n", name)
		for _, r := range reservations {
			fmt.Printf("- Date: %s, Table: %d\n", r.Date, r.Table)
		}
		fmt.Println()
	}
}

