package main

import (
	"fmt"
	"sync"
)

type Reservation struct {
	Date  string
	Table int
}

type Waitlist struct {
	Reservations []Reservation
	Mu          sync.Mutex
}

func NewWaitlist() *Waitlist {
	return &Waitlist{
		Reservations: make([]Reservation, 0),
	}
}

func (w *Waitlist) AddReservation(res Reservation) {
	w.Mu.Lock()
	defer w.Mu.Unlock()

	for i, r := range w.Reservations {
		if r.Date == res.Date && r.Table == res.Table {
			w.Reservations = append(w.Reservations[:i], w.Reservations[i+1:]...)
			w.Reservations = append(w.Reservations, res)
			break
		}
	}
}

func (w *Waitlist) GetNextReservation() Reservation {
	w.Mu.Lock()
	defer w.Mu.Unlock()

	if len(w.Reservations) > 0 {
		reservation := w.Reservations[0]
		w.Reservations = w.Reservations[1:]
		return reservation
	}
	return Reservation{}
}

var reservations map[string][]Reservation
var waitlist *Waitlist
var mu sync.Mutex
var activeReservations int

func init() {
	reservations = make(map[string][]Reservation)
	waitlist = NewWaitlist()
	activeReservations = 0
}

func ManageReservations(name string, date string, table int) bool {
	mu.Lock()
	defer mu.Unlock()

	if _, ok := reservations[date]; !ok {
		reservations[date] = make([]Reservation, 0)
	}

	for _, r := range reservations[date] {
		if r.Date == date && r.Table == table {
			return false
		}
	}

	if activeReservations >= 50 {
		if waitlist.GetNextReservation().Date == date && waitlist.GetNextReservation().Table == table {
			return true
		} else {
			return false
		}
	}

	reservations[date] = append(reservations[date], Reservation{Date: date, Table: table})
	activeReservations++
	return true
}

func CancelReservation(name string, date string, table int) bool {
	mu.Lock()
	defer mu.Unlock()

	if _, ok := reservations[date]; ok {
		for i, r := range reservations[date] {
			if r.Date == date && r.Table == table {
				reservations[date] = append(reservations[date][:i], reservations[date][i+1:]...)
				activeReservations--
				delete(reservations, date)
				return true
			}
		}
	}

	return false
}

func PrintReservations() {
	mu.Lock()
	defer mu.Unlock()

	fmt.Println("Active Reservations:")
	for date, reservations := range reservations {
		fmt.Printf("Date: %s\n", date)
		for _, r := range reservations {
			fmt.Printf("Table: %d\n", r.Table)
		}
		fmt.Println()
	}
}

func main() {
	ManageReservations("John", "2024-05-26", 1)
	ManageReservations("Jane", "2024-05-26", 2)
	ManageReservations("Bob", "2024-05-27", 3)
	PrintReservations()
	CancelReservation("John", "2024-05-26", 1)
	PrintReservations()
}
