package main

import (
	"fmt"
	"sync"
)

type ReservationSystem struct {
	reservations map[string][]string
	waitlist    sync.Map
	mu          sync.Mutex
}

func NewReservationSystem() *ReservationSystem {
	return &ReservationSystem{
		reservations: make(map[string][]string),
	}
}

func (rs *ReservationSystem) AddReservation(name string, date string, table int) bool {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	if _, ok := rs.reservations[date]; !ok {
		rs.reservations[date] = []string{name, fmt.Sprintf("Table %d", table)}
		return true
	}

	for _, reservation := range rs.reservations[date] {
		if reservation == fmt.Sprintf("Table %d", table) {
			rs.mu.Lock()
			defer rs.mu.Unlock()
			rs.waitlist.Store(date, name)
			return false
		}
	}

	rs.mu.Lock()
	defer rs.mu.Unlock()
	if len(rs.reservations[date]) < 50 {
		rs.reservations[date] = append(rs.reservations[date], name)
		return true
	} else {
		rs.waitlist.Store(date, name)
		return false
	}
}

func (rs *ReservationSystem) CancelReservation(name string, date string) bool {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	if _, ok := rs.reservations[date]; ok {
		for i, reservation := range rs.reservations[date] {
			if reservation == name {
				delete(rs.reservations[date], i)
				if len(rs.reservations[date]) == 0 {
					delete(rs.reservations, date)
				}
				return true
			}
		}
	}

	if _, ok := rs.waitlist.Load(date); ok {
		name = rs.waitlist.Load(date).(string)
		delete(rs.waitlist, date)
		rs.mu.Lock()
		defer rs.mu.Unlock()
		rs.reservations[date] = append(rs.reservations[date], name)
		return true
	}

	return false
}

func (rs *ReservationSystem) GetReservations(date string) []string {
	rs.mu.RLock()
	defer rs.mu.RUnlock()
	return rs.reservations[date]
}

func main() {
	rs := NewReservationSystem()
	fmt.Println(rs.AddReservation("John", "2024-02-20", 1)) // true
	fmt.Println(rs.AddReservation("Alice", "2024-02-20", 2)) // true
	fmt.Println(rs.AddReservation("Bob", "2024-02-20", 1))   // false
	fmt.Println(rs.GetReservations("2024-02-20"))            // ["John Table 1", "Alice Table 2"]
	fmt.Println(rs.CancelReservation("John", "2024-02-20")) // true
	fmt.Println(rs.GetReservations("2024-02-20"))            // ["Alice Table 2"]
}
