		for i := 0; i < len(i.stocks); i++ {
			if i.stocks[i] == product {
				if quantity <= 0 {
					fmt.Println("Invalid quantity. Please enter a positive integer.")
					return
				}
				i.stocks[i] = quantity
				i.q.Push(i.stocks[:])
				return
			}
		}
		fmt.Println("Product not found in inventory.")
	}
}

func (i *Inventory) PrintInventory() {
	i.mu.Lock()
	defer i.mu.Unlock()

	for i := 0; i < 10; i++ {
		if i < len(i.stocks) {
			fmt.Printf("Product %d: %d\n", i+1, i.stocks[i])
		} else {
			fmt.Printf("Product %d: Out of stock\n", i+1)
		}
	}
}

func main() {
