)

type Inventory struct {
 stocks []int
 mu    sync.Mutex
 size  int
}

func NewInventory() *Inventory {
	return &Inventory{
		stocks: make([]int, 0),
		size:   10,
	}
}

func (i *Inventory) AddStocks(stocks ...int) {
	i.mu.Lock()
	defer i.mu.Unlock()

	for _, stock := range stocks {
		if len(i.stocks) < i.size {
			i.stocks = append(i.stocks, stock)
		} else {
			fmt.Println("Inventory is full. Cannot add more stocks.")
			return
		}
	}
}

func (i *Inventory) UpdateStocks(index int, amount int) {
	i.mu.Lock()
	defer i.mu.Unlock()

	if index >= len(i.stocks) || index < 0 {
		fmt.Println("Invalid index. Cannot update stock.")
		return
	}

	i.stocks[index] += amount
	if i.stocks[index] < 0 {
		fmt.Println("Cannot have negative stock levels.")
		return
	}
}

func (i *Inventory) Copy() []int {
	i.mu.RLock()
	defer i.mu.RUnlock()
	return append(make([]int, len(i.stocks)), i.stocks...)
}

