			}
		}
	} = func(threshold time.Time) {
		deleteOldLogs(threshold)
	}

	// Example usage
	insertLog(time.Now(), "Log entry 1")
	insertLog(time.Now().Add(5 * time.Second), "Log entry 2")
	insertLog(time.Now().Add(10 * time.Second), "Log entry 3")

	fmt.Println(logs)

	deleteOldLogs(time.Now().Add(8 * time.Second))

	fmt.Println(logs)
}

