	return &LogStack{
		stack: make([]LogEntry, 0),
		limit: limit,
	}
}

func (ls *LogStack) Push(timestamp time.Time, message string) error {
	if len(ls.stack) >= ls.limit {
		return fmt.Errorf("log stack is full")
	}
	ls.stack = append(ls.stack, LogEntry{timestamp: timestamp, message: message})
	return nil
}

func (ls *LogStack) Pop(timestamp time.Time) (string, bool) {
	for i, entry := range ls.stack {
		if entry.timestamp.Before(timestamp) {
			logMessage := entry.message
			ls.stack = append(ls.stack[:i], ls.stack[i+1:]...)
			return logMessage, true
		}
	}
	return "", false
}

