	fmt.Printf("Popped log: %s\n", poppedLog)
	fmt.Println(ok)

	poppedLog, ok = logs.Pop(time.Now().Add(5 * time.Second))
	fmt.Printf("Popped log: %s\n", poppedLog)
	fmt.Println(ok)
