#include <iostream>
#include <stack>
#include <string>
#include <stdexcept>

std::string evaluate_postfix(const std::string& expression) {
    std::stack<int> stack;
    for (char c : expression) {
        if (c == ' ') {
            continue;
        }

        if (isdigit(c)) {
            int num = 0;
            while (c != '\0') {
                num = num * 10 + (c - '0');
                c = expression[++expression.find(c)];
            }
            stack.push(num);
        } else if (c == '+' || c == '-' || c == '*' || c == '/') {
            if (stack.size() < 2) {
                throw std::invalid_argument("Invalid symbol");
            }

            int operand2 = stack.top();
            stack.pop();
            int operand1 = stack.top();
            stack.pop();

            int result;
            switch (c) {
                case '+':
                    result = operand1 + operand2;
                    break;
                case '-':
                    result = operand1 - operand2;
                    break;
                case '*':
                    result = operand1 * operand2;
                    break;
                case '/':
                    if (operand2 == 0) {
                        throw std::runtime_error("Division by zero");
                    }
                    result = operand1 / operand2;
                    break;
                default:
                    throw std::invalid_argument("Invalid symbol");
            }

            stack.push(result);
        } else {
            throw std::invalid_argument("Invalid symbol");
        }
    }

    if (stack.size() != 1) {
        throw std::invalid_argument("Invalid expression");
    }

    return std::to_string(stack.top());
}

int main() {
    try {
        std::cout << evaluate_postfix("2 3 +") << std::endl;  // Output: 5
        std::cout << evaluate_postfix("5 3 -") << std::endl;  // Output: 2
        std::cout << evaluate_postfix("4 5 *") << std::endl;  // Output: 20
        std::cout << evaluate_postfix("10 2 /") << std::endl; // Output: 5
        std::cout << evaluate_postfix("10 0 /") << std::endl; // Throws runtime_error
        std::cout << evaluate_postfix("a 2 +") << std::endl;   // Throws invalid_argument
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
