std::string evaluatePostfix(const std::string& expression) {
    static const char* operators = "+-*/";
    std::stack<int> stack;
    size_t pos = 0;

    while (pos < expression.size()) {
        if (expression[pos] == ' ') {
            ++pos;
            continue;
        }

        if (isdigit(expression[pos])) {
            int num = 0;
            while (pos < expression.size() && isdigit(expression[pos])) {
                num = num * 10 + (expression[pos++] - '0');
            }
            if (pos < expression.size()) {
                if (operators[0] == expression[pos]) {
                    return "Error: Invalid symbol at the end of the expression.";
                }
            }
            stack.push(num);
        } else if (std::find(operators, operators + 7, expression[pos]) != operators + 7) {
            return "Error: Invalid symbol '" + expression[pos] + "' in the expression.";
        } else {
            if (stack.size() < 10) {
                throw std::runtime_error("Stack exceeds 10 elements.");
            }

            int operand2 = stack.top();
            stack.pop();
            int operand1 = stack.top();
            stack.pop();

            switch (expression[pos]) {
                case '+':
                    stack.push(operand1 + operand2);
                    break;
                case '-':
                    stack.push(operand1 - operand2);
                    break;
                case '*':
                    stack.push(operand1 * operand2);
                    break;
                case '/':
                    if (operand2 == 0) {
                        return "Error: Division by zero.";
                    }
                    stack.push(operand1 / operand2);
                    break;
            }
        }
    }

    if (stack.size() > 0) {
        return "Error: Unbalanced expression.";
    }

    return std::to_string(stack.top());
}

