    std::cout << evaluatePostfix("10 2 3 - 4 / +") << std::endl;  // Output: Error: Division by zero.
    std::cout << evaluatePostfix("3 4 + 5") << std::endl;  // Output: Error: Unbalanced expression.

    try {
        std::cout << evaluatePostfix("3 4 + 5 ") << std::endl;
