std::string evaluatePostfix(const std::string& expression) {
    const int MAX_STACK_SIZE = 10;
    std::stack<std::string> stack;

    for (char c : expression) {
        if (c == ' ') continue;

        if (c >= '0' && c <= '9') {
            // Handle integers
            std::string num;
            while (c != '\0' && (c >= '0' && c <= '9')) {
                num += c;
                c = expression[++expression.find(c)];
            }
            if (!num.empty()) {
                stack.push(num);
            }
        } else if (c == '+' || c == '-' || c == '*' || c == '/') {
            // Check for division by zero
            if (c == '/' && stack.size() < 2) {
                throw std::runtime_error("Division by zero");
            }

            // Check for invalid symbols
            if (stack.size() > MAX_STACK_SIZE) {
                throw std::out_of_range("Stack size exceeded");
            }

            // Pop two operands from the stack
            std::string operand2 = stack.top();
            stack.pop();
            std::string operand1 = stack.top();
            stack.pop();

            // Perform operation and push result back to the stack
            double result;
            if (c == '+') {
                result = std::stod(operand1) + std::stod(operand2);
            } else if (c == '-') {
                result = std::stod(operand1) - std::stod(operand2);
            } else if (c == '*') {
                result = std::stod(operand1) * std::stod(operand2);
            } else if (c == '/') {
                result = std::stod(operand1) / std::stod(operand2);
            }

            stack.push(std::to_string(result));
        } else {
            // Invalid symbol
            throw std::invalid_argument("Invalid symbol in expression");
        }
    }

    // Check if there's exactly one element left in the stack
    if (stack.size() != 1) {
        throw std::runtime_error("Invalid expression");
    }

    return stack.top();
}

