use std::collections::HashMap;

fn manage_inventory(inventory: &mut HashMap<String, u32>, product: String, quantity: u32, action: &str) {
    match action {
        "insert" => {
            if let Some(existing_quantity) = inventory.get_mut(&product) {
                *existing_quantity += quantity;
            } else {
                inventory.insert(product, quantity);
            }
        },
        "remove" => {
            if let Some(existing_quantity) = inventory.get_mut(&product) {
                if *existing_quantity <= quantity {
                    inventory.remove(&product);
                } else {
                    *existing_quantity -= quantity;
                }
            }
        },
        _ => panic!("Invalid action. Please use 'insert' or 'remove'."),
    }
}

fn main() {
    let mut inventory = HashMap::new();
    manage_inventory(&mut inventory, "Product1".to_string(), 10, "insert");
    manage_inventory(&mut inventory, "Product2".to_string(), 5, "insert");
    manage_inventory(&mut inventory, "Product1".to_string(), 3, "remove");
    println!("{:?}", inventory);
}
