use std::collections::HashMap;
use std::collections::VecDeque;

struct Inventory {
    stock: HashMap<String, usize>,
    queue: VecDeque<(String, usize)>,
}

impl Inventory {
    fn new() -> Self {
        Inventory {
            stock: HashMap::new(),
            queue: VecDeque::new(),
        }
    }

    fn insert(&mut self, product_id: String, quantity: usize) {
        if self.stock.contains_key(&product_id) {
            let current_quantity = *self.stock.get(&product_id).unwrap();
            if current_quantity + quantity > 50 {
                self.remove(product_id);
                self.insert(product_id, quantity);
            } else {
                self.stock.insert(product_id, current_quantity + quantity);
            }
        } else {
            if self.queue.len() >= 50 {
                self.remove_least_recently_updated();
            }
            self.stock.insert(product_id, quantity);
            self.queue.push_back((product_id.clone(), quantity));
        }
    }

    fn remove(&mut self, product_id: String) {
        if let Some(quantity) = self.stock.get_mut(&product_id) {
            if *quantity == 0 {
                self.stock.remove(&product_id);
                self.queue.pop_front();
            } else {
                *quantity -= 1;
            }
        }
    }

    fn get(&self, product_id: &str) -> Option<usize> {
        self.stock.get(product_id).cloned()
    }

    fn remove_least_recently_updated(&mut self) {
        if !self.queue.is_empty() {
            let (product_id, _) = self.queue.pop_front().unwrap();
            self.stock.remove(&product_id);
        }
    }
}
