use std::collections::HashMap;
use std::collections::HashSet;
use std::collections::VecDeque;

struct LRUCache<K, V> {
    cache: HashMap<K, (V, usize)>,
    order: VecDeque<K>,
    capacity: usize,
}

impl<K, V> LRUCache<K, V>
where
    K: Eq + std::hash::Hash,
{
    fn new(capacity: usize) -> Self {
        LRUCache {
            cache: HashMap::new(),
            order: VecDeque::new(),
            capacity,
        }
    }

    fn insert(&mut self, key: K, value: V) {
        if let Some((old_value, _)) = self.cache.get(&key) {
            self.remove(key);
        } else if self.cache.len() >= self.capacity {
            let oldest_key = self.order.pop_front().unwrap();
            self.cache.remove(&oldest_key);
        }
        self.cache.insert(key, (value, self.order.len()));
        self.order.push_back(key);
    }

    fn remove(&mut self, key: K) {
        match self.cache.remove(&key) {
            None => {}
            Some(_) => self.order.pop_back(),
        }
    }

    fn get(&mut self, key: K) -> Option<&V> {
        match self.cache.get(&key) {
            None => None,
            Some((value, _)) => {
                self.order.push_back(key);
                Some(value)
            }
        }
    }
}

fn manage_inventory(product_id: &str, quantity: i32, inventory: &mut LRUCache<String, i32>) {
    match inventory.get(product_id) {
        Some(current_quantity) => {
            if current_quantity > quantity {
                inventory.remove(product_id);
            } else {
                inventory.insert(product_id, quantity);
            }
        }
        None => inventory.insert(product_id.to_string(), quantity),
    }
}

fn main() {
    let mut inventory = LRUCache::new(50);

    manage_inventory("A", 10, &mut inventory);
    manage_inventory("B", 20, &mut inventory);
    manage_inventory("A", 5, &mut inventory);
    println!("{:?}", inventory.cache); // prints the current state of the inventory
}
