import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentLinkedDeque;

public class InventorySystem {
    private ConcurrentHashMap<String, Integer> inventory;
    private ConcurrentLinkedDeque<String> leastRecentlyUsedProducts;
    private int capacity = 50;
    private final Object lock = new Object();

    public InventorySystem() {
        this.inventory = new ConcurrentHashMap<>();
        this.leastRecentlyUsedProducts = new ConcurrentLinkedDeque<>();
    }

    public void addProduct(String productId, int quantity) {
        synchronized (lock) {
            if (!inventory.containsKey(productId)) {
                if (leastRecentlyUsedProducts.size() >= capacity) {
                    String oldestProductId = leastRecentlyUsedProducts.removeFirst();
                    inventory.remove(oldestProductId);
                }
                inventory.put(productId, quantity);
                leastRecentlyUsedProducts.addLast(productId);
            } else {
                int currentQuantity = inventory.get(productId);
                if (currentQuantity + quantity <= capacity) {
                    leastRecentlyUsedProducts.remove(productId);
                    leastRecentlyUsedProducts.addLast(productId);
                    inventory.put(productId, currentQuantity + quantity);
                } else {
                    System.out.println("Not enough stock to fulfill the order.");
                }
            }
        }
    }

    public boolean contains(String productId) {
        synchronized (lock) {
            return inventory.containsKey(productId);
        }
    }

    public int size() {
        synchronized (lock) {
            return inventory.size();
        }
    }

    public static void main(String[] args) {
        InventorySystem inventorySystem = new InventorySystem();
        inventorySystem.addProduct("P001", 10);
        inventorySystem.addProduct("P002", 20);
        System.out.println(inventorySystem.contains("P001")); // true
        System.out.println(inventorySystem.size()); // 2
        inventorySystem.addProduct("P003", 30); // Not enough stock to fulfill the order.
        System.out.println(inventorySystem.contains("P002")); // false
        System.out.println(inventorySystem.size()); // 2
    }
}
