use std::collections::VecDeque;

struct ElevatorScheduler {
    requests: VecDeque<(i32, bool)>,
}

impl ElevatorScheduler {
    fn new() -> Self {
        let mut scheduler = ElevatorScheduler {
            requests: VecDeque::with_capacity(10),
        };
        scheduler
    }

    fn add_request(&mut self, floor: i32, urgent: bool) {
        if self.requests.len() >= 10 {
            panic!("Elevator scheduler is full. Cannot add more requests.");
        }
        self.requests.push_back((floor, urgent));
    }

