use std::collections::VecDeque;

struct FloorRequest {
    floor: i32,
    is_urgent: bool,
}

impl FloorRequest {
    fn new(floor: i32, is_urgent: bool) -> Self {
        FloorRequest { floor, is_urgent }
    }
}

struct ElevatorControlSystem {
    requests: VecDeque<FloorRequest>,
}

impl ElevatorControlSystem {
    fn new() -> Self {
        ElevatorControlSystem {
            requests: VecDeque::with_capacity(10),
        }
    }

    fn add_request(&mut self, floor: i32, is_urgent: bool) {
        if self.requests.len() >= 15 {
            panic!("Elevator system capacity exceeded.");
        }

        let request = FloorRequest::new(floor, is_urgent);
        self.requests.push_back(request);
    }

    fn process_requests(&mut self) {
        while !self.requests.is_empty() {
            if let Some(request) = self.requests.pop_front() {
                if request.is_urgent {
                    println!("Urgent request at floor {}: Processing immediately.", request.floor);
                } else {
                    println!("Normal request at floor {}: Processing after urgent requests.", request.floor);
                }
            } else {
                break;
            }
        }
    }
}

fn main() {
    let mut elevator_system = ElevatorControlSystem::new();

    elevator_system.add_request(5, true); // Urgent request
