    TaskQueue(int size) : maxSize(size) {}

    void addTask(const std::string& task) {
        if (taskList.size() == maxSize) {
            throw std::runtime_error("Task queue is full. Cannot add more tasks.");
        }
        taskList.push_back(task);
    }

    void removeTask() {
        if (taskList.empty()) {
            throw std::runtime_error("Task queue is empty. Cannot remove tasks.");
        }
        taskList.pop_front();
    }

    bool isEmpty() const {
        return taskList.empty();
    }

    bool isFull() const {
        return taskList.size() == maxSize;
    }

    std::string getFrontTask() const {
        if (taskList.empty()) {
            throw std::runtime_error("Task queue is empty.");
        }
        return taskList.front();
    }
};

int main() {
