        TaskQueue queue(10);

        queue.addTask("Task 1");
        queue.addTask("Task 2");
        queue.addTask("Task 3");

        while (!queue.isEmpty()) {
            std::cout << queue.getFrontTask() << std::endl;
            queue.removeTask();
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

