    std::list<std::string> taskList;
    int maxSize;

public:
    TaskQueue(int size) : maxSize(size) {}

    void push(const std::string& task) {
        if (taskList.size() == maxSize) {
            throw std::runtime_error("Task queue is full. Cannot add more tasks.");
        }
        taskList.push_back(task);
    }

    std::string pop() {
        if (taskList.empty()) {
            throw std::runtime_error("Task queue is empty. Cannot remove tasks.");
        }
        std::string frontTask = taskList.front();
        taskList.pop_front();
        return frontTask;
    }
};

int main() {
    try {
        TaskQueue queue(10);

        // Add tasks to the queue
        queue.push("Task 1");
        queue.push("Task 2");
        queue.push("Task 3");

        // Remove tasks from the queue
        std::cout << queue.pop() << std::endl;  // Output: Task 1
        std::cout << queue.pop() << std::endl;  // Output: Task 2

        // Attempting to add a task when the queue is full
        queue.push("Task 4");  // This should throw an exception

        // Attempting to remove a task when the queue is empty
        queue.pop();  // This should throw an exception
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
