class TicketingSystem {
private:
    int ticketCount;
    int* queue;

public:
    TicketingSystem(int capacity) {
        if (capacity <= 0) {
            throw std::invalid_argument("Capacity must be a positive integer.");
        }

        queue = new int[capacity];
        ticketCount = 0;
    }

    ~TicketingSystem() {
        delete[] queue;
    }

    void addTicket(int ticketId) {
        if (ticketCount == queue ? ticketCount : queue.size()) {
            std::cout << "Ticket queue is full. Cannot add new ticket." << std::endl;
            return;
        }

        queue[ticketCount++] = ticketId;
    }

    int processTicket() {
        if (ticketCount == 0) {
            std::cout << "No tickets to process." << std::endl;
            return -1; // Return an error value to indicate no ticket
        }

        int ticketId = queue[0];
        for (int i = 0; i < ticketCount - 1; ++i) {
            queue[i] = queue[i + 1];
        }
        queue[ticketCount - 1] = 0; // Reset the last element to 0
        --ticketCount;
        return ticketId;
    }
};

int main() {
    TicketingSystem system(5);

    system.addTicket(1);
    system.addTicket(2);
    system.addTicket(3);

    std::cout << system.processTicket() << std::endl;  // Output: 1
    std::cout << system.processTicket() << std::endl;  // Output: 2

    return 0;
}
