#include <queue>
#include <mutex>
#include <condition_variable>

class TicketingSystem {
private:
    std::queue<int> ticketQueue;
    std::mutex mtx;
    std::condition_variable cv;

public:
    void pushTicket() {
        std::unique_lock<std::mutex> lock(mtx);
        while (ticketQueue.size() >= 100) {
            cv.wait(lock, [this] { return ticketQueue.empty(); });
        }
        ticketQueue.push(1);
        cv.notify_one();
    }

    int popTicket() {
        std::unique_lock<std::mutex> lock(mtx);
        if (ticketQueue.empty()) {
            return -1; // No tickets available
        }
        int ticket = ticketQueue.front();
        ticketQueue.pop();
        return ticket;
    }

    bool isEmpty() {
        std::lock_guard<std::mutex> lock(mtx);
        return ticketQueue.empty();
    }

    int size() {
        std::lock_guard<std::mutex> lock(mtx);
        return ticketQueue.size();
    }
};

int main() {
    TicketingSystem system;
    system.pushTicket();
    system.pushTicket();
    system.pushTicket();

    std::cout << "Is empty? " << (system.isEmpty() ? "Yes" : "No") << std::endl;
    std::cout << "Size: " << system.size() << std::endl;

