class EventRegistrationSystem:
    def __init__(self):
        self.attendees = {}

    def register(self, attendee, registered=True):
        if attendee in self.attendees:
            self.attendees[attendee]['registered'] = registered
            self.attendees[attendee]['operations'] += 1
            print(f"Attendee {attendee} is already registered.")
        else:
            self.attendees[attendee] = {'registered': registered, 'operations': 1}
            print(f"Attendee {attendee} registered successfully.")

    def get(self, attendee):
        if attendee in self.attendees:
            return self.attendees[attendee]['registered']
        else:
            return None

    def withdraw(self, attendee):
        if attendee in self.attendees:
            if self.attendees[attendee]['operations'] > 1:
                self.attendees[attendee]['operations'] -= 1
                print(f"Attendee {attendee} withdrawn successfully.")
                return True
            else:
                print(f"Attendee {attendee} has already been withdrawn.")
                return False
        else:
            print(f"Attendee {attendee} is not registered.")
            return False


# Example usage
