import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class Playlist {
    private Node head;
    private int size;
    private final Lock lock = new ReentrantLock();
    private final int MAX_SIZE = 50;

    public Playlist() {
        this.head = null;
        this.size = 0;
    }

    public void addFirst(String track) {
        lock.lock();
        try {
            if (size >= MAX_SIZE) {
                removeLast();
            }
            Node newNode = new Node(track, head);
            head = newNode;
            size++;
        } finally {
            lock.unlock();
        }
    }

    public String removeFirst() {
        lock.lock();
        try {
            if (head == null) {
                return null;
            }
            String track = head.track;
            head = head.next;
            size--;
            return track;
        } finally {
            lock.unlock();
        }
    }

    public String peek() {
        lock.lock();
        try {
            if (head == null) {
                return null;
            }
            return head.track;
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return size;
        } finally {
            lock.unlock();
        }
    }

    private void removeLast() {
        lock.lock();
        try {
            if (head == null) {
                return;
            }
            if (head.next == null) {
                head = null;
            } else {
                Node current = head;
                head = head.next;
                while (head != null && current.next != head) {
                    current = current.next;
                }
                current.next = null;
            }
            size--;
        } finally {
            lock.unlock();
        }
    }

    private static class Node {
        String track;
        Node next;

        public Node(String track, Node next) {
            this.track = track;
            this.next = next;
        }
    }

    public static void main(String[] args) {
        Playlist playlist = new Playlist();
        // Test the operations
        playlist.addFirst("Track1");
        playlist.addFirst("Track2");
        System.out.println(playlist.peek());  // Track2
        System.out.println(playlist.removeFirst());  // Track2
        System.out.println(playlist.size());  // 1
        playlist.addFirst("Track3");
        System.out.println(playlist.peek());  // Track3
        System.out.println(playlist.removeFirst());  // Track3
        System.out.println(playlist.size());  // 1
    }
}
