struct CustomerSupport {
    queue: VecDeque<String>,
}

impl CustomerSupport {
    fn new() -> Self {
        CustomerSupport {
            queue: VecDeque::new(),
        }
    }

    fn add_query(&mut self, query: String) {
        if self.queue.len() < 10 {
            self.queue.push_back(query);
        } else {
            println!("Queue is full. Removing oldest query to add new one.");
            self.queue.pop_front();
            self.queue.push_back(query);
        }
    }

    fn check_empty(&self) -> bool {
        self.queue.is_empty()
    }

