    support.add_query("Query 1".to_string());
    support.add_query("Query 2".to_string());
    support.add_query("Query 3".to_string());

    assert!(support.check_empty());

    support.process_oldest_query();

    support.add_query("New Query 1".to_string());
    support.add_query("New Query 2".to_string());
    support.add_query("New Query 3".to_string());

