#include <queue>
#include <mutex>
#include <condition_variable>
#include <stdexcept>

class ConferenceScheduler {
private:
    std::priority_queue<std::pair<double, std::string>> speakers_;
    std::mutex mtx_;
    std::condition_variable cv_;

public:
    void push(const std::string& name, double rating) {
        std::lock_guard<std::mutex> lock(mtx_);
        if (speakers_.size() >= 20) {
            speakers_.pop();
        }
        speakers_.push({rating, name});
        cv_.notify_all();
    }

    void pop() {
        std::unique_lock<std::mutex> lock(mtx_);
        cv_.wait(lock, [this] { return !speakers_.empty(); });
        if (speakers_.empty()) {
            throw std::runtime_error("Queue is empty");
        }
        auto speaker = speakers_.top();
        speakers_.pop();
        cv_.notify_all();
        return speaker.second;
    }

    std::string top() {
        std::lock_guard<std::mutex> lock(mtx_);
        if (speakers_.empty()) {
            throw std::runtime_error("Queue is empty");
        }
        return speakers_.top().second;
    }
};
