	if len(q.list) >= q.capacity {
		return errors.New("queue is full")
	}
	q.list = append(q.list, userId)
	return nil
}

func (q *Queue) PushFront(userId int) error {
	if len(q.list) + 1 > q.capacity {
		return errors.New("queue is full")
	}
	if float64(len(q.list)+1)*0.2 > float64(q.capacity) {
		return errors.New("cannot push front more than 20% of the queue")
	}
	for i := len(q.list); i > 0; i-- {
		q.list[i] = q.list[i-1]
	}
	q.list[0] = userId
	return nil
}

func (q *Queue) Next() (int, bool) {
	if len(q.list) == 0 {
		return 0, false
	}
	next := q.list[0]
	q.list = q.list[1:]
	return next, true
}

