type Queue struct {
	queue []int
	capacity int
	size float64
}

func NewQueue(capacity int) *Queue {
	return &Queue{
		queue: make([]int, 0),
		capacity: capacity,
	}
}

func (q *Queue) pushback(userId int) error {
	if len(q.queue) >= q.capacity*0.7 {
		return errors.New("queue is full")
	}
	q.queue = append(q.queue, userId)
	q.size++
	return nil
}

func (q *Queue) pushfront(userId int) error {
	if len(q.queue) >= q.capacity*0.3 {
		return errors.New("cannot bypass more than 30% of the queue")
	}
	if len(q.queue) >= q.capacity*0.7 {
		return errors.New("queue is full")
	}
	q.queue = append([]int{userId}, q.queue...)
	q.size++
	return nil
}

func (q *Queue) dequeue() (int, bool) {
	if len(q.queue) == 0 {
		return 0, false
	}
	userId := q.queue[0]
	q.queue = q.queue[1:]
	q.size--
	return userId, true
}

func (q *Queue) getQueueSize() float64 {
	return float64(len(q.queue)) / float64(q.capacity)
}

func main() {
	queue := NewQueue(10)
	fmt.Println(queue.getQueueSize()) // prints 0.0

	err := queue.pushback(1)
	fmt.Println(err) // prints nil
	fmt.Println(queue.getQueueSize()) // prints 0.1

	err = queue.pushfront(2)
	fmt.Println(err) // prints nil
	fmt.Println(queue.getQueueSize()) // prints 0.2

