import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.concurrent.atomic.AtomicInteger;

public class InventorySystem {
    private final ConcurrentMap<String, Product> inventory;
    private final AtomicInteger size;
    private final Object lock = new Object();

    public InventorySystem() {
        this.inventory = new ConcurrentHashMap<>();
        this.size = new AtomicInteger(0);
    }

    public void addProduct(String id, int quantity) {
        synchronized (lock) {
            if (size.get() >= 100) {
                removeLeastRecentlyUpdated();
            }
            inventory.put(id, new Product(quantity));
            size.incrementAndGet();
        }
    }

    public void updateQuantity(String id, int newQuantity) {
        synchronized (lock) {
            if (inventory.containsKey(id)) {
                Product product = inventory.get(id);
                product.setQuantity(newQuantity);
                size.decrementAndGet();
                inventory.remove(id);
                inventory.put(id, product);
                size.incrementAndGet();
            } else {
                System.out.println("Product not found in inventory.");
            }
        }
    }

    public int getQuantity(String id) {
        synchronized (lock) {
            if (inventory.containsKey(id)) {
                return inventory.get(id).getQuantity();
            } else {
                System.out.println("Product not found in inventory.");
                return -1;
            }
        }
    }

    public void removeProduct(String id) {
        synchronized (lock) {
            if (inventory.containsKey(id)) {
                inventory.remove(id);
                size.decrementAndGet();
            } else {
                System.out.println("Product not found in inventory.");
            }
        }
    }

    private void removeLeastRecentlyUpdated() {
        synchronized (lock) {
            if (inventory.isEmpty()) {
                return;
            }
            Map.Entry<String, Product> leastRecentlyUpdatedEntry = null;
            for (Map.Entry<String, Product> entry : inventory.entrySet()) {
                if (leastRecentlyUpdatedEntry == null || entry.getValue().getLastUpdate() < leastRecentlyUpdatedEntry.getValue().getLastUpdate()) {
                    leastRecentlyUpdatedEntry = entry;
                }
            }
            String removedId = leastRecentlyUpdatedEntry.getKey();
            inventory.remove(removedId);
            size.decrementAndGet();
        }
    }

    private static class Product {
        private int quantity;
        private long lastUpdate;

        public Product(int quantity) {
            this.quantity = quantity;
            this.lastUpdate = System.currentTimeMillis();
        }

        public int getQuantity() {
            return quantity;
        }

        public void setQuantity(int newQuantity) {
            quantity = newQuantity;
            lastUpdate = System.currentTimeMillis();
        }

        public long getLastUpdate() {
            return lastUpdate;
        }
    }

    public static void main(String[] args) {
        InventorySystem inventorySystem = new InventorySystem();
        inventorySystem.addProduct("P001", 10);
        inventorySystem.addProduct("P002", 20);
        System.out.println(inventorySystem.getQuantity("P001")); // prints: 10
        inventorySystem.updateQuantity("P001", 15);
        System.out.println(inventorySystem.getQuantity("P001")); // prints: 15
        inventorySystem.removeProduct("P002");
        System.out.println(inventorySystem.getQuantity("P002")); // prints: -1
    }
