type TaskStack struct {
	stack []string
	limit int
}

func NewTaskStack(limit int) *TaskStack {
	return &TaskStack{
		stack: make([]string, 0),
		limit: limit,
	}
}

func (ts *TaskStack) Push(task string) error {
	if len(ts.stack) >= ts.limit {
		return errors.New("stack is full")
	}
	ts.stack = append(ts.stack, task)
	return nil
}

func (ts *TaskStack) Pop() (string, error) {
	if len(ts.stack) == 0 {
		return "", errors.New("stack is empty")
	}
	task := ts.stack[len(ts.stack)-1]
	ts.stack = ts.stack[:len(ts.stack)-1]
	return task, nil
}

func main() {
	taskStack := NewTaskStack(10)

	// Add tasks to the stack
	err := taskStack.Push("Task 1")
	fmt.Println(err) // No error

	err = taskStack.Push("Task 2")
	fmt.Println(err) // No error

	err = taskStack.Push("Task 3")
	fmt.Println(err) // No error

	// Try to add more than 10 tasks
	err = taskStack.Push("Task 4")
	fmt.Println(err) // stack is full

	// Remove tasks from the stack
	task, err := taskStack.Pop()
	fmt.Printf("Popped task: %s\n", task) // Popped task: Task 3
	task, err = taskStack.Pop()
	fmt.Printf("Popped task: %s\n", task) // Popped task: Task 2
	task, err = taskStack.Pop()
	fmt.Printf("Popped task: %s\n", task) // Popped task: Task 1
}

