package main

import (
	"fmt"
)

type TaskStack struct {
	stack []string
	capacity int
}

func NewTaskStack(capacity int) *TaskStack {
	return &TaskStack{
		stack: make([]string, capacity),
		capacity: capacity,
	}
}

func (ts *TaskStack) Push(task string) {
	if len(ts.stack) < ts.capacity {
		ts.stack = append(ts.stack, task)
	} else {
		ts.removeOldest()
		ts.stack = append(ts.stack, task)
	}
}

func (ts *TaskStack) Pop() string {
	if len(ts.stack) == 0 {
		return ""
	}
	task := ts.stack[len(ts.stack)-1]
	ts.stack = ts.stack[:len(ts.stack)-1]
	return task
}

func (ts *TaskStack) Peek() string {
	if len(ts.stack) == 0 {
		return ""
	}
	return ts.stack[len(ts.stack)-1]
}

func (ts *TaskStack) removeOldest() {
	if len(ts.stack) > 0 {
		ts.stack = ts.stack[0:len(ts.stack)-1]
	}
}

func main() {
	taskStack := NewTaskStack(10)
	taskStack.Push("Task 1")
	taskStack.Push("Task 2")
	fmt.Println(taskStack.Peek()) // Output: Task 2
	fmt.Println(taskStack.Pop())   // Output: Task 2
	fmt.Println(taskStack.Peek()) // Output: Task 1
}
