#include <vector>
#include <iostream>

class TrainScheduler {
private:
    std::vector<int> schedules;
    const int MAX_CAPACITY = 50;

public:
    void addSchedule(int departureTime) {
        if (schedules.size() < MAX_CAPACITY) {
            schedules.push_back(departureTime);
        } else {
            // Remove the oldest schedule when capacity is reached
            schedules.pop_back();
            schedules.push_back(departureTime);
        }
    }

    void cancelLastSchedule() {
        if (!schedules.empty()) {
            schedules.pop_back();
        }
    }

    int getCurrentCapacity() {
        return schedules.size();
    }

    int getOldestDepartureTime() {
        if (!schedules.empty()) {
            return schedules[0];
        } else {
            return -1; // Return -1 to indicate no schedules
        }
    }
};

int main() {
    TrainScheduler scheduler;

    scheduler.addSchedule(10);
    scheduler.addSchedule(12);
    scheduler.addSchedule(14);

    std::cout << "Current Capacity: " << scheduler.getCurrentCapacity() << std::endl;
    std::cout << "Oldest Departure Time: " << scheduler.getOldestDepartureTime() << std::endl;

    scheduler.cancelLastSchedule();

    std::cout << "Current Capacity: " << scheduler.getCurrentCapacity() << std::endl;
    std::cout << "Oldest Departure Time: " << scheduler.getOldestDepartureTime() << std::endl;

