    var highestScore, lowestScore int
    // Initialize a variable to store the sum of all scores
    var totalScore int = 0

    // Check if the slice is not empty
    if len(scores) > 0 {
        // Initialize variables to store the maximum and minimum indices
        maxIndex := 0
        minIndex := 0

        // Iterate over the slice to find the highest and lowest scores
        for i, score := range scores {
            if score > scores[maxIndex] {
                maxIndex = i
            }
            if score < scores[minIndex] {
