import java.util.HashMap;
import java.util.Map;

public class Main {
    public static int maxNonConsecutiveSum(int[] nums) {
        if (nums.length == 0) {
            return 0;
        }

        Map<Integer, Integer> dp = new HashMap<>();
        dp.put(0, 0);
        int maxSum = 0;

        for (int num : nums) {
            if (dp.size() < 11) {
                int sumWithoutCurrentNum = dp.getOrDefault(num, 0);
                dp.putIfAbsent(num, sumWithoutCurrentNum);
                int sumWithCurrentNum = dp.getOrDefault(dp.size() - 1, 0) + num;
                dp.putIfAbsent(sumWithCurrentNum, sumWithCurrentNum);

                maxSum = Math.max(maxSum, sumWithoutCurrentNum, dp.get(sumWithCurrentNum));
            }
        }

        return maxSum;
