import java.util.Map;

public class Main {
    public static int largestSum(int[] nums) {
        Map<Integer, Integer> map = new HashMap<>();
        map.put(0, -1);
        int maxSum = 0;
        int sum = 0;
        int pushIndex = 0;

        for (int i = 0; i < nums.length; i++) {
            if (map.containsKey(sum)) {
                pushIndex = Math.max(pushIndex, map.get(sum) + 1);
            }
            while (pushIndex < i && sum < 0) {
                sum -= nums[pushIndex];
                pushIndex++;
            }

            if (!map.containsKey(sum)) {
                map.put(sum, i);
            }

            if (sum > maxSum) {
                maxSum = sum;
            }
        }

        return maxSum;
    }

    public static void main(String[] args) {
        int[] nums = {5, 1, 1, 5};
        System.out.println(largestSum(nums));
    }
}
