        relationships.computeIfAbsent(user1, k -> new ArrayList<>()).add(user2);
        relationships.computeIfAbsent(user2, k -> new ArrayList<>()).add(user1);

        if (!followEvents.containsKey(user1)) {
            followEvents.put(user1, new ArrayList<>());
        }
        followEvents.get(user1).add(new FollowEvent(user2, System.currentTimeMillis()));

        if (!followEvents.containsKey(user2)) {
            followEvents.put(user2, new ArrayList<>());
        }
        followEvents.get(user2).add(new FollowEvent(user1, System.currentTimeMillis()));
    }

    public String getLatestCommonFollower(String user1, String user2) {
        List<String> commonFollowers = new ArrayList<>();

        for (String user : relationships.get(user1)) {
            if (relationships.get(user).contains(user2)) {
                commonFollowers.add(user);
            }
        }

        if (commonFollowers.isEmpty()) {
            return null;
        }

        String latestCommonFollower = commonFollowers.get(0);
        for (int i = 1; i < commonFollowers.size(); i++) {
            if (new Date(followEvents.get(user1).get(i).getTime()).before(new Date(followEvents.get(latestCommonFollower).get(i).getTime()))) {
                latestCommonFollower = commonFollowers.get(i);
            }
        }

        return latestCommonFollower;
    }

    public List<String> getSuggestedNewFriends(String user) {
        List<String> suggestedFriends = new ArrayList<>();

        for (String user2 : relationships.get(user)) {
            if (!followEvents.get(user).contains(followEvents.get(user2).get(0))) {
                suggestedFriends.add(user2);
            }
        }

