        if (!users.contains(user1)) {
            users.add(user1);
            relationships.put(user1, new ArrayList<>());
        }
        if (!users.contains(user2)) {
            users.add(user2);
            relationships.put(user2, new ArrayList<>());
        }
        relationships.get(user1).add(relationships.get(user2).size());
        relationships.get(user2).add(relationships.get(user1).size());
        updateMutualConnections(user1, user2);
    }

    public int latestCommonFollower(String user1, String user2) {
        List<Integer> followers1 = relationships.get(user1);
        List<Integer> followers2 = relationships.get(user2);
        int i = 0, j = 0;
        while (i < followers1.size() && j < followers2.size()) {
            if (followers1.get(i) < followers2.get(j)) {
                i++;
            } else if (followers1.get(i) > followers2.get(j)) {
                j++;
            } else {
                return followers1.get(i);
            }
        }
        return -1;
    }

    public List<String> suggestNewFriends(String user) {
