            mutualConnections.put(user1, new ArrayList<>());
        }
        if (!mutualConnections.containsKey(user2)) {
            mutualConnections.put(user2, new ArrayList<>());
        }
        mutualConnections.get(user1).add(user2);
        mutualConnections.get(user2).add(user1);
