        this.relationships = new HashMap<>();
        this.followEvents = new ArrayList<>();

        // Initialize the map with 50 entries to maintain efficient performance and storage management
        for (int i = 0; i < 50; i++) {
            relationships.put("user" + i, new ArrayList<>());
        }
    }

    // Method to add a new follower between two users
    public void follow(String user1, String user2) {
        if (!relationships.containsKey(user1)) {
            relationships.put(user1, new ArrayList<>());
        }
        if (!relationships.containsKey(user2)) {
            relationships.put(user2, new ArrayList<>());
        }

        relationships.get(user1).add(relationships.size());
        relationships.get(user2).add(relationships.size());

        followEvents.add(relationships.size() - 1);
    }

    // Method to get the latest common follower between any two users
    public int latestCommonFollower(String user1, String user2) {
        Set<Integer> set1 = new HashSet<>(relationships.get(user1));
        Set<Integer> set2 = new HashSet<>(relationships.get(user2));

        int commonFollowers = 0;
        for (Integer follower : set1) {
            if (set2.contains(follower)) {
                commonFollowers = follower;
                break;
            }
        }

        return commonFollowers;
    }

    // Method to suggest possible new friends through mutual connections
    public List<String> suggestNewFriends(String user, String targetUser) {
        List<String> suggestedFriends = new ArrayList<>();

        for (String friend : relationships.get(user)) {
            if (friend != targetUser && !relationships.get(targetUser).contains(friend)) {
                suggestedFriends.add(friend);
            }
        }

        return suggestedFriends;
    }

    // Method to print follow events chronologically
