import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class EventScheduler {
    private ConcurrentLinkedQueue<Event> queue;
    private final Lock lock = new ReentrantLock();
    private final int maxSize = 10;

    public EventScheduler() {
        this.queue = new ConcurrentLinkedQueue<>();
    }

    public void addEvent(Event event) {
        lock.lock();
        try {
            if (queue.size() < maxSize) {
                queue.offer(event);
            } else {
                queue.poll();
                queue.offer(event);
            }
        } finally {
            lock.unlock();
        }
    }

    public Event getMostRecentEvent() {
        lock.lock();
        try {
            if (queue.isEmpty()) {
                throw new RuntimeException("No events in the schedule");
            }
            return queue.poll();
        } finally {
            lock.unlock();
        }
    }

    public Event peekMostRecentEvent() {
        lock.lock();
        try {
            if (queue.isEmpty()) {
                throw new RuntimeException("No events in the schedule");
            }
            return queue.peek();
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return queue.size();
        } finally {
            lock.unlock();
        }
    }

    public static class Event {
        private String name;
        private long timestamp;

        public Event(String name, long timestamp) {
            this.name = name;
            this.timestamp = timestamp;
        }

        @Override
        public String toString() {
            return "Event{" +
                    "name='" + name + '\'' +
                    ", timestamp=" + timestamp +
                    '}';
        }
    }

    public static void main(String[] args) throws InterruptedException {
        EventScheduler scheduler = new EventScheduler();

        Thread thread1 = new Thread(() -> {
            scheduler.addEvent(new Event("Event 1", System.currentTimeMillis()));
            scheduler.addEvent(new Event("Event 2", System.currentTimeMillis() - 1000));
            scheduler.addEvent(new Event("Event 3", System.currentTimeMillis() - 2000));
        });

        Thread thread2 = new Thread(() -> {
            scheduler.addEvent(new Event("Event 4", System.currentTimeMillis()));
            scheduler.addEvent(new Event("Event 5", System.currentTimeMillis() - 3000));
        });

        thread1.start();
        thread2.start();

        thread1.join();
        thread2.join();

        while (!scheduler.size() == 0) {
            System.out.println(scheduler.getMostRecentEvent());
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }
}
