        this.activeSessions = new HashSet<>();
        this.timer = new Timer();
    }

    public void addSession(String sessionId) {
        if (activeSessions.size() < MAX_CAPACITY) {
            long timestamp = System.currentTimeMillis();
            activeSessions.add(sessionId);
            System.out.println("Added session " + sessionId + " at " + timestamp + "ms");
            timer.schedule(new TimerTask() {
                @Override
                public void run() {
                    activeSessions.remove(sessionId);
                }
            }, 300000); // remove after 5 minutes
        } else {
            System.out.println("Maximum capacity of sessions reached. Cannot add new session.");
        }
    }

    public void removeSession(String sessionId) {
        if (activeSessions.contains(sessionId)) {
            long timestamp = System.currentTimeMillis();
            activeSessions.remove(sessionId);
            System.out.println("Removed session " + sessionId + " at " + timestamp + "ms");
        } else {
            System.out.println("Session " + sessionId + " does not exist.");
        }
    }

    public static void main(String[] args) {
        SessionManagementSystem sessionManagementSystem = new SessionManagementSystem();
        sessionManagementSystem.addSession("session1");
        sessionManagementSystem.addSession("session2");
        sessionManagementSystem.removeSession("session1");
