use std::collections::BTreeMap;

pub enum StudentOperation {
    Add { id: String, name: String },
    Remove { id: String },
}

pub fn manage_roster() -> BTreeMap<String, String> {
    let mut roster = BTreeMap::new();

    fn add_student(roster: &mut BTreeMap<String, String>, operation: StudentOperation) -> Result<(), String> {
        match operation {
            StudentOperation::Add { id, name } => {
                roster.insert(id.clone(), name.clone());
            }
            StudentOperation::Remove { id } => {
                if let Some(_student) = roster.remove(id) {
                    Ok(())
                } else {
                    Err(format!("Student with ID '{}' not found in the roster.", id))
                }
            }
        }
    }

    let mut add_student = |id: String, name: String| -> Result<(), String> {
        add_student(&mut roster, StudentOperation::Add { id, name })
    };

    let mut remove_student = |id: String| -> Result<(), String> {
        add_student(&mut roster, StudentOperation::Remove { id })
    };

    add_student,
    remove_student,
}

