class GuestList {
private:
    std::stack<std::string> guestStack;
    int capacity;

public:
    GuestList() : capacity(50) {}

    void push(const std::string& guest) {
        if (guestStack.size() == capacity) {
            std::cout << "The guest list is full. Cannot add more guests." << std::endl;
            return;
        }
        guestStack.push(guest);
    }

    std::string pop() {
        if (guestStack.empty()) {
            std::cout << "No guests to remove from the list." << std::endl;
            return "";
        }
        std::string guest = guestStack.top();
        guestStack.pop();
        return guest;
    }
};

int main() {
    GuestList guestList;
    guestList.push("John");
    guestList.push("Jane");
    guestList.push("Bob");

    std::cout << guestList.pop() << std::endl;  // Output: Bob
    std::cout << guestList.pop() << std::endl;  // Output: Jane

