from collections import OrderedDict

class TaskManager:
    def __init__(self, max_tasks=10):
        self.ordered_dict = OrderedDict()
        self.max_tasks = max_tasks

    def add_task(self, task_name, priority):
        if len(self.ordered_dict) >= self.max_tasks:
            self.pop_least_urgent()
        self.ordered_dict[task_name] = priority

    def adjust_priority(self, task_name, new_priority):
        if task_name not in self.ordered_dict:
            raise ValueError("Task does not exist")
        old_priority = self.ordered_dict[task_name]
        del self.ordered_dict[task_name]
        if new_priority < old_priority:
            self.move_to_end(task_name, 1)
        else:
            self.move_to_end(task_name, -1)

    def get_least_urgent(self):
        if not self.ordered_dict:
            return None
        least_urgent_task = next(iter(self.ordered_dict))
        return least_urgent_task

    def pop_least_urgent(self):
        if not self.ordered_dict:
            return None
        least_urgent_task = next(iter(self.ordered_dict))
        del self.ordered_dict[least_urgent_task]

    def move_to_end(self, key, value):
        if key not in self.ordered_dict:
            raise ValueError("Task does not exist")
        if value == 0:
            self.ordered_dict.move_to_end(key)
        elif value > 0:
            self.ordered_dict[key] = value
        else:
            self.pop_least_urgent()

# Example usage:
task_manager = TaskManager()
task_manager.add_task('Task A', 3)
task_manager.add_task('Task B', 2)
task_manager.add_task('Task C', 1)

print(task_manager.get_least_urgent())  # Output: 'Task C'
task_manager.adjust_priority('Task B', 4)
print(task_manager.get_least_urgent())  # Output: 'Task A'
task_manager.pop_least_urgent()
print(task_manager.get_least_urgent())  # Output: None
