class TaskPrioritizer:
    def __init__(self, max_tasks=10):
        self.max_tasks = max_tasks
        self.stack = []

    def push(self, task, priority):
        if len(self.stack) < self.max_tasks:
            self.stack.append((task, priority))
            self.stack.sort(key=lambda x: x[1], reverse=True)
        else:
            self.stack.pop(0)
            self.stack.append((task, priority))
            self.stack.sort(key=lambda x: x[1], reverse=True)

    def pop(self):
        if not self.is_empty():
            return self.stack.pop(0)[0]
        else:
            return None

    def is_empty(self):
        return len(self.stack) == 0

# Example usage:
