use std::thread;

fn count_colors(colors: Vec<String>) -> Result<BTreeMap<String, u32>, String> {
    if colors.len() > 2500 {
        return Err("Input list exceeds the maximum size of 2500 elements".to_string());
    }

    let mut color_map = BTreeMap::new();
    let color_map_lock = Arc::new(Mutex::new(color_map));

    for color in colors {
        let color = color.to_lowercase();
        *color_map_lock.lock().unwrap().entry(color).or_insert(0) += 1;
    }

    if color_map.len() > 100 {
        return Err("The map has exceeded the maximum size of 100 items".to_string());
    }

    Ok(color_map)
}

