public:
    SavingsAccount(double initialBalance, double interestRate)
        : balance(initialBalance), interestRate(interestRate) {}

    void push(Account* account) override {
        if (account != nullptr) {
            account->logAction("Savings account pushed");
            accountStack.push(account);
        } else {
            throw std::invalid_argument("Invalid account object");
        }
    }

    Account* pop() override {
        if (!accountStack.empty()) {
            Account* account = accountStack.top();
            accountStack.pop();
            return account;
        } else {
            throw std::runtime_error("No accounts in the stack");
        }
    }

    double calculateInterest() override {
        return balance * interestRate;
    }

    void logAction(const std::string& action) override {
        std::lock_guard<std::mutex> lock(mtx);
        std::cout << "Savings account: " << action << std::endl;
    }
};

// Checking account class
class CheckingAccount : public Account {
private:
    double balance;
    double overdraftLimit;

