        std::lock_guard<std::mutex> lock(mtx);
        std::cout << "Checking account: " << action << std::endl;
    }
};

// Joint account class
class JointAccount : public Account {
private:
    std::vector<double> owners;
    double balance;
    double interestRate;

public:
    JointAccount(std::vector<double> owners, double initialBalance, double interestRate)
        : owners(owners), balance(initialBalance), interestRate(interestRate) {}

    void push(Account* account) override {
        if (account != nullptr) {
            account->logAction("Joint account pushed");
            accountStack.push(account);
        } else {
