        std::cout << "Joint account: " << action << std::endl;
    }
};

// Account factory function
Account* createAccount(std::string accountType, double initialBalance, double interestRate,
                       std::vector<double> owners = {}, double overdraftLimit = 0.0) {
    if (accountType == "savings") {
        return new SavingsAccount(initialBalance, interestRate);
    } else if (accountType == "checking") {
        return new CheckingAccount(initialBalance, overdraftLimit);
    } else if (accountType == "joint") {
        return new JointAccount(owners, initialBalance, interestRate);
    } else {
        throw std::invalid_argument("Invalid account type");
    }
}

// Thread-safe account operations
void threadSafeOperation(Account* account, const std::string& action) {
    std::lock_guard<std::mutex> lock(account->mtx);
    account->logAction(action);
}

int main() {
    // Create a stack to hold account objects
    std::stack<Account*> accountStack;

    // Create some accounts
    SavingsAccount savingsAccount(1000.0, 0.05);
    CheckingAccount checkingAccount(500.0, 200.0);
    JointAccount jointAccount({1, 2}, 1500.0, 0.03);

    // Push accounts onto the stack
    savingsAccount.push(&savingsAccount);
    checkingAccount.push(&checkingAccount);
    jointAccount.push(&jointAccount);

    // Perform some operations on the accounts
    threadSafeOperation(savingsAccount, "Deposit $1000");
    threadSafeOperation(checkingAccount, "Withdraw $500");
    threadSafeOperation(jointAccount, "Add owner 3");

    // Pop accounts from the stack
    Account* poppedAccount = jointAccount.pop();
    delete poppedAccount;

    // Log the final state of the accounts
    threadSafeOperation(savingsAccount, "Final balance: $" + std::to_string(savingsAccount.calculateInterest()));
    threadSafeOperation(checkingAccount, "Final balance: $" + std::to_string(checkingAccount.balance));
    threadSafeOperation(jointAccount, "Final balance: $" + std::to_string(jointAccount.calculateInterest()));

    // Save the stack state to a file
    std::ofstream file("accounts.txt");
    while (!accountStack.empty()) {
        Account* account = accountStack.top();
        file << account->calculateInterest() << std::endl;
        accountStack.pop();
    }
    file.close();

    return 0;
}
