package main

import (
    "fmt"
    "sync"
)

const (
    maxMessages = 200
)

var (
    messages chan string
    mu       sync.Mutex
    count    int
)

func init() {
    messages = make(chan string, maxMessages)
}

func sendMessage(message string) {
    mu.Lock()
    defer mu.Unlock()

    if count >= maxMessages {
        fmt.Println("Channel is full. Dropping message.")
        return
    }

    messages <- message
    count++
}

func receiveMessage() (string, bool) {
    mu.Lock()
    defer mu.Unlock()

    select {
    case message := <-messages:
        count--
        return message, true
    default:
        return "", false
    }
}

func main() {
    go func() {
        for i := 0; i < 100; i++ {
            sendMessage(fmt.Sprintf("User %d: Hello", i))
        }
    }()

    for {
        message, ok := receiveMessage()
        if !ok {
            break
        }
        fmt.Println(message)
    }
}
