		return
	}

	s.channel <- message
	s.count++
}

func (s *ChatServer) Receive() (string, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()

	select {
	case msg := <-s.channel:
		s.count--
		return msg, true
	default:
		return "", false
	}
}

func main() {
	server := NewChatServer()

	go func() {
		for i := 0; i < 100; i++ {
			server.Send(fmt.Sprintf("User %d: Hello", i))
		}
	}()

	for {
		msg, ok := server.Receive()
		if !ok {
			break
		}
		fmt.Println(msg)
	}
}
