from collections import defaultdict

class Calculator:
    def __init__(self):
        self.cache = defaultdict(lambda: None)
        self.stack = []
        self.size_limit = 1000

    def calculate(self, expression):
        stack = [None]
        i = 0
        while i < len(expression):
            if expression[i].isdigit():
                num = ''
                while i < len(expression) and expression[i].isdigit():
                    num += expression[i]
                    i += 1
                stack.append(int(num))
            elif expression[i] in '+-*/':
                b = stack.pop()
                a = stack.pop()
                result = self.apply_operation(a, b, expression[i])
                stack.append(result)
            elif expression[i] == '(':
                stack.append(None)
                i += 1
            elif expression[i] == ')':
                temp = stack.pop()
                while temp is not None:
                    result = self.apply_operation(temp, stack.pop(), '+')
                    stack.append(result)
                    temp = stack.pop()
                i += 1
            else:
                raise ValueError("Invalid character in expression")

        return stack[0]

    def apply_operation(self, a, b, operation):
        if operation == '+':
            return a + b
        elif operation == '-':
            return a - b
        elif operation == '*':
            return a * b
        elif operation == '/':
            if b == 0:
                raise ZeroDivisionError("Cannot divide by zero")
            return a / b
        else:
            raise ValueError("Invalid operation")

    def push(self, value):
        if len(self.cache) >= self.size_limit:
            self.cache.pop()
        self.cache[value] = None
        self.stack.append(value)

    def pop(self):
        if not self.stack:
            raise IndexError("Stack is empty")
        value = self.stack.pop()
        del self.cache[value]
        return value

calculator = Calculator()

def evaluate_expression(expression):
    return calculator.calculate(expression)

# Test the function
print(evaluate_expression("10+20*3"))  # Output: 70
print(evaluate_expression("(10+20)*3"))  # Output: 90
print(evaluate_expression("10/(2+3)"))  # Output: 2.0
