    private static final int MAX_INACTIVE_TIME = 30; // minutes
    private static final int MAX_OPERATIONS_PER_SESSION = 10;
    private static final int MAX_ALLOWED_OPERATIONS = 10;

    private ConcurrentMap<String, Session> sessions;
    private Lock lock;

    public SessionManager() {
        this.sessions = new ConcurrentHashMap<>();
        this.lock = new ReentrantLock();
    }

    public boolean addSession(String sessionId) {
        if (sessions.size() >= MAX_ACTIVE_SESSIONS) {
            return false;
        }
        sessions.put(sessionId, new Session());
        return true;
    }

    public boolean performOperation(String sessionId, String operation) {
        if (!sessions.containsKey(sessionId)) {
            return false;
        }
        lock.lock();
        try {
            if (sessions.get(sessionId).getOperations().size() >= MAX_OPERATIONS_PER_SESSION) {
                removeInactiveSessions();
                if (sessions.size() >= MAX_ACTIVE_SESSIONS) {
                    return false;
                }
            }
            if (operation.equals("add_operation")) {
                sessions.get(sessionId).getOperations().add(operation);
            } else if (operation.equals("remove_operation")) {
                sessions.get(sessionId).getOperations().remove(operation);
            } else if (operation.equals("update_data")) {
                sessions.get(sessionId).getData().put("key", "value");
            } else if (operation.equals("delete_data")) {
                sessions.get(sessionId).getData().remove("key");
            } else {
                return false;
            }
            return true;
        } finally {
            lock.unlock();
        }
    }

    private void removeInactiveSessions() {
        long currentTime = System.currentTimeMillis() / 1000;
        sessions.entrySet().removeIf(entry -> entry.getValue().getLastActivityTime() + MAX_INACTIVE_TIME * 60 < currentTime);
    }

    private static class Session {
        private ConcurrentMap<String, Object> data;
        private java.util.List<String> operations;
        private long lastActivityTime;

        public Session() {
            this.data = new ConcurrentHashMap<>();
            this.operations = new java.util.ArrayList<>();
            this.lastActivityTime = System.currentTimeMillis() / 1000;
        }

        public void updateLastActivityTime() {
            this.lastActivityTime = System.currentTimeMillis() / 1000;
        }

        public ConcurrentMap<String, Object> getData() {
            return data;
        }

        public java.util.List<String> getOperations() {
            return operations;
        }

        public long getLastActivityTime() {
            return lastActivityTime;
        }
    }
