        this.maxOperations = 10;
        this.maxSessions = 500;
        this.maxCapacity = 1000;
    }

    public boolean addSession(String sessionId) {
        if (sessions.size() >= maxSessions) {
            return false;
        }
        if (sessions.size() >= maxCapacity) {
            throw new RuntimeException("Maximum capacity reached");
        }
        sessions.put(sessionId, System.currentTimeMillis());
        return true;
    }

    public boolean performOperation(String sessionId, String operation) {
        if (!sessions.containsKey(sessionId)) {
            return false;
        }
        if (operation.equals("get") || operation.equals("update")) {
            sessions.put(sessionId, System.currentTimeMillis());
            return true;
        } else if (operation.equals("delete")) {
            sessions.remove(sessionId);
            return true;
        } else {
            return false;
        }
    }

    public void removeInactiveSessions() {
        long threshold = System.currentTimeMillis() - 30 * 60 * 1000;
        for (String sessionId : sessions.keySet()) {
            if (sessions.get(sessionId) < threshold) {
                sessions.remove(sessionId);
            }
        }
    }

