import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class SessionManager {
    private static final int MAX_CAPACITY = 1000;
    private static final int MAX_OPERATIONS = 10;
    private static final int SESSION_EXPIRATION_TIME = 60; // in seconds

    private ConcurrentMap<String, SessionData> sessions;
    private Lock lock;
    private int operationCount;

    public SessionManager() {
        this.sessions = new ConcurrentHashMap<>();
        this.lock = new ReentrantLock();
        this.operationCount = 0;
    }

    private class SessionData {
        long timestamp;
        boolean expired;

        public SessionData(long timestamp) {
            this.timestamp = timestamp;
            this.expired = false;
        }
    }

    private void limitOperations() {
        if (operationCount >= MAX_OPERATIONS) {
            throw new RuntimeException("Maximum operations reached. Cannot perform more than " + MAX_OPERATIONS + " operations.");
        }
    }

    private void expireSession(String sessionId) {
        sessions.remove(sessionId);
        operationCount--;
    }

    private void updateSession(String sessionId, String data) {
        SessionData sessionData = sessions.get(sessionId);
        if (sessionData != null) {
            sessionData.timestamp = System.currentTimeMillis();
            sessions.put(sessionId, sessionData);
            operationCount++;
        } else {
            throw new RuntimeException("Session not found.");
        }
    }

    private void createSession(String sessionId) {
        if (sessions.size() >= MAX_CAPACITY) {
            throw new RuntimeException("Maximum capacity reached. Cannot create more than " + MAX_CAPACITY + " sessions.");
        }
        sessions.put(sessionId, new SessionData(System.currentTimeMillis()));
        operationCount++;
    }

    private void readSession(String sessionId) {
        SessionData sessionData = sessions.get(sessionId);
        if (sessionData != null) {
            operationCount++;
        } else {
            throw new RuntimeException("Session not found.");
        }
    }

    private void deleteSession(String sessionId) {
        sessions.remove(sessionId);
        operationCount--;
    }

    public void performOperation(String sessionId, String operation, String data) {
        try {
            lock.lock();
            limitOperations();

            switch (operation) {
                case "create":
                    createSession(sessionId);
                    break;
                case "read":
                    readSession(sessionId);
                    break;
                case "update":
                    updateSession(sessionId, data);
                    break;
                case "delete":
                    deleteSession(sessionId);
                    break;
                case "expire":
                    expireSession(sessionId);
                    break;
                default:
                    throw new RuntimeException("Invalid operation.");
            }
        } finally {
            lock.unlock();
        }
    }

    public static void main(String[] args) {
        SessionManager sessionManager = new SessionManager();
        sessionManager.performOperation("session1", "create", "");
        sessionManager.performOperation("session2", "create", "");
        sessionManager.performOperation("session1", "read", "");
        sessionManager.performOperation("session3", "update", "data");
        sessionManager.performOperation("session1", "delete", "");
        sessionManager.performOperation("session2", "expire", "");
    }
}
