import java.util.PriorityQueue;

public class LinkedListMerger {
    public static void mergeSortedLinkedLists(LinkedList[] linkedLists) {
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();

        for (LinkedList list : linkedLists) {
            if (list != null && !list.isEmpty()) {
                minHeap.offer(list.head.data);
            }
        }

        LinkedList mergedList = new LinkedList();

        while (!minHeap.isEmpty()) {
            int minValue = minHeap.poll();
            mergedList.add(minValue);

            LinkedList currentList = findNextNodeWithMinValue(linkedLists, minValue);

            if (currentList != null && !currentList.isEmpty()) {
                minHeap.offer(currentList.head.data);
            }
        }

