    Node next;

    public Node(int data) {
        this.data = data;
        this.next = null;
    }
}

public class LinkedList {
    private Node head;
    private int size;
    private PriorityQueue<Integer> minHeap;

    public LinkedList() {
        this.head = null;
        this.size = 0;
        this.minHeap = new PriorityQueue<>();
    }

    public void add(int data) {
        if (size < 10) {
            Node newNode = new Node(data);
            if (head == null) {
                head = newNode;
            } else {
                Node lastNode = head;
                while (lastNode.next != null) {
                    lastNode = lastNode.next;
                }
                lastNode.next = newNode;
            }
            minHeap.offer(data);
            size++;
        } else {
            throw new RuntimeException("List is full. Cannot add more elements.");
        }
    }

    public void offer(int data) {
        add(data);
    }

    public void mergeSortedLinkedLists(LinkedList... linkedLists) {
        for (LinkedList list : linkedLists) {
            if (list != null) {
                while (!list.minHeap.isEmpty()) {
                    minHeap.offer(list.minHeap.poll());
                }
            }
        }
        while (!minHeap.isEmpty()) {
            add(minHeap.poll());
        }
    }

    public void printList() {
        Node temp = head;
        while (temp != null) {
            System.out.print(temp.data + " ");
            temp = temp.next;
        }
        System.out.println();
    }

    public static void main(String[] args) {
        LinkedList list1 = new LinkedList();
        list1.add(5);
        list1.add(3);
        list1.add(8);

        LinkedList list2 = new LinkedList();
        list2.add(2);
        list2.add(4);
        list2.add(6);

        LinkedList list3 = new LinkedList();
        list3.add(1);
        list3.add(7);
        list3.add(9);

        list1.mergeSortedLinkedLists(list2, list3);
        list1.printList();
    }
}
