        while (!mergedList.isEmpty()) {
            System.out.print(mergedList.poll() + " ");
        }
    }

    public static LinkedList mergeSortedLinkedLists(LinkedList... lists) {
        if (lists.length == 0) {
            return null;
        }

        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        for (LinkedList list : lists) {
            if (list != null && !list.isEmpty()) {
                minHeap.offer(list.poll());
            }
        }

        LinkedList mergedList = new LinkedList();

        while (!minHeap.isEmpty()) {
            mergedList.offer(minHeap.poll());
            if (mergedList.size() < 10) {
                continue;
            }

            while (!minHeap.isEmpty()) {
                mergedList.offer(minHeap.poll());
                if (mergedList.size() >= 10) {
                    break;
                }
            }
        }

        return mergedList;
    }

    private static class LinkedList {
        private int size;
        private int[] elements;

        public LinkedList() {
            this.elements = new int[10000];
            this.size = 0;
        }

        public boolean isEmpty() {
            return size == 0;
        }

        public void offer(int element) {
            if (size < 10000) {
                elements[size] = element;
                size++;
            } else {
                throw new RuntimeException("The linked list has reached its maximum capacity.");
            }
        }

        public int poll() {
            if (isEmpty()) {
                throw new RuntimeException("The linked list is empty.");
            }
            return elements[0];
        }

        public int size() {
            return size;
        }
    }
