var maxStudents = 2000

func addStudent(name, grade string) bool {
	if len(studentRecords) >= maxStudents {
		return false
	}
	if _, ok := studentRecords[name]; ok {
		return false
	}
	studentRecords[name] = Student{Name: name, Grade: parseInt(grade)}
	return true
}

func updateStudent(name, grade string) bool {
	if _, ok := studentRecords[name]; !ok {
		return false
	}
	studentRecords[name].Grade = parseInt(grade)
	return true
}

func listStudents() {
	for _, record := range studentRecords {
		fmt.Printf("%s - %d\n", record.Name, record.Grade)
	}
}

func removeStudent(name string) bool {
	if _, ok := studentRecords[name]; !ok {
		return false
	}
	delete(studentRecords, name)
	return true
}

func parseInt(s string) (int, error) {
	var i int
	if i, err := fmt.Sscan(s, &i); err != nil {
		return 0, err
	} else if i < 0 || i > 100 {
		return 0, fmt.Errorf("invalid grade value")
	}
	return i, nil
}

