package main

import (
	"errors"
	"fmt"
)

type StudentGrade struct {
	Name  string
	Grade int
}

type GradeManager struct {
	grades []StudentGrade
	maxSize int
}

func NewGradeManager(maxSize int) *GradeManager {
	return &GradeManager{
		grades: make([]StudentGrade, maxSize),
		maxSize: maxSize,
	}
}

func (gm *GradeManager) AddGrade(name string, grade int) error {
	if len(gm.grades) >= gm.maxSize {
		return errors.New("maximum size exceeded")
	}

	for _, student := range gm.grades {
		if student.Name == name {
			return fmt.Errorf("student with name '%s' already exists", name)
		}
	}

	if name == "" {
		return errors.New("student name cannot be empty")
	}

	if grade < 0 || grade > 100 {
		return fmt.Errorf("grade must be between 0 and 100")
	}

	gm.grades = append(gm.grades, StudentGrade{Name: name, Grade: grade})
	return nil
}

func (gm *GradeManager) UpdateGrade(name string, grade int) error {
	for index, student := range gm.grades {
		if student.Name == name {
			if grade < 0 || grade > 100 {
				return fmt.Errorf("grade must be between 0 and 100")
			}

			gm.grades[index].Grade = grade
			return nil
		}
	}

	return fmt.Errorf("student with name '%s' does not exist", name)
}

func (gm *GradeManager) ListGrades() {
	for _, student := range gm.grades {
		fmt.Printf("%s: %d\n", student.Name, student.Grade)
	}
}

func (gm *GradeManager) RemoveStudent(name string) error {
	for index, student := range gm.grades {
		if student.Name == name {
			gm.grades = append(gm.grades[:index], gm.grades[index+1:]...)
			return nil
		}
	}

	return fmt.Errorf("student with name '%s' does not exist", name)
}

func main() {
	gradeManager := NewGradeManager(2000)

	// Add grades
	err := gradeManager.AddGrade("John Doe", 85)
	if err != nil {
		fmt.Println(err)
		return
	}

	err = gradeManager.AddGrade("Jane Doe", 90)
	if err != nil {
		fmt.Println(err)
		return
	}

	// List grades
	gradeManager.ListGrades()

	// Update grade
	err = gradeManager.UpdateGrade("John Doe", 95)
	if err != nil {
		fmt.Println(err)
		return
	}

	// List grades after update
	gradeManager.ListGrades()

	// Remove student
	err = gradeManager.RemoveStudent("Jane Doe")
	if err != nil {
		fmt.Println(err)
		return
	}

	// List grades after removal
	gradeManager.ListGrades()
}
