package main

import (
	"errors"
	"fmt"
)

type StudentGrade struct {
	Name  string
	Grade int
}

type GradeStack struct {
	stack []StudentGrade
	maxSize int
}

func NewGradeStack(maxSize int) *GradeStack {
	return &GradeStack{
		stack: make([]StudentGrade, maxSize),
		maxSize: maxSize,
	}
}

func (g *GradeStack) Push(name string, grade int) error {
	if len(g.stack) >= g.maxSize {
		return errors.New("stack is full")
	}

	for i := len(g.stack) - 1; i >= 0; i-- {
		if g.stack[i].Name == name && g.stack[i].Grade == grade {
			return errors.New("student name already exists at the top of the stack")
		}
	}

	g.stack = append(g.stack, StudentGrade{Name: name, Grade: grade})
	return nil
}

func (g *GradeStack) Update(name string, grade int) error {
	for i := range g.stack {
		if g.stack[i].Name == name {
			if grade < 0 || grade > 100 {
				return errors.New("grade must be between 0 and 100")
			}
			g.stack[i].Grade = grade
			return nil
		}
	}

	return errors.New("student not found in the stack")
}

func (g *GradeStack) Pop() (*StudentGrade, error) {
	if len(g.stack) == 0 {
		return nil, errors.New("stack is empty")
	}

	top := g.stack[len(g.stack)-1]
	g.stack = g.stack[:len(g.stack)-1]
	return &top, nil
}

func (g *GradeStack) GetGrades() []StudentGrade {
	return g.stack
}

func main() {
	stack := NewGradeStack(2000)

	stack.Push("John Doe", 85)
	stack.Push("Jane Doe", 90)
	stack.Push("John Doe", 95) // duplicate student name

	fmt.Println(stack.GetGrades())

	updated := stack.Update("John Doe", 92)
	if updated != nil {
		fmt.Println(updated)
	}

	popped, err := stack.Pop()
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Printf("Popped: %+v\n", popped)
	}

	fmt.Println(stack.GetGrades())
}
