use std::collections::HashSet;

fn max_non_adjacent_sum(nums: Vec<i32>) -> i32 {
    let max_size = 1500;
    let mut dp: Vec<i32> = vec![0; nums.len() + 1];
    let mut sums: HashSet<i32> = HashSet::new();

    dp[0] = 0;
    for i in 1..=nums.len() {
        dp[i] = std::cmp::max(nums[i - 1] + dp[i - 1], dp[i - 1]);
        let mut key = dp[i];
        if sums.len() < max_size {
            sums.insert(key);
        } else if !sums.contains(&key) {
            sums.remove(&dp[i - 2]);
            sums.insert(key);
        }
    }
    dp[nums.len()]
}

fn main() {
    let nums = vec![2, 4, 6, 2, 5];
    println!("{}", max_non_adjacent_sum(nums));
}
