use std::collections::HashSet;

fn max_sum(nums: Vec<i32>, memo: &mut HashSet<i32>) -> i32 {
    if nums.is_empty() {
        return 0;
    }
    if let Some(&sum) = memo.get(&nums[0]) {
        return sum;
    }
    let mut max_incl = nums[0];
    let mut max_excl = 0;
    for &num in &nums[1..] {
        let incl = max_sum(nums.iter().skip(1), memo) + num;
        let excl = max_excl;
        if incl > excl {
            max_incl = incl;
        } else {
            max_excl = excl;
        }
    }
    memo.insert(max_incl);
    max_incl
}

fn main() {
    let nums = vec![2, 4, 6, 2, 5];
    let mut memo = HashSet::new();
    println!("{}", max_sum(nums.clone(), &mut memo));
}
