fn max_non_adjacent_sum(nums: Vec<i32>) -> i32 {
    let mut dp = vec![0; nums.len() + 1];
    dp[0] = 0;
    dp[1] = nums[0];

    let mut sums = HashSet::with_capacity(750);
    sums.insert(0);

    for i in 2..=nums.len() {
        if !sums.contains(&(dp[i - 1])) {
            dp[i] = dp[i - 1];
        } else {
            let include_current = dp[i - 1] + nums[i - 1];
            let exclude_current = dp[i - 2];

            if include_current > exclude_current {
                dp[i] = include_current;
            } else {
                dp[i] = exclude_current;
            }
        }

        sums.insert(dp[i]);
    }

    *dp.iter().max().unwrap()
}

fn main() {
    let nums = vec![5, 1, 1, 5];
    println!("Maximum sum of non-adjacent elements is {}", max_non_adjacent_sum(nums));
}
