use std::collections::HashSet;

fn max_non_adjacent_sum(nums: Vec<i32>, capacity: usize) -> i32 {
    let mut dp = vec![0; nums.len() + 1];
    dp[0] = 0;
    let mut memo = HashSet::with_capacity(capacity);
    memo.insert(0);

    for i in 1..=nums.len() {
        if i <= 2 {
            dp[i] = nums[i - 1];
        } else {
            let include_current = *memo.iter().max().unwrap();
            let exclude_current = dp[i - 1];
            dp[i] = std::cmp::max(include_current, exclude_current);
            if dp[i] == include_current {
                memo.insert(dp[i]);
            }
        }
    }

    dp[nums.len()]
}

fn main() {
    let nums = vec![5, 1, 1, 5];
    let capacity = 750;
    println!("Maximum sum of non-adjacent elements is {}", max_non_adjacent_sum(nums, capacity));
}
