    std::map<std::string, std::vector<std::pair<int, int>>> airlineFlights;
    int maxFlightsPerAirline;

public:
    FlightReservationSystem() : maxFlightsPerAirline(300) {}

    void addFlight(const std::string& airline, int flightNumber, int seatsAvailable) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            if (airlineFlights[airline].size() < maxFlightsPerAirline) {
                airlineFlights[airline].push_back({flightNumber, seatsAvailable});
                std::cout << "Flight added successfully." << std::endl;
            } else {
                std::cout << "Maximum number of flights reached for this airline." << std::endl;
            }
        } else {
            airlineFlights[airline] = {{flightNumber, seatsAvailable}};
            std::cout << "New airline added successfully." << std::endl;
        }
    }

    void removeFlight(const std::string& airline, int flightNumber) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            for (auto it = airlineFlights[airline].begin(); it != airlineFlights[airline].end(); ++it) {
                if (it->first == flightNumber) {
                    airlineFlights[airline].erase(it);
                    std::cout << "Flight removed successfully." << std::endl;
                    return;
                }
            }
            std::cout << "Flight not found or already cancelled." << std::endl;
        } else {
            std::cout << "Airline not found." << std::endl;
        }
    }

    void checkAvailability(const std::string& airline, int flightNumber) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            for (const auto& flight : airlineFlights[airline]) {
                if (flight.first == flightNumber) {
                    std::cout << "Seats available: " << flight.second << std::endl;
                    return;
                }
            }
            std::cout << "Flight not found or already booked." << std::endl;
        } else {
            std::cout << "Airline not found." << std::endl;
        }
    }

    void bookSeat(const std::string& airline, int flightNumber, int passengerName) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            for (auto it = airlineFlights[airline].begin(); it != airlineFlights[airline].end(); ++it) {
                if (it->first == flightNumber) {
                    if (it->second > 0) {
                        it->second--;
                        std::cout << "Seat booked successfully for " << passengerName << "." << std::endl;
                    } else {
                        std::cout << "All seats are booked. Overbooking is not allowed." << std::endl;
                    }
                    return;
                }
            }
            std::cout << "Flight not found or already booked." << std::endl;
        } else {
            std::cout << "Airline not found." << std::endl;
        }
    }

    void cancelBooking(const std::string& airline, int flightNumber, const std::string& passengerName) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            for (auto it = airlineFlights[airline].begin(); it != airlineFlights[airline].end(); ++it) {
                if (it->first == flightNumber) {
                    if (it->second > 0) {
                        it->second++;
                        std::cout << "Booking cancelled successfully for " << passengerName << "." << std::endl;
                    } else {
                        std::cout << "No booking to cancel." << std::endl;
                    }
                    return;
                }
            }
            std::cout << "Flight not found or no booking to cancel." << std::endl;
        } else {
            std::cout << "Airline not found." << std::endl;
        }
    }
};

int main() {
