    system.addFlight("Air India", 102, 250);
    system.checkAvailability("Air India", 101);
    system.bookSeat("Air India", 101, "John Doe");
    system.cancelBooking("Air India", 101, "John Doe");
    system.removeFlight("Air India", 101);

    return 0;
}
