class FlightReservationSystem {
private:
    std::map<std::string, std::vector<std::pair<int, int>>> airlineFlights;
    std::map<std::string, int> reservations;

public:
    void addAirline(const std::string& airline) {
        if (airlineFlights.find(airline) == airlineFlights.end()) {
            airlineFlights[airline] = {};
            for (int i = 0; i < 300; ++i) {
                airlineFlights[airline].push_back({-1, -1});
            }
        } else {
            throw std::invalid_argument("Airline already exists.");
        }
    }

    void removeAirline(const std::string& airline) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            airlineFlights.erase(airline);
        } else {
            throw std::invalid_argument("Airline does not exist.");
        }
    }

    void addFlight(const std::string& airline, int flightNumber, int seatsAvailable) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            if (seatsAvailable >= 0 && seatsAvailable <= 300) {
                airlineFlights[airline][flightNumber - 1] = {airline, seatsAvailable};
            } else {
                throw std::out_of_range("Invalid number of seats available.");
            }
        } else {
            throw std::invalid_argument("Airline does not exist.");
        }
    }

    void removeFlight(const std::string& airline, int flightNumber) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            if (flightNumber > 0 && flightNumber <= airlineFlights[airline].size()) {
                airlineFlights[airline][flightNumber - 1] = {-1, -1};
            } else {
                throw std::out_of_range("Invalid flight number.");
            }
        } else {
            throw std::invalid_argument("Airline does not exist.");
        }
    }

    void checkAvailability(const std::string& airline, int flightNumber) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            if (flightNumber > 0 && flightNumber <= airlineFlights[airline].size()) {
                auto& flight = airlineFlights[airline][flightNumber - 1];
                if (flight.first != "-1" && flight.second > 0) {
                    std::cout << "Flight " << flightNumber << " on " << airline << " is available." << std::endl;
                } else {
                    std::cout << "Flight " << flightNumber << " on " << airline << " is not available." << std::endl;
                }
            } else {
                throw std::out_of_range("Invalid flight number.");
            }
        } else {
            throw std::invalid_argument("Airline does not exist.");
        }
    }

    void makeReservation(const std::string& airline, int flightNumber, int passengerCount) {
        if (airlineFlights.find(airline) != airlineFlights.end()) {
            if (flightNumber > 0 && flightNumber <= airlineFlights[airline].size()) {
                auto& flight = airlineFlights[airline][flightNumber - 1];
                if (flight.first != "-1" && flight.second >= passengerCount) {
                    flight.second -= passengerCount;
                    reservations[airline + "-" + std::to_string(flightNumber)] = passengerCount;
                    std::cout << "Reservation made successfully." << std::endl;
                } else {
                    throw std::out_of_range("Not enough seats available.");
                }
            } else {
                throw std::out_of_range("Invalid flight number.");
            }
        } else {
            throw std::invalid_argument("Airline does not exist.");
        }
    }

    void cancelReservation(const std::string& airline, int flightNumber) {
        if (reservations.find(airline + "-" + std::to_string(flightNumber)) != reservations.end()) {
            int passengerCount = reservations[airline + "-" + std::to_string(flightNumber)];
            reservations.erase(airline + "-" + std::to_string(flightNumber));
            auto& flight = airlineFlights[airline][flightNumber - 1];
            if (flight.first != "-1") {
                flight.second += passengerCount;
                std::cout << "Reservation cancelled successfully." << std::endl;
            } else {
                std::cout << "No reservation found for this flight." << std::endl;
            }
        } else {
            throw std::invalid_argument("No reservation found for this flight.");
        }
    }

    void clearReservations() {
        reservations.clear();
        for (auto& airline : airlineFlights) {
            for (auto& flight : airline.second) {
                flight.second = 300;
            }
        }
    }
};

int main() {
    FlightReservationSystem system;
    system.addAirline("Air India");
    system.addFlight("Air India", 101, 200);
    system.makeReservation("Air India", 101, 50);
    system.checkAvailability("Air India", 101);
    system.cancelReservation("Air India", 101);
    system.checkAvailability("Air India", 101);
    system.clearReservations();
    return 0;
}
