struct Task {
    description: String,
    completed: bool,
}

impl Task {
    fn new(description: &str) -> Self {
        Task {
            description: description.to_string(),
            completed: false,
        }
    }

    fn mark_completed(&mut self) {
        self.completed = true;
    }
}

struct CLI {
    tasks: VecDeque<Task>,
}

impl CLI {
    fn new() -> Self {
        CLI {
            tasks: VecDeque::new(),
        }
    }

    fn add_task(&mut self, task: Task) {
        if self.tasks.len() >= 50 {
            self.tasks.pop_back();
        }
        self.tasks.push_front(task);
    }

    fn remove_task(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            return None;
        }
        let task = self.tasks.pop_back().unwrap();
        Some(task)
    }

    fn view_tasks(&self) {
        for (i, task) in self.tasks.iter().enumerate() {
            println!("{}: {}", i + 1, task.description);
        }
    }

    fn prioritize_tasks(&mut self) {
        self.tasks.retain(|task| !task.completed);
    }

    fn save_to_file(&self, filename: &str) {
        let file = File::create(filename).unwrap();
        let mut writer = BufWriter::new(file);
        for task in self.tasks.iter() {
            writeln!(writer, "{}: {}", task.description, task.completed).unwrap();
        }
    }

    fn load_from_file(&mut self, filename: &str) {
        let file = File::open(filename).unwrap();
        let reader = std::io::BufReader::new(file);
        for line in reader.lines() {
            let line = line.unwrap();
            let parts: Vec<&str> = line.split(': ').collect();
            if parts.len() == 2 {
                let task = Task::new(parts[0].trim());
                task.mark_completed();
                self.add_task(task);
            }
        }
    }
}

