class FrequencyCounter:
    def __init__(self, max_unique_entries=1000):
        self.max_unique_entries = max_unique_entries
        self.frequency_dict = {}
        self.unique_count = 0

    def update(self, item):
        if self.unique_count < self.max_unique_entries and item not in self.frequency_dict:
            self.frequency_dict[item] = 1
            self.unique_count += 1
        elif self.unique_count == self.max_unique_entries and item not in self.frequency_dict:
            # Remove the least frequent item to make space for the new one
            min_freq_item = min(self.frequency_dict, key=self.frequency_dict.get)
            del self.frequency_dict[min_freq_item]
            self.frequency_dict[item] = 1
            self.unique_count -= 1

    def get_frequency(self, item):
        return self.frequency_dict.get(item, 0)


def count_frequencies(input_list):
    counter = FrequencyCounter()
    for item in input_list:
        counter.update(item)
    return counter.frequency_dict


