// Define the possible movements in the grid (up, down, left, right)
const vector<pair<int, int>> movements = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

// Function to calculate the shortest path using dynamic programming
int shortestPath(unordered_set<pair<int, int>>& visited, const vector<vector<bool>>& grid) {
    // Get the number of rows and columns in the grid
    int rows = grid.size();
    int cols = grid[0].size();

    // Create a queue for BFS and add the starting point
    unordered_set<pair<int, int>> queue;
    queue.insert({0, 0});

    // Mark the starting point as visited
    visited.insert({0, 0});

    // Initialize the distance to the starting point as 0
    int distance = 0;

    // Directions to move in the grid
    vector<pair<int, int>> directions = movements;

    while (!queue.empty()) {
        // Dequeue all adjacent cells at the current distance
        int size = queue.size();
        for (int i = 0; i < size; ++i) {
            auto cell = *queue.begin();
            queue.erase(queue.begin());

            // Explore neighbors
            for (const auto& direction : directions) {
                int row = cell.first + direction.first;
                int col = cell.second + direction.second;

                // Check if the neighbor is within bounds and not visited before
                if (row >= 0 && row < rows && col >= 0 && col < cols && !visited.count({row, col})) {
                    // Mark the neighbor as visited and enqueue it
                    visited.insert({row, col});
                    queue.insert({row, col});

                    // Update the distance if the neighbor is closer
                    if (distance + 1 < abs(row - cell.first) + abs(col - cell.second)) {
                        distance = abs(row - cell.first) + abs(col - cell.second);
                    }
                }
            }
        }
    }

    return distance;
}

int main() {
    // Example usage:
    vector<vector<bool>> grid = {
        {false, false, true, false},
        {true, true, true, false},
        {false, false, false, true},
        {false, true, true, false}
    };

    unordered_set<pair<int, int>> visited;
    cout << "Shortest Path: " << shortestPath(visited, grid) << endl;

