#include <iostream>
#include <unordered_set>
#include <vector>

using namespace std;

// Define the possible movements in the grid (up, down, left, right)
const vector<pair<int, int>> movements = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

// Function to check if a position is within the grid boundaries
bool isValidPosition(int x, int y, int rows, int cols) {
    return (x >= 0 && x < rows && y >= 0 && y < cols);
}

// Dynamic programming function to calculate the shortest path using A* algorithm
int shortestPath(unordered_set<pair<int, int>>& visited, const vector<vector<bool>>& grid, int startRow, int startCol) {
    unordered_set<pair<int, int>> openSet;
    openSet.insert({startRow, startCol});

    while (!openSet.empty()) {
        // Find the node with the lowest f-score in the open set
        auto it = min_element(openSet.begin(), openSet.end(),
            [&grid](const pair<int, int>& a, const pair<int, int>& b) {
                return grid[a.first][a.second] + abs(a.first - startRow) + abs(a.second - startCol) <
                       grid[b.first][b.second] + abs(b.first - startRow) + abs(b.second - startCol);
            });

        if (it == openSet.end() || !isValidPosition(it->first, it->second, grid.size(), grid[0].size())) {
            break;
        }

        int row = it->first;
        int col = it->second;

        // If we've reached the goal, return the distance
        if (grid[row][col]) {
            return grid[row][col];
        }

        // Mark the current node as visited and remove it from the open set
        visited.insert({row, col});
        openSet.erase(it);

        // Explore neighbors
        for (const auto& movement : movements) {
            int newRow = row + movement.first;
            int newCol = col + movement.second;

            if (isValidPosition(newRow, newCol, grid.size(), grid[0].size()) &&
                !visited.find({newRow, newCol}) && !grid[newRow][newCol]) {
                openSet.insert({newRow, newCol});
            }
        }
    }

    // If no path is found, return -1
    return -1;
}

int main() {
    int rows = 10;
    int cols = 10;
    vector<vector<bool>> grid(rows, vector<bool>(cols, false));

    // Set some cells to true to represent obstacles
    grid[3][3] = true;
    grid[5][5] = true;
    grid[7][7] = true;

    int startRow = 0;
    int startCol = 0;

    unordered_set<pair<int, int>> visited;

    int shortestDistance = shortestPath(visited, grid, startRow, startCol);

    cout << "Shortest distance: " << shortestDistance << endl;

    return 0;
}
