#include <iostream>
#include <vector>
#include <unordered_set>
#include <limits>

using namespace std;

struct Point {
    int x, y;
};

int shortestPath(vector<vector<int>>& grid) {
    const int rows = grid.size();
    const int cols = grid[0].size();

    unordered_set<Point> visited;
    vector<vector<int>> distances(rows, vector<int>(cols, numeric_limits<int>::max()));
    distances[0][0] = 0;

    auto addPointToVisited = [&](const Point& point) {
        visited.insert(point);
    };

    auto removePointFromVisited = [&](const Point& point) {
        visited.erase(point);
    };

    auto isWithinBounds = [&](const Point& point) {
        return 0 <= point.x && point.x < rows && 0 <= point.y && point.y < cols;
    };

    auto getNeighbors = [&](const Point& point) {
        vector<Point> neighbors;
        if (isWithinBounds({point.x - 1, point.y})) neighbors.push_back({point.x - 1, point.y});
        if (isWithinBounds({point.x + 1, point.y})) neighbors.push_back({point.x + 1, point.y});
        if (isWithinBounds({point.x, point.y - 1})) neighbors.push_back({point.x, point.y - 1});
        if (isWithinBounds({point.x, point.y + 1})) neighbors.push_back({point.x, point.y + 1});
        return neighbors;
    };

    auto updateDistances = [&](const Point& point) {
        for (const auto& neighbor : getNeighbors(point)) {
            if (distances[neighbor.x][neighbor.y] > distances[point.x][point.y] + grid[neighbor.x][neighbor.y]) {
                distances[neighbor.x][neighbor.y] = distances[point.x][point.y] + grid[neighbor.x][neighbor.y];
                addPointToVisited(neighbor);
            }
        }
    };

    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            if (!visited.count({i, j})) {
                updateDistances({i, j});
            }
        }
    }

    int minDistance = numeric_limits<int>::max();
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            if (distances[i][j] < minDistance) minDistance = distances[i][j];
        }
    }

    return minDistance == numeric_limits<int>::max() ? -1 : minDistance;
}

int main() {
    vector<vector<int>> grid = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};
    cout << shortestPath(grid) << endl;
    return 0;
}
