import java.util.ArrayList;
import java.util.HashMap;

public class FileCache {
    private ArrayList<HashMap<String, Object>> cache;
    private int maxFiles;

    public FileCache(int maxFiles) {
        this.maxFiles = maxFiles;
        this.cache = new ArrayList<>();
    }

    public void addFile(String filename, long lastModified, long fileSize) {
        if (cache.size() < maxFiles) {
            HashMap<String, Object> fileMetadata = new HashMap<>();
            fileMetadata.put("filename", filename);
            fileMetadata.put("lastModified", lastModified);
            fileMetadata.put("fileSize", fileSize);
            cache.add(fileMetadata);
        } else {
            // Remove the oldest file from the cache before adding a new one
            cache.remove(0);
            addFile(filename, lastModified, fileSize);
        }
    }

    public HashMap<String, Object> getFileMetadata(String filename) {
        for (HashMap<String, Object> file : cache) {
            if ((String) file.get("filename").equals(filename)) {
                return file;
            }
        }
        return null;
    }

    public void removeFile(String filename) {
        for (int i = 0; i < cache.size(); i++) {
            if ((String) cache.get(i).get("filename").equals(filename)) {
                cache.remove(i);
                break;
            }
        }
    }

    public static void main(String[] args) {
        FileCache cache = new FileCache(1000);

        cache.addFile("file1.txt", System.currentTimeMillis(), 1024);
        cache.addFile("file2.txt", System.currentTimeMillis(), 2048);

        HashMap<String, Object> metadata = cache.getFileMetadata("file1.txt");
        System.out.println(metadata);

        cache.removeFile("file1.txt");

        metadata = cache.getFileMetadata("file1.txt");
        System.out.println(metadata);
    }
}
