public class FileCache {
    private final List<File> fileObjects;
    private final int capacity;

    public FileCache(int capacity) {
        this.capacity = capacity;
        this.fileObjects = new ArrayList<>(capacity);
    }

    public void addFile(File file) {
        if (fileObjects.size() < capacity) {
            fileObjects.add(file);
        } else {
            throw new RuntimeException("Capacity exceeded");
        }
    }

    public File getFile(String filename) {
        for (File file : fileObjects) {
            if (file.filename.equals(filename)) {
                return file;
            }
        }
        return null;
    }

    public void removeFile(String filename) {
        fileObjects.removeIf(file -> file.filename.equals(filename));
    }

    public static void main(String[] args) {
        FileCache cache = new FileCache(1000);

        File file1 = new File("file1.txt", 1643723900, 1024);
        File file2 = new File("file2.txt", 1643723910, 2048);

        cache.addFile(file1);
        cache.addFile(file2);

