package main

import (
    "context"
    "fmt"
    "log"

    "github.com/google/bufio"
)

const (
    maxBufferSize = 1000
    maxBufferSize  = int(maxBufferSize * 1024)
)

type Temperature struct {
    SensorID string
    Temperature float64
}

func main() {
    // Create a logger
    log.Logger = log.New(
        bufio.NewBufferedWriter(bufio.NewBufferedWriterSize(maxBufferSize)),
        "", // prefix
        log.LstdFlags|log.Lshortfile,
    )

    ctx := context.Background()

    // Initialize the buffer
    var buffer bufio.Reader
    if err := buffer.ReadFrom(ctx, []byte{}); err != nil {
        log.Fatal(err)
    }

    // Process temperature data
    for {
        select {
        case <-ctx.Done():
            return
        default:
            // Read from the buffer
            tempData, err := buffer.ReadString('\n')
            if err != nil {
                log.Println("Error reading from buffer:", err)
                continue
            }
            log.Println("Received temperature data:", string(tempData))

            // Parse temperature data
            var temps []Temperature
            for _, line := range strings.Split(string(tempData), "\n") {
                if len(line) == 0 {
                    continue
                }
                parts := strings.SplitN(line, ",", 2)
                if len(parts) != 2 {
                    log.Println("Invalid temperature data format:", line)
                    continue
                }
                sensorID, temperature := parts[0], float64(parts[1])
                temps = append(temps, Temperature{sensorID, temperature})
            }

            // Compute moving average
            if len(temps) > 0 {
                avgTemp := computeMovingAverage(temps)
                log.Println("Moving average temperature:", avgTemp)
            } else {
                log.Println("No temperature data available.")
            }
        }
    }
}

func computeMovingAverage(temps []Temperature) (float64, error) {
    // Check conditions
    if len(temps) < 3 {
        return 0, fmt.Errorf("not enough temperature data")
    }

    // Initialize the sum and count
    sum := 0.0
    count := 0

    // Compute the moving average
    for i := len(temps) - 1; i >= 0; i-- {
        sum += temps[i].Temperature
        count++
        if count > maxBufferSize {
            break
        }
    }

    // Handle overflow scenario
    if count > maxBufferSize {
        return 0, fmt.Errorf("overflow: too many temperature data points")
    }

    // Calculate the moving average
    avgTemp := sum / float64(count)

    return avgTemp, nil
}
