    }()

    wg.Wait()
}

func processTemperatureData() {
    // Initialize the buffer with a maximum size of maxBufferSize
    buffer := bufio.NewBuffer(make([]byte, maxBufferSize))

    // Create a mutex for synchronization
    mu := &sync.Mutex{}

    // Initialize the moving average values
    avgValue := 0.0
    count := 0

    // Process temperature data from multiple sensors
    for i := 0; i < 10; i++ {
        // Simulate reading temperature data from a sensor
        temp := getTemperatureData(i)

        // Add the temperature data to the buffer
        addTemperatureToBuffer(buffer, temp)

        // Update the moving average
        updateMovingAverage(buffer, &avgValue, &count)
    }

    // Log the final moving average
    log.Printf("%s: Final Moving Average = %f\n", logLevel, avgValue)
}

func getTemperatureData(sensorID int) Temperature {
    // Simulate getting temperature data from a sensor
    return Temperature{Value: float64(sensorID)}
}

func addTemperatureToBuffer(buffer *bufio.Buffer, temp Temperature) {
    // Check if the buffer is full
    if buffer.Len() >= maxBufferSize {
        log.Printf("%s: Buffer overflow detected. Removing oldest entry.\n", logLevel)
        removeOldestEntry(buffer)
    }

    // Add the temperature data to the buffer
    mu.Lock()
    buffer.Push(temp.Value)
    mu.Unlock()
}

func removeOldestEntry(buffer *bufio.Buffer) {
    // Remove the oldest entry from the buffer
    oldestEntry := buffer.Peek()
    buffer.Pop()
    buffer.Unpeek()
}

func updateMovingAverage(buffer *bufio.Buffer, avgValue *float64, count *int) {
    // Calculate the moving average
    sum := 0.0
    for i := 0; i < buffer.Len(); i++ {
        sum += buffer.Peek()[i]
    }
    avgValue *= 0.9
    avgValue += sum / float64(*count)
    *count++
}
