package main

import (
	"log"
	"sync"

	"github.com/google/bufio"
)

const (
	maxCapacity = 20
	maxEntries  = 1000
)

type Temperature struct {
	Temperature float64 `json:"temperature"`
}

type SensorData struct {
	Temperature Temperature `json:"temperature"`
}

func main() {
	sensorData := make(chan SensorData, maxEntries)
	buffer := bufio.NewBuffer(make([]byte, 0, maxCapacity*4))

	var wg sync.WaitGroup
	wg.Add(1)

	go func() {
		defer wg.Done()
		for data := range sensorData {
			if err := processTemperature(data); err != nil {
				log.Printf("Error processing temperature: %v", err)
			}
		}
	}()

	go func() {
		for i := 0; i < maxEntries; i++ {
			sensorData <- SensorData{Temperature: Temperature{i + 1}}
			if i%10 == 0 {
				log.Println("Adding new temperature reading")
			}
		}
		close(sensorData)
	}()

	wg.Wait()

	if buffer.Len() > 0 {
		log.Println("Buffer is not empty after processing all entries")
	} else {
		log.Println("All entries processed successfully")
	}

	log.Println("Exiting application")
}

func processTemperature(data SensorData) error {
	buffer.Push(data.Temperature)
	if buffer.Len() > maxCapacity {
		log.Printf("Warning: Buffer capacity exceeded. Discarding oldest entry.")
		buffer.Pop()
		return nil
	}
	return nil
}
