#include <iostream>
#include <stack>

class MaxSubarraySum {
private:
    std::stack<int> stack;
    int max_sum = 0;

public:
    int calculate_max_sum(int arr[], int size) {
        if (size == 0) {
            return 0;
        }

        for (int i = 0; i < size; i++) {
            while (!stack.empty() && stack.top() <= arr[i]) {
                stack.pop();
            }
            stack.push(arr[i]);

            if (i == stack.top()) {
                max_sum = std::max(max_sum, static_cast<int>(arr[i] - stack.at(0)));
            } else if (i > stack.top()) {
                max_sum = std::max(max_sum, static_cast<int>(arr[i] + stack.top()));
            }
        }

        return max_sum;
    }
};

int main() {
    int arr[] = {2, 1, -1, 3, 4, -1};
    int size = sizeof(arr) / sizeof(arr[0]);
    MaxSubarraySum max_subarray_sum;
    std::cout << "Maximum sum of any contiguous subarray: " << max_subarray_sum.calculate_max_sum(arr, size) << std::endl;
    return 0;
}
