func fibonacci(n int, memo sync.Map) (int, bool) {
    if n <= 0 {
        return 0, true
    }
    if n == 1 {
        return 1, true
    }
    if val, ok := memo.Load(n); ok {
        return val.(int), true
    }
    result, _ := fibonacci(n-1, memo)
    result, _ = fibonacci(n-2, memo)
    result := result + val.(int)
    memo.Store(n, result)
    return result, true
}

func main() {
    var memo sync.Map
    for i := 0; i < 1000; i++ {
        val, _ := fibonacci(i, &memo)
        fmt.Printf("Fibonacci number for %d is %d\n", i, val)
    }
}
