    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<>> pq;

    int total_size = 0;
    for (const auto& array : arrays) {
        total_size += array.size();
        if (total_size > 10000) {
            throw std::invalid_argument("The total size of all arrays exceeds 10,000 elements.");
        }
    }

    for (const auto& array : arrays) {
        pq.push({array[0], array.size()});
    }

    while (!pq.empty()) {
        auto [value, size] = pq.top();
        pq.pop();
        merged_array.push_back(value);
        if (size > 1) {
            pq.push({array[value + 1], size - 1});
        }
    }

    return merged_array;
