std::vector<int> merge_sorted_arrays(const std::vector<std::vector<int>>& arrays) {
    const int max_size = 10000;
    std::priority_queue<int, std::vector<int>, std::greater<int>> pq;

    for (const auto& array : arrays) {
        if (!array.empty()) {
            pq.push(array[0]);
        }
    }

    std::vector<int> result;
    while (!pq.empty() || !arrays.empty()) {
        if (!pq.empty()) {
            result.push_back(pq.top());
            pq.pop();
        }

        // Find the next element from the non-empty array with the smallest top element
        int min_idx = -1;
        int min_val = INT_MAX;
        for (int i = 0; i < arrays.size(); ++i) {
            if (!arrays[i].empty() && arrays[i][0] < min_val) {
                min_idx = i;
                min_val = arrays[i][0];
            }
        }

        if (min_idx != -1) {
            pq.push(arrays[min_idx][0]);
            arrays[min_idx].erase(arrays[min_idx].begin());
        } else {
            break;
        }
    }

    return result;
