                    pq.push({array.back(), i});
                    break;
                }
            }
        }

        std::vector<int> result;
        while (!pq.empty()) {
            auto [element, array_index] = pq.top();
            pq.pop();

            result.push_back(element);

            if (++arrays[array_index].size() == max_length) {
                pq.push({arrays[array_index].back(), array_index});
            }
        }

        return result;
