#include <queue>
#include <vector>
#include <iostream>

std::vector<int> merge_sorted_arrays(const std::vector<std::vector<int>>& arrays) {
    const int max_size = 10000;
    const int max_queue_size = 100;

    // Initialize the priority queue and the result vector
    std::priority_queue<int, std::vector<int>, std::greater<int>> pq;
    std::vector<int> result(max_size);

    // Initialize counters for the result vector and the priority queue
    int result_index = 0;
    int pq_index = 0;

    // Push elements from each array into the priority queue
    for (const auto& array : arrays) {
        for (int element : array) {
            if (pq.size() < max_queue_size) {
                pq.push(element);
            } else {
                break;
            }
        }
    }

    // Merge elements from the priority queue into the result vector
    while (!pq.empty()) {
        result[result_index++] = pq.top();
        pq.pop();

        // If the priority queue is not empty, push the next element into it
        if (!pq.empty()) {
            pq.push(pq.top());
            pq.pop();
        }
    }

    return result;
}

// Example usage:
int main() {
    std::vector<std::vector<int>> arrays = {{1, 3, 5}, {2, 4, 6}, {7, 8, 9}};
    std::vector<int> merged_array = merge_sorted_arrays(arrays);

    // Print the merged array
    for (int element : merged_array) {
        std::cout << element << " ";
    }
    std::cout << std::endl;

    return 0;
}
