import java.util.PriorityQueue;
import java.util.concurrent.ConcurrentLinkedQueue;

class Task {
    int priority;
    long duration;

    public Task(int priority, long duration) {
        this.priority = priority;
        this.duration = duration;
    }
}

public class TaskExecutor {
    private final ConcurrentLinkedQueue<Task> taskQueue;
    private final PriorityQueue<Task> priorityQueue;

    public TaskExecutor() {
        this.taskQueue = new ConcurrentLinkedQueue<>();
        this.priorityQueue = new PriorityQueue<>((a, b) -> Integer.compare(b.priority, a.priority));
    }

    public void addTask(Task task) {
        if (taskQueue.size() < 100) {
            taskQueue.add(task);
            priorityQueue.add(task);
        } else {
            throw new RuntimeException("Queue is full. Cannot add more tasks.");
        }
    }

    public long executeTasks() throws InterruptedException {
        long totalTime = 0;
        while (!taskQueue.isEmpty()) {
            Task task = priorityQueue.poll();
            try {
                Thread.sleep(task.duration);
                totalTime += task.duration;
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                throw new RuntimeException(e);
            }
        }
        return totalTime;
    }

    public static void main(String[] args) throws InterruptedException {
        TaskExecutor executor = new TaskExecutor();
        executor.addTask(new Task(1, 1000));
        executor.addTask(new Task(2, 500));
        executor.addTask(new Task(3, 2000));
        executor.addTask(new Task(4, 1500));

        long totalTime = executor.executeTasks();
        System.out.println("Total time taken to execute all tasks: " + totalTime + " milliseconds");
    }
}
