import java.util.PriorityQueue;
import java.util.concurrent.atomic.AtomicLong;

public class TaskProcessor {
    private final PriorityQueue<Task> queue;
    private final AtomicLong totalTime;

    public TaskProcessor() {
        this.queue = new PriorityQueue<>();
        this.totalTime = new AtomicLong(0);
    }

    public void addTask(Task task) {
        if (queue.size() + 1 > 100) {
            throw new RuntimeException("Queue capacity exceeded");
        }
        queue.add(task);
    }

    public Task pollTask() {
        if (queue.isEmpty()) {
            return null;
        }
        return queue.poll();
    }

    public Task peekTask() {
        if (queue.isEmpty()) {
            return null;
        }
        return queue.peek();
    }

    public void clearQueue() {
        while (!queue.isEmpty()) {
            queue.poll();
        }
    }

    public long getTotalTime() {
        return totalTime.get();
    }

    public static class Task implements Comparable<Task> {
        int priority;
        long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }

        @Override
        public int compareTo(Task other) {
            return Integer.compare(other.priority, this.priority);
        }
    }

    public static void main(String[] args) {
        TaskProcessor processor = new TaskProcessor();

        // Add tasks to the queue
        processor.addTask(new Task(3, 100));
        processor.addTask(new Task(2, 200));
        processor.addTask(new Task(1, 300));

        // Process tasks
        while (!processor.queue.isEmpty()) {
            Task task = processor.pollTask();
            System.out.println("Processing task with priority " + task.priority + " and duration " + task.duration + "ms");
            processor.totalTime.addAndGet(task.duration);
        }

        // Clear the queue
        processor.clearQueue();

        // Get total time taken
        System.out.println("Total time taken: " + processor.getTotalTime() + "ms");
    }
}
