class Product {
public:
    std::string name;
    double price;
    std::string genre;

    Product(std::string n, double p, std::string g) : name(n), price(p), genre(g) {}
};

class Stack {
private:
    std::stack<Product> products;

public:
    void push(Product product) {
        if (products.size() < 150) {
            products.push(product);
        } else {
            std::cout << "Stack is full. Cannot add more products." << std::endl;
        }
    }

    void pop() {
        if (!products.empty()) {
            products.pop();
        } else {
            std::cout << "Stack is empty. Cannot remove products." << std::endl;
        }
    }

    bool isEmpty() {
        return products.empty();
    }

    bool isFull() {
        return products.size() == 150;
    }

    void displayProducts() {
        while (!isEmpty()) {
            std::cout << "Name: " << products.top().name << ", Price: " << products.top().price << ", Genre: " << products.top().genre << std::endl;
            pop();
        }
    }
};

class Bookstore {
private:
    std::stack<Product> productCatalog;
    std::map<std::string, double> discounts;

public:
    void addProduct(Product product) {
        productCatalog.push(product);
    }

    void removeProduct(std::string productName) {
        auto it = std::find_if(productCatalog.begin(), productCatalog.end(),
            [&productName](const Product& product) { return product.name == productName; });
        if (it != productCatalog.end()) {
            productCatalog.pop();
        } else {
            std::cout << "Product not found in catalog." << std::endl;
        }
    }

    void applyDiscount(std::string productName, double discountPercentage) {
        if (productCatalog.isEmpty()) {
            std::cout << "No products in catalog to apply discount." << std::endl;
            return;
        }

        auto it = std::find_if(productCatalog.begin(), productCatalog.end(),
            [&productName](const Product& product) { return product.name == productName; });
        if (it != productCatalog.end()) {
            discounts[productName] = discountPercentage;
        } else {
            std::cout << "Product not found in catalog." << std::endl;
        }
    }

    void calculateTotal() {
        double total = 0;
        for (auto& pair : discounts) {
            auto it = std::find_if(productCatalog.begin(), productCatalog.end(),
                [&pair](const Product& product) { return product.name == pair.first; });
            if (it != productCatalog.end()) {
                total += productCatalog.top().price * (1 - pair.second / 100);
                productCatalog.pop();
            }
        }
        std::cout << "Total after applying discounts: $" << total << std::endl;
    }

    void sortCatalogByPrice() {
        std::vector<std::pair<std::string, double>> productsVector(productCatalog.size());
        int i = 0;
        while (!productCatalog.isEmpty()) {
            productsVector[i++] = *productCatalog.top();
            productCatalog.pop();
        }
        std::sort(productsVector.begin(), productsVector.end(), sortByPrice);
        productCatalog.clear();
        for (auto& pair : productsVector) {
            productCatalog.push(pair);
        }
    }

    void sortCatalogByGenre() {
        std::vector<std::pair<std::string, std::string>> productsVector(productCatalog.size());
        int i = 0;
        while (!productCatalog.isEmpty()) {
            productsVector[i++] = *productCatalog.top();
            productCatalog.pop();
        }
        std::sort(productsVector.begin(), productsVector.end(), sortByGenre);
        productCatalog.clear();
        for (auto& pair : productsVector) {
            productCatalog.push(pair);
        }
    }

    void displayCatalog() {
        while (!productCatalog.isEmpty()) {
            std::cout << "Name: " << productCatalog.top().name << ", Price: " << productCatalog.top().price << ", Genre: " << productCatalog.top().genre << std::endl;
            productCatalog.pop();
        }
    }
};

int main() {
    Bookstore bookstore;

    // Adding products to the catalog
    Product book1("Harry Potter", 15.99, "Fantasy");
    Product book2("To Kill a Mockingbird", 12.99, "Classic");
    Product book3("1984", 14.99, "Dystopian");

    bookstore.addProduct(book1);
    bookstore.addProduct(book2);
    bookstore.addProduct(book3);

    // Displaying the initial catalog
    std::cout << "Initial Catalog:" << std::endl;
    bookstore.displayCatalog();

    // Sorting the catalog by price
    bookstore.sortCatalogByPrice();
    std::cout << "\nCatalog sorted by price:" << std::endl;
    bookstore.displayCatalog();

    // Applying a discount
    bookstore.applyDiscount("Harry Potter", 10);
    std::cout << "\nDiscount applied to Harry Potter." << std::endl;

    // Calculating the total after applying the discount
    bookstore.calculateTotal();

    // Sorting the catalog by genre
    bookstore.sortCatalogByGenre();
    std::cout << "\nCatalog sorted by genre:" << std::endl;
    bookstore.displayCatalog();

    return 0;
}
