// Function to merge k sorted arrays into a single sorted array
std::vector<int> mergeSortedArrays(const std::vector<std::vector<int>>& arrays, const std::string& inputFile = "", const std::string& outputFile = "") {
    // Initialize min-heap with the first element from each array
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<>> minHeap;
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], i});
        }
    }

    // Initialize the result vector
    std::vector<int> result;

    // Merge the sorted arrays
    while (!minHeap.empty()) {
        auto [element, arrayIndex] = minHeap.top();
        minHeap.pop();
        result.push_back(element);

        // Add the next element from the array to the min-heap
        if (arrays[arrayIndex].size() > 1) {
            minHeap.push({arrays[arrayIndex][1], arrayIndex});
        }
    }

    return result;
}

// Function to print the result vector
void printResult(const std::vector<int>& result) {
    std::cout << "[";
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i];
        if (i != result.size() - 1) {
            std::cout << ", ";
        }
    }
    std::cout << "]" << std::endl;
}

