#include <iostream>
#include <fstream>
#include <vector>
#include <queue>
#include <stdexcept>

// Structure to represent an array and its size
struct Array {
    std::vector<int> data;
    int size;
};

// Function to merge two sorted arrays into a single sorted array
std::vector<int> mergeArrays(const Array& arr1, const Array& arr2) {
    std::vector<int> result;
    result.reserve(arr1.size + arr2.size);

    while (!arr1.data.empty() && !arr2.data.empty()) {
        if (arr1.data[0] <= arr2.data[0]) {
            result.push_back(arr1.data[0]);
            arr1.data.erase(arr1.data.begin());
        } else {
            result.push_back(arr2.data[0]);
            arr2.data.erase(arr2.data.begin());
        }
    }

    // Append remaining elements from both arrays
    result.insert(result.end(), arr1.data.begin(), arr1.data.end());
    result.insert(result.end(), arr2.data.begin(), arr2.data.end());

    return result;
}

// Function to merge multiple sorted arrays into a single sorted array using min-heap
std::vector<int> mergeSortedArrays(int numArrays, const std::vector<Array>& arrays) {
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<>> minHeap;

    for (int i = 0; i < numArrays; ++i) {
        if (!arrays[i].data.empty()) {
            minHeap.emplace(arrays[i].data[0], i);
        }
    }

    std::vector<int> mergedArray;
    mergedArray.reserve(numArrays * 200); // Assuming each array has no more than 200 elements

    while (!minHeap.empty()) {
        auto [element, arrayIndex] = minHeap.top();
        minHeap.pop();

        mergedArray.push_back(element);

        if (++arrayIndex < numArrays) {
            if (!arrays[arrayIndex].data.empty()) {
                minHeap.emplace(arrays[arrayIndex].data[0], arrayIndex);
            }
        }
    }

    return mergedArray;
}

