// Function to merge multiple sorted arrays into a single sorted array
std::vector<int> mergeSortedArrays(const std::vector<std::vector<int>>& arrays) {
    // Create a min-heap with the priority_queue from STL
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<>> minHeap;

    // Initialize the min-heap with the first element of each array
    for (size_t i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], i});
        }
    }

    // Initialize the result vector
    std::vector<int> result;

    // Merge the arrays until the min-heap is empty
    while (!minHeap.empty()) {
        // Pop the smallest element from the min-heap
        auto [element, arrayIndex] = minHeap.top();
        minHeap.pop();

        // Add the popped element to the result vector
        result.push_back(element);

        // Push the next element from the same array into the min-heap
        if (arrayIndex + 1 < arrays[arrayIndex].size()) {
            minHeap.push({arrays[arrayIndex][arrayIndex + 1], arrayIndex});
        }
    }

    return result;
}

