std::vector<int> mergeSortedArrays(const std::vector<std::vector<int>>& arrays, const std::string& outputFile = "") {
    // Create a min-heap with the specified maximum size (1000 elements)
    std::priority_queue<int, std::vector<int>, std::greater<int>> minHeap(1000);

    // Initialize an empty vector to store the merged result
    std::vector<int> mergedArray;

    // Iterate over each array and push its first element into the min-heap
    for (const auto& array : arrays) {
        if (!array.empty()) {
            minHeap.push(array[0]);
        }
    }

    // Merge the arrays until the min-heap is empty
    while (!minHeap.empty()) {
        // Pop the smallest element from the min-heap and add it to the merged array
        int smallestElement = minHeap.top();
        minHeap.pop();

        // Add the popped element to the merged array
        mergedArray.push_back(smallestElement);

        // Push the next element from the same array into the min-heap
        for (auto& array : arrays) {
            if (!array.empty() && array[0] == smallestElement) {
                array.erase(array.begin());
                minHeap.push(array[0]);
                break;
            }
        }
    }

    // Write the merged array to the output file if specified
    if (!outputFile.empty()) {
        std::ofstream outputFileStream(outputFile);
