class Employee {
public:
    int age;
    std::string name;

    // Constructor with default values
    Employee(int a = 0, std::string n = "") : age(a), name(n) {}

    // Copy constructor
    Employee(const Employee& e) : age(e.age), name(e.name) {}

    // Move constructor
    Employee(Employee&& e) noexcept : age(e.age), name(std::move(e.name)) { e.age = 0; }

    // Assignment operator
    Employee& operator=(const Employee& e) {
        if (this != &e) {
            age = e.age;
            name = e.name;
        }
        return *this;
    }

    // Move assignment operator
    Employee& operator=(Employee&& e) noexcept {
        if (this != &e) {
            age = e.age;
            name = std::move(e.name);
            e.age = 0;
        }
        return *this;
    }

    // Destructor
    ~Employee() {}

    // Comparison operators
    bool operator<(const Employee& other) const {
        if (age == other.age) {
            return name < other.name;
        }
        return age < other.age;
    }

    bool operator>(const Employee& other) const {
        return !(*this < other);
    }

    bool operator<=(const Employee& other) const {
        return !(*this > other);
    }

    bool operator>=(const Employee& other) const {
        return !(*this < other);
    }

    bool operator==(const Employee& other) const {
        return age == other.age && name == other.name;
    }

    bool operator!=(const Employee& other) const {
        return !(*this == other);
    }

    // Output operator
    friend std::ostream& operator<<(std::ostream& os, const Employee& e) {
        os << "Age: " << e.age << ", Name: " << e.name;
        return os;
    }
};

class EmployeeDeque {
private:
    std::deque<Employee> employees;
    mutable std::mutex mtx;

public:
    // Constructor
    EmployeeDeque() : employees(), capacity(800) {}

    // Destructor
    ~EmployeeDeque() {}

    // Check if the deque is empty
    bool isEmpty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.empty();
    }

    // Check if the deque has reached its capacity
    bool isFull() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.size() >= capacity;
    }

    // Add an employee to the back of the deque
    void push_back(const Employee& employee) {
        if (isFull()) {
            throw std::runtime_error("Deque is full");
        }
        std::lock_guard<std::mutex> lock(mtx);
        employees.push_back(employee);
    }

    // Remove and return the front employee from the deque
    Employee pop_front() {
        if (isEmpty()) {
            throw std::runtime_error("Deque is empty");
        }
        std::lock_guard<std::mutex> lock(mtx);
        Employee frontEmployee = employees.front();
        employees.pop_front();
        return frontEmployee;
    }

    // Sort the deque based on age and then name
    void sort() {
        std::sort(employees.begin(), employees.end(), [](const Employee& a, const Employee& b) {
            if (a.age == b.age) {
                return a.name < b.name;
            }
            return a.age < b.age;
        });
    }

    // Get the number of employees in the deque
    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.size();
    }

    // Clear the deque
    void clear() {
        std::lock_guard<std::mutex> lock(mtx);
        employees.clear();
    }
};

int main() {
    EmployeeDeque employeeDeque;

    try {
        Employee emp1(30, "John Doe");
        Employee emp2(25, "Jane Smith");
        Employee emp3(30, "Bob Johnson");

        employeeDeque.push_back(emp1);
        employeeDeque.push_back(emp2);
        employeeDeque.push_back(emp3);

        std::cout << "Before sorting:" << std::endl;
        for (const auto& employee : employeeDeque.employees) {
            std::cout << employee << std::endl;
        }

        employeeDeque.sort();

        std::cout << "\nAfter sorting:" << std::endl;
        for (const auto& employee : employeeDeque.employees) {
            std::cout << employee << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
