class ThreadSafeDeque {
private:
    std::deque<Employee> employees;
    std::mutex mtx;

public:
    void push_back(const Employee& employee) {
        std::lock_guard<std::mutex> lock(mtx);
        if (!employee.name.empty() && employee.age > 0) {
            employees.push_back(employee);
            if (employees.size() > 600) {
                throw std::runtime_error("Maximum size exceeded");
            }
        } else {
            throw std::invalid_argument("Invalid employee data");
        }
    }

    Employee pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            throw std::runtime_error("No elements in the deque");
        }
        Employee employee = employees.back();
        employees.pop_back();
        return employee;
    }
};

void stableSort(std::deque<Employee>& employees) {
    std::sort(employees.begin(), employees.end());
}

