    fn insert(&mut self, word: &str) {
        let lower_word = word.to_lowercase();
        if let Some(value) = self.map.get_mut(&lower_word) {
            *value += 1;
        } else {
            self.map.insert(lower_word.to_string(), 1);
        }
    }

    fn retrieve(&self) -> Vec<(String, u32)> {
        self.map.iter().collect()
    }

    fn display(&self) {
        for (word, count) in self.retrieve() {
            println!("{}: {}", word, count);
        }
    }

    fn print_tree(&self) {
        for (word, count) in self.retrieve() {
            println!("{} | {}",
                     word,
                     count);
        }
    }
}

fn main() {
    let mut file = File::open("text.txt").unwrap();
    let reader = BufReader::new(file);

    let mut map = WordFrequencyMap::new();

    for line in reader.lines() {
        for word in line.unwrap().split_whitespace() {
            let word = word.to_lowercase().replace("[^a-zA-Z0-9]", "");
            map.insert(word.as_str());
        }
    }

    map.display();

    let mut sorted_map = map.retrieve();
    sorted_map.sort_by(|a, b| b.1.cmp(&a.1));
    map.print_tree();

    // Note: Deletion is not allowed as per the problem constraints.
}
