use std::collections::LinkedList;
use std::error::Error;
use std::time::SystemTime;

enum Operation {
    Enqueue(String, String),
    Dequeue,
    Lookup(String),
}

struct Message {
    id: String,
    timestamp: String,
}

struct MessageQueue {
    queue: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        MessageQueue {
            queue: LinkedList::new(),
            max_size,
        }
    }

    fn execute(&mut self, op: Operation) -> Result<(), Box<dyn Error>> {
        match op {
            Operation::Enqueue(id, timestamp) => {
                if self.queue.len() >= self.max_size {
                    return Err(Box::new(MessageQueueOverflowError));
                }
                let message = Message {
                    id: id.to_string(),
                    timestamp: timestamp.to_string(),
                };
                self.queue.push_back(message);
                Ok(())
            }
            Operation::Dequeue => {
                if self.queue.is_empty() {
                    return Err(Box::new(MessageQueueUnderflowError));
                }
                self.queue.pop_front();
                Ok(())
            }
            Operation::Lookup(id) => {
                for message in &self.queue {
                    if message.id == id {
                        return Ok(());
                    }
                }
                Err(Box::new(MessageNotFoundError))
            }
        }
    }
}

