use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

// Define a Message struct to hold the message data
struct Message {
    id: String,
    timestamp: Instant,
}

impl Message {
    fn new(id: String, timestamp: Instant) -> Self {
        Message { id, timestamp }
    }
}

// Define a Queue struct to manage the LinkedList and provide methods for push, pop, lookup, and expiration
struct Queue {
    messages: Arc<Mutex<LinkedList<Message>>>,
    max_size: usize,
}

impl Queue {
    fn new(max_size: usize) -> Self {
        Queue {
            messages: Arc::new(Mutex::new(LinkedList::new())),
            max_size,
        }
    }

    // Push a new message onto the queue
    fn push(&self, message: Message) -> Result<(), String> {
        if self.messages.lock().unwrap().len() >= self.max_size {
            return Err("Queue overflow".to_string());
        }

        let mut messages = self.messages.lock().unwrap();
        messages.push_back(message);
        Ok(())
    }

    // Pop the oldest message from the queue
    fn pop(&self) -> Option<Message> {
        if self.messages.lock().unwrap().is_empty() {
            None
        } else {
            let mut messages = self.messages.lock().unwrap();
            messages.pop_front().cloned()
        }
    }

    // Lookup a message by ID
    fn lookup(&self, id: &str) -> Option<&Message> {
        if let Some(messages) = self.messages.lock().unwrap().iter() {
            for message in messages {
                if message.id == id {
                    return Some(message);
                }
            }
        }
        None
    }

    // Remove expired messages (older than 30 seconds)
    fn expire(&self) {
        let now = Instant::now();
        let mut messages = self.messages.lock().unwrap();
        while let Some(mut message) = messages.pop_front() {
            if now.duration_since(message.timestamp).as_secs() > 30 {
                break;
            }
            messages.push_back(message);
        }
    }
}

fn main() {
    let mut queue = Queue::new(500);

    // Create some test messages
    let message1 = Message::new("id1".to_string(), Instant::now() - Duration::seconds(10));
    let message2 = Message::new("id2".to_string(), Instant::now() - Duration::seconds(20));

    // Push messages onto the queue
    match queue.push(message1.clone()) {
        Ok(_) => println!("Pushed message 1"),
        Err(err) => println!("Error: {}", err),
    }
    match queue.push(message2.clone()) {
        Ok(_) => println!("Pushed message 2"),
        Err(err) => println!("Error: {}", err),
    }

    // Lookup a message by ID
    match queue.lookup(&message1.id) {
        Some(message) => println!("Found message: {:?}", message),
        None => println!("Message not found"),
    }

    // Pop the oldest message from the queue
    match queue.pop() {
        Some(message) => println!("Popped message: {:?}", message),
        None => println!("Queue is empty"),
    }

    // Simulate time passing (30 seconds)
    thread::sleep(Duration::from_secs(30));

    // Expiration should remove the oldest message
    match queue.pop() {
        Some(message) => println!("Expired message: {:?}", message),
        None => println!("No expired messages"),
    }
