struct Message {
    id: String,
    timestamp: Instant,
}

impl Message {
    fn new(id: String, timestamp: Instant) -> Self {
        Message { id, timestamp }
    }
}

struct MessageQueue {
    queue: Arc<Mutex<LinkedList<Message>>>,
}

impl MessageQueue {
    fn new() -> Self {
        let queue = Arc::new(Mutex::new(LinkedList::new()));
        MessageQueue { queue }
    }

    fn push(&self, message: Message) -> Result<(), String> {
        if self.queue.lock().unwrap().len() >= 500 {
            return Err("Queue overflow".to_string());
        }

        let now = Instant::now();
        if message.timestamp > now - Duration::seconds(30) {
            self.queue.lock().unwrap().push(message);
            Ok(())
        } else {
            Err("Message is older than 30 seconds".to_string())
        }
    }

    fn pop(&self) -> Option<Message> {
        self.queue.lock().unwrap().pop()
    }

    fn get_by_id(&self, id: &str) -> Option<&Message> {
        for message in self.queue.lock().unwrap().iter() {
            if message.id == id {
                return Some(message);
            }
        }
        None
    }
}

fn main() {
    let mut queue = MessageQueue::new();

    let message1 = Message::new("1".to_string(), Instant::now());
    let message2 = Message::new("2".to_string(), Instant::now());

    assert!(queue.push(message1).is_ok());
    assert!(queue.push(message2).is_err()); // Queue overflow

    assert_eq!(queue.pop(), Some(message1));
    assert_eq!(queue.get_by_id("1"), Some(&message1));

    let message3 = Message::new("3".to_string(), Instant::now());
    assert!(queue.push(message3).is_ok());

    assert_eq!(queue.pop(), Some(message2));
    assert_eq!(queue.get_by_id("2"), Some(&message2));
}
