class Cinema {
private:
    std::vector<std::pair<int, bool>> bookings;
    int maxBookings;

public:
    Cinema(int maxBookings = 10000) : maxBookings(maxBookings) {}

    void makeReservation(int seatNumber) {
        if (seatNumber < 1 || seatNumber > maxBookings) {
            throw std::invalid_argument("Invalid seat number");
        }

        for (auto& booking : bookings) {
            if (booking.second && booking.first == seatNumber) {
                throw std::runtime_error("Seat is already booked");
            }
        }

        for (auto it = bookings.begin(); it != bookings.end();) {
            if (it->second && it->first <= seatNumber && seatNumber <= it->first + 10) {
                ++it;
                continue;
            }
            it = bookings.erase(it);
        }

        bookings.push_back({seatNumber, true});
    }

    void cancelReservation(int seatNumber) {
        if (seatNumber < 1 || seatNumber > maxBookings) {
            throw std::invalid_argument("Invalid seat number");
        }

        for (auto it = bookings.begin(); it != bookings.end();) {
            if (it->second && it->first == seatNumber) {
                it = bookings.erase(it);
            } else {
                ++it;
            }
        }
    }

    bool isAvailable(int seatNumber) {
        if (seatNumber < 1 || seatNumber > maxBookings) {
            return false;
        }

        for (const auto& booking : bookings) {
            if (booking.second && booking.first == seatNumber) {
                return false;
            }
        }

        return true;
    }
};

int main() {
    Cinema cinema;

    try {
        cinema.makeReservation(1);
