        }

        if (!isSeatAvailable(seatNumber)) {
            throw std::runtime_error("Seat is not available for reservation.");
        }

        reservations.push(std::make_pair(seatNumber, true));
        std::cout << "Reservation successful. Seat " << seatNumber << " booked." << std::endl;
    }

