        if (!isSeatReserved(seatNumber)) {
            throw std::runtime_error("Seat is not reserved for cancellation.");
        }

        reservations.pop();
        std::cout << "Reservation cancelled. Seat " << seatNumber << " unbooked." << std::endl;
    }

    void checkAvailability(int seatNumber) {
        if (isSeatReserved(seatNumber)) {
            std::cout << "Seat " << seatNumber << " is reserved." << std::endl;
        } else {
            std::cout << "Seat " << seatNumber << " is available." << std::endl;
        }
    }

    void printReservations() {
        if (reservations.empty()) {
            std::cout << "No reservations found." << std::endl;
        } else {
            std::cout << "Current Reservations:" << std::endl;
            while (!reservations.empty()) {
                auto& reservation = *reservations.top();
                std::cout << "Seat " << reservation.first << ": Reserved" << std::endl;
                reservations.pop();
            }
        }
    }

    bool isSeatReserved(int seatNumber) {
        for (const auto& reservation : reservations) {
            if (reservation.first == seatNumber) {
                return true;
            }
        }
        return false;
    }

    bool isSeatAvailable(int seatNumber) {
        for (const auto& reservation : reservations) {
            if (reservation.first == seatNumber) {
                return false;
            }
        }
        return true;
    }
