import heapq
from datetime import datetime, timedelta

class TaskManager:
    def __init__(self, capacity=50):
        self.capacity = capacity
        self.queue = []
        self.deadlines = {}

    def add_task(self, task_name, deadline):
        if len(self.queue) < self.capacity:
            heapq.heappush(self.queue, (-deadline, task_name))
            self.deadlines[task_name] = deadline
        else:
            closest_deadline = -self.queue[0][0]
            for name, deadline in self.deadlines.items():
                if deadline <= closest_deadline:
                    break
            if deadline <= closest_deadline:
                self.heapreplace(task_name, deadline)
            else:
                print(f"Task {task_name} cannot be added due to capacity constraints.")

    def heappop(self, task_name):
        if task_name not in self.deadlines:
            return None
        for i, (deadline, _) in enumerate(self.queue):
            if deadline == self.deadlines[task_name]:
                del self.deadlines[task_name]
                heapq.heappop(self.queue)
                return task_name
        return None

    def heapreplace(self, task_name, new_deadline):
        if task_name not in self.deadlines:
            return None
        for i, (deadline, _) in enumerate(self.queue):
            if deadline == self.deadlines[task_name]:
                self.deadlines[task_name] = new_deadline
                heapq.heapreplace(self.queue, (-new_deadline, task_name))
                return task_name
        return None

def main():
