        this.taskSet = new TreeSet<>();
    }

    public void addTask(int taskId, int priority) {
        if (taskSet.size() >= maxTasks) {
            throw new RuntimeException("Task set is at maximum capacity");
        }
        try {
            Task task = new Task(taskId, priority);
            taskSet.add(task);
            logger.log(Level.INFO, "Added task {0} with priority {1}", new Object[]{taskId, priority});
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error adding task", e);
        }
    }

    public void removeTask(int taskId) {
        if (taskSet.size() <= minTasks) {
            throw new RuntimeException("Task set has minimum required tasks");
        }
        try {
            taskSet.remove(new Task(taskId, 0));
            logger.log(Level.INFO, "Removed task {0}", new Object[]{taskId});
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error removing task", e);
        }
    }

    public Task pollFirstTask() {
        if (taskSet.isEmpty()) {
            throw new RuntimeException("Task set is empty");
        }
        try {
            return taskSet.pollFirst();
            logger.log(Level.INFO, "Pulled first task");
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error pulling first task", e);
            return null;
        }
    }

    public static class Task implements Comparable<Task> {
        private int id;
        private int priority;

        public Task(int id, int priority) {
            this.id = id;
            this.priority = priority;
        }

        @Override
        public int compareTo(Task other) {
            return Integer.compare(this.priority, other.priority);
        }

        @Override
        public String toString() {
            return "Task{" +
                    "id=" + id +
                    ", priority=" + priority +
                    '}';
        }
    }

