        TaskScheduler scheduler = new TaskScheduler();
        scheduler.addTask(1, 1);
        scheduler.addTask(2, 2);
        scheduler.addTask(3, 3);
        scheduler.pollFirstTask();
        scheduler.removeTask(2);
        scheduler.pollFirstTask();
    }
