#include <iostream>
#include <vector>
#include <algorithm>

class PriorityQueue {
private:
    std::vector<std::pair<int, std::string>> queue;
    int capacity;

public:
    PriorityQueue() : capacity(500) {}

    void push(int priority, const std::string& item) {
        if (queue.size() >= capacity) {
            throw std::runtime_error("Priority queue is full. Cannot add more items.");
        }
        queue.push_back({priority, item});
        std::sort(queue.begin(), queue.end(), [](const auto& a, const auto& b) {
            return a.first > b.first;
        });
    }

    void pop() {
        if (queue.empty()) {
            throw std::runtime_error("Priority queue is empty. Cannot remove items.");
        }
        queue.pop_back();
    }

    std::string top() {
        if (queue.empty()) {
            throw std::runtime_error("Priority queue is empty. Cannot retrieve top item.");
        }
        return queue[0].second;
    }
};

int main() {
    try {
        PriorityQueue pq;
        pq.push(1, "Item 1");
        pq.push(3, "Item 2");
        pq.push(2, "Item 3");

        std::cout << pq.top() << std::endl;  // Output: Item 3

        pq.pop();

        std::cout << pq.top() << std::endl;  // Output: Item 2

        pq.pop();
        pq.pop();

        try {
            pq.pop();
        } catch (const std::exception& e) {
            std::cerr << e.what() << std::endl;  // Output: Priority queue is empty. Cannot remove items.
        }
    } catch (const std::exception& e) {
        std::cerr << e.what() << std::endl;
    }

    return 0;
}
