    fn new() -> Self {
        Library {
            media: VecDeque::new(),
        }
    }

    fn add(&mut self, media_type: MediaType) -> Result<(), String> {
        if self.media.len() >= 1000 {
            return Err("Library is full. Cannot add more entries.".to_string());
        }

        match media_type {
            MediaType::Book(title) => self.media.push_back(media_type),
            MediaType::Movie(title) => self.media.push_back(media_type),
            MediaType::Music(title) => self.media.push_back(media_type),
            _ => return Err("Invalid media type".to_string()),
        }

        Ok(())
    }

    fn update(&mut self, index: usize, media_type: MediaType) -> Result<(), String> {
        if index < self.media.len() {
            match media_type {
                MediaType::Book(title) => self.media[index] = media_type,
                MediaType::Movie(title) => self.media[index] = media_type,
                MediaType::Music(title) => self.media[index] = media_type,
                _ => return Err("Invalid media type".to_string()),
            }
        } else {
            return Err("Index out of bounds".to_string());
        }

        Ok(())
    }

    fn remove(&mut self, index: usize) -> Result<MediaType, String> {
        if index < self.media.len() {
            let media = self.media.pop_front().unwrap();
            Ok(media)
        } else {
            Err("Index out of bounds".to_string())
        }
    }

    fn display_media(&self) {
        for (i, media) in self.media.iter().enumerate() {
            match media {
                MediaType::Book(title) => println!("{} - Book", i + 1),
