}

impl Library {
    fn new() -> Self {
        Library {
            media: VecDeque::new(),
        }
    }

    fn add(&mut self, media_type: MediaType) -> Result<(), String> {
        if self.media.len() >= 1000 {
            return Err("Collection limit exceeded".to_string());
