        if index < 0 || index >= self.media.len() {
            return Err("Index out of range".to_string());
        }

        let media = self.media.pop_front().unwrap();

        if self.media.len() == 1000 {
            return Err("Collection limit exceeded".to_string());
        }

        Ok(media)
    }

