        if index < 0 || index >= self.media.len() {
            return Err("Index out of range".to_string());
        }

        match self.media.get_mut(index) {
            Some(media) => match media_type {
                MediaType::Book(title) => *media = media_type,
                MediaType::Movie(title) => *media = media_type,
                MediaType::Music(title) => *media = media_type,
                _ => return Err("Invalid media type".to_string()),
            },
            None => return Err("Index out of range".to_string()),
        }

