            throw new RuntimeException("Maximum number of students reached.");
        }
        students.add(student);
    }

    public void removeStudent(int studentId) {
        if (!students.contains(new Student(studentId, null, null))) {
            throw new RuntimeException("Student not found.");
        }
        students.remove(new Student(studentId, null, null));
    }

    public boolean containsStudent(int studentId) {
        return students.contains(new Student(studentId, null, null));
    }

    public int size() {
        return students.size();
    }

    public static void main(String[] args) {
