use std::collections::SmallVec;
use std::fmt;

#[derive(Debug, PartialEq)]
enum Priority {
    Low,
    Medium,
    High,
}

impl fmt::Display for Priority {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match *self {
            Priority::Low => write!(f, "Low"),
            Priority::Medium => write!(f, "Medium"),
            Priority::High => write!(f, "High"),
        }
    }
}

struct PriorityQueue {
    tasks: SmallVec<[Priority; 200]>,
    max_size: usize,
}

impl PriorityQueue {
    fn new(max_size: usize) -> Self {
        Self {
            tasks: SmallVec::new(),
            max_size,
        }
    }

    fn add_task(&mut self, task: Priority) -> Result<(), usize> {
        if self.tasks.len() >= self.max_size {
            return Err(self.max_size);
        }
        self.tasks.push(task);
        Ok(())
    }

    fn update_task(&mut self, index: usize, task: Priority) -> Result<(), usize> {
        if index >= self.tasks.len() {
            return Err(self.tasks.len());
        }
        self.tasks[index] = task;
        Ok(())
    }

    fn remove_task(&mut self, index: usize) -> Result<Priority, usize> {
        if index >= self.tasks.len() {
            return Err(self.tasks.len());
        }
        let task = self.tasks.remove(index);
        Ok(task)
    }
}

fn main() {
    let mut pq = PriorityQueue::new(200);

    match pq.add_task(Priority::High) {
        Ok(_) => println!("Added High task"),
        Err(size) => println!("Overflow, cannot add more tasks: {}", size),
    }

    match pq.add_task(Priority::Medium) {
        Ok(_) => println!("Added Medium task"),
        Err(size) => println!("Overflow, cannot add more tasks: {}", size),
    }

    match pq.add_task(Priority::Low) {
        Ok(_) => println!("Added Low task"),
        Err(size) => println!("Overflow, cannot add more tasks: {}", size),
    }

    match pq.update_task(0, Priority::High) {
        Ok(_) => println!("Updated High task"),
        Err(size) => println!("Overflow, cannot update task: {}", size),
    }

    match pq.remove_task(0) {
        Ok(task) => println!("Removed task: {:?}", task),
        Err(size) => println!("Overflow, cannot remove task: {}", size),
    }
}
