```rust
use smallvec::SmallVec;

struct PriorityQueue {
    tasks: SmallVec<[usize; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        PriorityQueue {
            tasks: SmallVec::with_capacity(200),
        }
    }

    fn add_task(&mut self, task_id: usize) -> Result<(), usize> {
        if self.tasks.len() >= 200 {
            return Err(200);
        }
        self.tasks.push(task_id);
        Ok(())
    }

    fn update_task(&mut self, task_id: usize, priority: usize) -> Result<(), usize> {
        if let Some(index) = self.tasks.iter().position(|&id| id == task_id) {
            if index > 0 && self.tasks[index - 1] < priority {
                return Err(self.tasks[index - 1]);
            }
            if index + 1 < self.tasks.len() && self.tasks[index + 1] <= priority {
                return Err(self.tasks[index + 1]);
            }
            self.tasks.swap(index, index + 1);
            self.tasks[index] = priority;
            Ok(())
        } else {
            Err(task_id)
        }
    }

    fn remove_task(&mut self, task_id: usize) -> Option<usize> {
        self.tasks.retain(|&task_id| task_id != task_id);
        self.tasks.pop()
    }
}

fn main() {
    let mut pq = PriorityQueue::new();
    assert!(pq.add_task(1).is_ok());
    assert!(pq.add_task(2).is_ok());
    assert_eq!(pq.remove_task(1), Some(1));
    assert_eq!(pq.remove_task(2), Some(2));
}
