package main

import (
    "fmt"
    "log"
    "sync"
    "time"
)

type logEntry struct {
    key string
}

var maxEntries = 20000
var lruCache = make(map[string]int)
var mu sync.Mutex
var evictMu sync.Mutex
var evicted logEntry

func main() {
    // Create a channel to receive log file paths
    logFiles := make(chan string)

    // Start a goroutine to read and process log files concurrently
    go func() {
        for logFilePath := range logFiles {
            logFile, err := openLogfile(logFilePath)
            if err != nil {
                log.Printf("Error reading log file: %v", err)
                continue
            }
            defer logFile.Close()

            var entries []logEntry
            for line, _ := fmt.Fscan(logFile, &line); line != "" && len(entries) < maxEntries; line = fmt.Fscan(logFile, &line) {
                entry := logEntry{
                    key: line,
                }
                entries = append(entries, entry)
            }

            // Process the log entries concurrently
            go processLogEntries(entries)
        }
    }()

    // Accept log file paths from the user
    logFiles <- "./log1.log"
    logFiles <- "./log2.log"

    // Close the channel to signal the end of log file processing
    close(logFiles)
}

func openLogfile(filePath string) (*os.File, error) {
    return os.Open(filePath)
}

func processLogEntries(entries []logEntry) {
    for _, entry := range entries {
        mu.Lock()
        count, ok := lruCache[entry.key]
        if !ok {
            count = 0
        }
        lruCache[entry.key] = count + 1
        mu.Unlock()

        // Evict an entry from the cache if it's full
        evictMu.Lock()
        if len(lruCache) > maxEntries {
            evicted = entries[len(entries)-maxEntries]
            delete(lruCache, evicted.key)
        }
        evictMu.Unlock()

        // Simulate some I/O operation
        time.Sleep(100 * time.Millisecond)
    }
}
