package main

import (
    "fmt"
    "log"
    "sync"
    "time"
)

type logEntry struct {
    key string
}

type vector struct {
    entries []logEntry
    mu      sync.Mutex
    size    int
    cap     int
}

func (v *vector) increment(key string) {
    v.mu.Lock()
    for i, entry := range v.entries {
        if entry.key == key {
            v.entries[i].count++
            return
        }
    }
    v.entries = append(v.entries, logEntry{key: key})
    if len(v.entries) > v.cap {
        v.deleteOldest()
    }
    v.size++
    v.mu.Unlock()
}

func (v *vector) check(key string) bool {
    v.mu.RLock()
    defer v.mu.RUnlock()
    for _, entry := range v.entries {
        if entry.key == key {
            return true
        }
    }
    return false
}

func (v *vector) delete(key string) {
    v.mu.Lock()
    for i, entry := range v.entries {
        if entry.key == key {
            v.entries = append(v.entries[:i], v.entries[i+1:]...)
            v.size--
            return
        }
    }
    v.mu.Unlock()
}

func (v *vector) deleteOldest() {
    v.mu.Lock()
    oldest := v.entries[0]
    v.entries = v.entries[1:]
    v.size--
    v.mu.Unlock()
}

func worker(vector *vector, stop chan bool) {
    for {
        select {
        case <-stop:
            return
        default:
            key := fmt.Sprintf("log-%d", time.Now().UnixNano())
            vector.increment(key)
            if !vector.check(key) {
                vector.delete(key)
            }
        }
    }
}

func main() {
    var vector vector
    vector.cap = 20000
    vector.size = 0

    stop := make(chan bool)
    go func() {
        time.Sleep(time.Second * 10)
        stop <- true
    }()

    var wg sync.WaitGroup
    for i := 0; i < 5; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            worker(&vector, stop)
        }()
    }

    wg.Wait()
}
