def floyd_warshall(graph):
    n = len(graph)
    queue = Queue()

    for i in range(n):
        for j in range(n):
            if graph[i][j] == 0:
                queue.put((i, j))

    while not queue.empty():
        node1, node2 = queue.get()

        for k in range(n):
            if graph[node1][k] != 0 and graph[k][node2] != 0:
                if graph[node1][k] + graph[k][node2] < graph[node1][node2]:
                    graph[node1][node2] = graph[node1][k] + graph[k][node2]
                    queue.put((node1, node2))

    return graph

