use std::collections::HashMap;
use std::fs::File;
use std::io::{BufWriter, Write};
use std::sync::{Arc, Mutex};

// Define a logger
struct Logger {
    writer: BufWriter<File>,
}

impl Logger {
    fn new(file_path: &str) -> Self {
        let file = File::create(file_path).unwrap();
        Logger {
            writer: BufWriter::new(file),
        }
    }

    fn log(&self, message: &str) {
        writeln!(self.writer, "{}", message).unwrap();
    }
}

fn main() {
    // Initialize the logger
    let logger = Logger::new("employee_scores.log");

    // Create an array vector to store employee scores
    let mut employee_scores = Arc::new(Mutex::new(Vec::with_capacity(100)));

    // Function to add employee scores
    fn add_employee_score(scores: &mut Vec<(i32, i32)>) {
        if scores.len() >= 100 {
            panic!("ArrayVec overflow error");
        }

        let mut input = String::new();
        println!("Enter employee ID and score (space-separated): ");
        std::io::stdin().read_line(&mut input).expect("Failed to read line");
        let mut parts = input.split_whitespace();
        let employee_id: i32 = parts.next().unwrap().parse().expect("Invalid input");
        let score: i32 = parts.next().unwrap().parse().expect("Invalid input");

        if let Some(existing_score) = scores.iter().find(|&(id, _)| id == employee_id) {
            let new_score = existing_score.1 + score;
            *existing_score = (employee_id, new_score);
        } else {
            scores.push((employee_id, score));
        }

        // Log data processing step
        logger.log(&format!("Added employee ID {} with score {}", employee_id, score));

        // Calculate average scores per employee
        let mut total_score = 0;
        for (_, score) in scores {
            total_score += score;
        }
        let average_score = total_score as f64 / scores.len() as f64;

        // Log average scores per employee
        logger.log(&format!("Average score for employee ID {}: {:.2}", employee_id, average_score));
