            "3" => remove_data(&array_vec),
            "4" => break,
            _ => println!("Invalid choice"),
        }
    }
}

fn insert_data(array_vec: &Arc<Mutex<ArrayVec>>) {
    info!("Inserting data");

    let mut employee_id = String::new();
    let mut scores_str = String::new();

    std::io::stdin().read_line(&mut employee_id).expect("Failed to read employee ID");
    std::io::stdin().read_line(&mut scores_str).expect("Failed to read scores");

    let employee_id: i32 = employee_id.trim().parse().expect("Invalid employee ID");
    let scores: Vec<f64> = scores_str
        .split_whitespace()
        .map(|s| s.parse().expect("Invalid score"))
        .collect();

    if let Some(existing_entry) = array_vec.lock().unwrap().find(|entry| entry.employee_id == employee_id) {
        error!("Duplicate entry for employee ID {}", employee_id);
        return;
    }

    let entry = EmployeeScore::new(employee_id, scores);
    array_vec.lock().unwrap().insert(entry);

    info!("Inserted data: {:?}", entry);
}

fn get_average_scores(array_vec: &Arc<Mutex<ArrayVec>>) {
    info!("Getting average scores");

    let mut average_scores: Vec<(i32, f64)> = Vec::new();

    for entry in array_vec.lock().unwrap().iter() {
        let average_score = entry.calculate_average();
        average_scores.push((entry.employee_id, average_score));
    }

    average_scores.sort_by_key(|&(employee_id, _)| employee_id);

    for (employee_id, average_score) in average_scores {
        info!("Employee ID {}: Average Score = {}", employee_id, average_score);
    }
}

fn remove_data(array_vec: &Arc<Mutex<ArrayVec>>) {
    info!("Removing data");

    let mut employee_id = String::new();

    std::io::stdin().read_line(&mut employee_id).expect("Failed to read employee ID");

    let employee_id: i32 = employee_id.trim().parse().expect("Invalid employee ID");

    if let Some(entry) = array_vec.lock().unwrap().remove(&employee_id) {
        info!("Removed data: {:?}", entry);
    } else {
        error!("No data found for employee ID {}", employee_id);
    }
}

struct ArrayVec {
    entries: Vec<EmployeeScore>,
    max_size: usize,
}

impl ArrayVec {
    fn new(max_size: usize) -> Self {
        Self {
            entries: Vec::with_capacity(max_size),
            max_size,
        }
    }

    fn insert(&mut self, entry: EmployeeScore) {
        if self.entries.len() >= self.max_size {
            panic!("ArrayVec overflow: cannot insert more than {} entries", self.max_size);
        }

        self.entries.push(entry);
    }

    fn find(&self, key: &i32) -> Option<&EmployeeScore> {
        self.entries.iter().find(|entry| entry.employee_id == *key)
    }

    fn iter(&self) -> impl Iterator<Item = &EmployeeScore> {
        self.entries.iter()
    }

    fn remove(&mut self, key: &i32) -> Option<EmployeeScore> {
        self.entries.retain(|entry| entry.employee_id != *key);
        self.entries.pop()
    }
}
