from collections import deque

class NavigationSystem:
    def __init__(self, grid):
        self.grid = grid
        self.rows, self.cols = len(grid), len(grid[0])
        self.directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
        self.walls = {(0, 0), (0, 1), (0, -1), (1, 0)}
        self.queue = deque([(0, 0), (0, 1), (0, -1), (1, 0)])
        self.visited = {(0, 0)}

    def is_valid(self, x, y):
        return 0 <= x < self.rows and 0 <= y < self.cols and (x, y) not in self.walls and (x, y) not in self.visited

    def navigate(self, start, end):
        if start == end:
            return [start]

        while self.queue:
            x, y = self.queue.popleft()
            if (x, y) == end:
                path = [start]
                while (x, y) != start:
                    x, y = path[-1]
                    path.append((x, y))
                return path[::-1]

            for dx, dy in self.directions:
                nx, ny = x + dx, y + dy
                if self.is_valid(nx, ny):
                    self.queue.append((nx, ny))
                    self.visited.add((nx, ny))

        return None

# Example usage:
