from collections import deque

class NavigationSystem:
    def __init__(self, grid_size):
        self.grid_size = grid_size
        self.walls = set()
        self.parent_nodes = {}
        self.bfs_queue = deque(maxlen=500)

    def add_wall(self, x, y):
        self.walls.add((x, y))

    def move_up(self, x, y):
        if (x, y-1) not in self.walls and 0 <= y-1 < self.grid_size:
            return (x, y-1)
        return None

    def move_down(self, x, y):
        if (x, y+1) not in self.walls and 0 <= y+1 < self.grid_size:
            return (x, y+1)
        return None

    def move_left(self, x, y):
        if (x-1, y) not in self.walls and 0 <= x-1 < self.grid_size:
            return (x-1, y)
        return None

    def move_right(self, x, y):
        if (x+1, y) not in self.walls and 0 <= x+1 < self.grid_size:
            return (x+1, y)
        return None

    def bfs(self, start_x, start_y, end_x, end_y):
        self.bfs_queue.append((start_x, start_y))
        self.parent_nodes[(start_x, start_y)] = None

        while self.bfs_queue:
            current_x, current_y = self.bfs_queue.popleft()

            if (current_x, current_y) == (end_x, end_y):
                path = []
                while (current_x, current_y) != (start_x, start_y):
                    path.append((current_x, current_y))
                    current_x, current_y = self.parent_nodes[(current_x, current_y)]
                path.append((start_x, start_y))
                path.reverse()
                return path

            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                new_x, new_y = current_x + dx, current_y + dy
                if (new_x, new_y) not in self.walls:
                    if (new_x, new_y) not in self.parent_nodes:
                        self.parent_nodes[(new_x, new_y)] = (current_x, current_y)
                        self.bfs_queue.append((new_x, new_y))

        return None


# Example usage
if __name__ == "__main__":
