    navigation_system.add_wall(5, 5)
    navigation_system.add_wall(7, 3)

    start_x, start_y = 0, 0
    end_x, end_y = 9, 9

    path = navigation_system.bfs(start_x, start_y, end_x, end_y)
    if path:
