from collections import deque

class NavigationSystem:
    def __init__(self, grid_size):
        self.grid_size = grid_size
        self.max_capacity = 500
        self.walls = [[False for _ in range(grid_size)] for _ in range(grid_size)]
        self.parent_nodes = {}
        self.current_position = (0, 0)
        self.bfs_queue = deque([(0, 0, [0, 0])])

    def set_walls(self, walls):
        for i in range(len(walls)):
            for j in range(len(walls[i])):
                self.walls[i][j] = walls[i][j]

    def is_valid_move(self, x, y):
        return 0 <= x < self.grid_size and 0 <= y < self.grid_size and not self.walls[x][y]

    def bfs(self):
        while self.bfs_queue:
            x, y, path = self.bfs_queue.popleft()
            if (x, y) not in self.parent_nodes or len(self.parent_nodes[(x, y)]) > 100:
                continue
            if self.is_valid_move(x-1, y) and (x-1, y) not in self.parent_nodes or len(self.parent_nodes[(x-1, y)]) == 100:
                self.parent_nodes[(x-1, y)] = (x, y)
                self.bfs_queue.append((x-1, y, path + [(x-1, y)]))
            if self.is_valid_move(x+1, y) and (x+1, y) not in self.parent_nodes or len(self.parent_nodes[(x+1, y)]) == 100:
                self.parent_nodes[(x+1, y)] = (x, y)
                self.bfs_queue.append((x+1, y, path + [(x+1, y)]))
            if self.is_valid_move(x, y-1) and (x, y-1) not in self.parent_nodes or len(self.parent_nodes[(x, y-1)]) == 100:
                self.parent_nodes[(x, y-1)] = (x, y)
                self.bfs_queue.append((x, y-1, path + [(x, y-1)]))
            if self.is_valid_move(x, y+1) and (x, y+1) not in self.parent_nodes or len(self.parent_nodes[(x, y+1)]) == 100:
                self.parent_nodes[(x, y+1)] = (x, y)
                self.bfs_queue.append((x, y+1, path + [(x, y+1)]))

    def reconstruct_path(self):
        if (self.current_position) not in self.parent_nodes:
            return None
        path = []
        current_position = self.current_position
        while current_position != (0, 0):
            path.append(current_position)
            current_position = self.parent_nodes[current_position]
        path.append((0, 0))
        return list(reversed(path))

def main():
    grid_size = 10
    walls = [[True, False, True], [False, False, False], [True, False, True]]
    navigation_system = NavigationSystem(grid_size)
    navigation_system.set_walls(walls)
    navigation_system.bfs()
    path = navigation_system.reconstruct_path()
    if path:
        print("Path found:", path)

if __name__ == "__main__":
    main()
