#include <iostream>
#include <unordered_map>

int longestConsecutive(int arr[], int n) {
    if (n == 0) {
        throw std::invalid_argument("Input array is empty");
    }

    try {
        std::unordered_map<int, bool> numSet;
        for (int i = 0; i < n; i++) {
            numSet[arr[i]] = true;
        }

        int longestStreak = 0;
        for (const auto& num : numSet) {
            if (!num.second) {
                continue;
            }

            int currentNum = num.first;
            int currentStreak = 1;

            while (numSet.find(currentNum + 1) != numSet.end()) {
                currentNum += 1;
                currentStreak += 1;
            }

            longestStreak = std::max(longestStreak, currentStreak);
        }

        return longestStreak;
    } catch (const std::exception& e) {
        throw std::runtime_error(e.what());
    }
}

int main() {
    int arr[] = {100, 4, 200, 1, 3, 2};
    int n = sizeof(arr) / sizeof(arr[0]);

    try {
        int result = longestConsecutive(arr, n);
        std::cout << "Length of the longest consecutive sequence: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
