class DatasetManager:
    def __init__(self, max_entries=1000):
        self.max_entries = max_entries
        self.dataset = {}
        self.entry_id_counter = 1

    def insert(self, key, value):
        if len(self.dataset) < self.max_entries:
            self.dataset[self.entry_id_counter] = (key, value)
            self.entry_id_counter += 1
            return f"Entry {key} inserted successfully."
        else:
            return "Dataset is full. Cannot insert new entry."

    def update(self, key, value=None):
        if key in self.dataset:
            if value is not None:
                self.dataset[key] = (key, value)
                return f"Entry {key} updated successfully."
            else:
                return f"No value provided for entry {key}."
        else:
            return f"No entry found with key {key}."

    def delete(self, key):
        if key in self.dataset:
            del self.dataset[key]
            return f"Entry {key} deleted successfully."
        else:
            return f"No entry found with key {key}."

    def fetch(self, key):
        if key in self.dataset:
            return self.dataset[key]
        else:
            return f"No entry found with key {key}."


