import java.util.Stack;

public class StockPriceAnalyzer {
    private static final int MAX_STACK_SIZE = 500;
    private Stack<Double> stack = new Stack<>();
    private double minPrice = Double.MAX_VALUE;
    private double maxProfit = 0;

    public void push(double price) {
        if (stack.size() < MAX_STACK_SIZE) {
            stack.push(price);
        } else {
            while (stack.size() > MAX_STACK_SIZE) {
                stack.pop();
            }
            stack.push(price);
        }
    }

    public double pop() {
        if (!stack.isEmpty()) {
            double topPrice = stack.pop();
            if (topPrice < minPrice) {
                minPrice = topPrice;
            } else {
                double profit = topPrice - minPrice;
                maxProfit = Math.max(maxProfit, profit);
            }
            return topPrice;
        }
        return Double.NaN;
    }

    public double computeMaxProfit() {
        return maxProfit;
    }

    public static void main(String[] args) {
        StockPriceAnalyzer analyzer = new StockPriceAnalyzer();
        analyzer.push(10.0);
        analyzer.push(7.0);
        analyzer.push(5.0);
        analyzer.push(8.0);
        analyzer.push(11.0);
        analyzer.push(9.0);

        System.out.println("Maximum possible profit: " + analyzer.computeMaxProfit());
