use std::collections::BTreeMap;
use std::io;

struct MedianFinder {
    lower_half: BTreeMap<i32, i32>,
    upper_half: BTreeMap<i32, i32>,
}

impl MedianFinder {
    fn new() -> MedianFinder {
        MedianFinder {
            lower_half: BTreeMap::new(),
            upper_half: BTreeMap::new(),
        }
    }

    fn add_num(&mut self, num: i32) {
        if self.lower_half.is_empty() {
            self.lower_half.insert(num, 1);
            self.upper_half.insert(num, 0);
        } else if num < self.lower_half.iter().next().unwrap().0 {
            let (mut pos, mut count) = (self.lower_half.len() - 1, 0);
            while pos > 0 && self.lower_half.iter().nth(pos - 1).unwrap().0 >= num {
                self.lower_half.remove(&(self.lower_half.iter().nth(pos - 1).unwrap().0,));
                pos -= 1;
                count += 1;
            }
            self.lower_half.insert(num, count + 1);
            self.upper_half.remove(&self.lower_half[&(num, 0)]);
            self.upper_half.insert(num, count);
        } else {
            let (mut pos, mut count) = (self.upper_half.len(), 0);
            while pos > 0 && self.upper_half.iter().nth(pos - 1).unwrap().0 <= num {
                self.upper_half.remove(&(self.upper_half.iter().nth(pos - 1).unwrap().0,));
                pos -= 1;
                count += 1;
            }
            self.upper_half.insert(num, count + 1);
            self.lower_half.remove(&self.upper_half[&(num, 0)]);
            self.lower_half.insert(num, count);
        }
    }

    fn find_median(&self) -> i32 {
        if self.lower_half.len() > self.upper_half.len() {
            self.lower_half.iter().next().unwrap().0
        } else {
            let mut lower_half_iter = self.lower_half.iter();
            let mut upper_half_iter = self.upper_half.iter();
            if lower_half_iter.next().unwrap().1 > upper_half_iter.next().unwrap().1 {
                self.lower_half.iter().next().unwrap().0
            } else {
                self.upper_half.iter().next().unwrap().0
            }
        }
    }
}

fn main() {
    let mut median_finder = MedianFinder::new();
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    let mut nums = input.trim().split_whitespace().map(|n| n.parse::<i32>().unwrap());
    for num in nums {
        median_finder.add_num(num);
        if nums.position(|n| *n == num) == Some(0) {
            println!("{}", median_finder.find_median());
        }
    }
}
