    fn new() -> Self {
        MedianCalculator {
            map: BTreeMap::new(),
        }
    }

    fn add(&mut self, num: i32) {
        if let Some(pos) = self.map.range(..num).next_back() {
            if pos.1 > 0 {
                *pos.1 -= 1;
            } else {
                self.map.remove(&pos);
            }
        }
        self.map.insert(num, 1);
    }

    fn get_median(&self) -> Option<f64> {
        let mut count = 0;
        for (_, val) in &self.map {
            count += val;
        }
        if count % 2 == 0 {
            let mid1 = self.map.iter().rev().next().unwrap().0 as f64;
            let mid2 = self.map.iter().rev().nth(1).map(|(_, val)| (*val as f64)).unwrap_or(0.0);
            Some((mid1 + mid2) / 2.0)
        } else {
            let mid = self.map.iter().rev().next().unwrap().0 as f64;
            Some(mid)
        }
    }
}

