use std::collections::BTreeMap;

struct MedianFinder {
    lower_half: BTreeMap<i32, i32>,
    upper_half: BTreeMap<i32, i32>,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            lower_half: BTreeMap::new(),
            upper_half: BTreeMap::new(),
        }
    }

    fn add_num(&mut self, num: i32) {
        if self.lower_half.len() >= 2000 {
            let max = self.lower_half.keys().max().unwrap();
            self.remove_max(max);
        }

        if self.upper_half.is_empty() || *self.upper_half.first_key_value().unwrap().0 > num {
            self.lower_half.insert(num, 1);
        } else {
            self.upper_half.insert(num, 1);
        }

        self.rebalance();
    }

    fn remove_max(&mut self, key: &i32) {
        match self.lower_half.get_mut(key) {
            Some(value) => {
                if value == &1 {
                    self.lower_half.remove(key);
                } else {
                    *value -= 1;
                }
            }
            None => {}
        }

        match self.upper_half.get_mut(key) {
            Some(value) => {
                if value == &1 {
                    self.upper_half.remove(key);
                } else {
                    *value -= 1;
                }
            }
            None => {}
        }
    }

    fn rebalance(&mut self) {
        if self.lower_half.len() + self.upper_half.len() > 5000 {
            let (lower_keys, upper_keys) = (
                self.lower_half.keys().cloned().collect::<Vec<_>>(),
                self.upper_half.keys().cloned().collect::<Vec<_>>(),
            );

            for key in lower_keys.iter().rev() {
                self.upper_half.insert(*key, 1);
            }

            for key in upper_keys {
                self.lower_half.insert(key, 1);
            }
        }
    }

    fn find_median(&self) -> i32 {
        if self.lower_half.len() > self.upper_half.len() {
            self.lower_half.keys().next().unwrap()
        } else if self.upper_half.len() > self.lower_half.len() {
            self.upper_half.keys().next().unwrap()
        } else {
            let lower_key = self.lower_half.keys().next().unwrap();
            let upper_key = self.upper_half.keys().next().unwrap();

            (*lower_key).cmp(upper_key)
        }
    }
}

