    // Function to calculate rolling average of stock prices
    go func() {
        var sum float64
        for p := range prices {
            sum += p.Value
            if len(prices) > 1000 {
                sum -= prices[0].Value
                prices <- StockPrice{p.Time, 0}
                prices <- StockPrice{p.Time, sum/len(prices)}
            } else {
                prices <- StockPrice{p.Time, sum}
            }
        }
    }()

    // Generate and send fake stock prices
    for i := 0; i < 5000; i++ {
        price := rand.Float64() * 100.0
        prices <- StockPrice{i*10, price}
    }

    // Close the channel to signal end of data
    close(prices)
