		Year:   year,
		Issued: false,
	})
}

// RemoveBook removes a book from the library by its title
func (l *Library) RemoveBook(title string) {
	for i, book := range l.books {
		if book.Title == title {
			l.books = append(l.books[:i], l.books[i+1:]...)
			break
		}
	}
}

// UpdateIssued updates the issued status of a book
func (l *Library) UpdateIssued(title string, issued bool) {
	for i, book := range l.books {
		if book.Title == title {
