import time

class LogProcessor:
    def __init__(self, max_size=1500):
        self.queue = queue.Queue(maxsize=max_size)
        self.lock = threading.Lock()
        self.running = False

    def start(self):
        self.running = True
        self.thread = threading.Thread(target=self.process_logs)
        self.thread.start()

    def stop(self):
        self.running = False
        self.queue.join()

    def process_logs(self):
        while self.running:
            try:
                log_message = self.queue.get(timeout=1)
                print(f"Processing log message: {log_message}")
                # Simulate some processing time
                time.sleep(2)
            except queue.Empty:
                pass

def producer(log_processor):
    for i in range(1000):
        log_processor.queue.put(f"Log Message {i}")

def consumer(log_processor):
    while True:
        log_processor.queue.get()

if __name__ == "__main__":
    log_processor = LogProcessor()
    log_processor.start()

    producer_thread = threading.Thread(target=producer, args=(log_processor,))
    consumer_thread = threading.Thread(target=consumer, args=(log_processor,))

    producer_thread.start()
    consumer_thread.start()

    time.sleep(10)

    log_processor.stop()
