        aggregates = self.get_aggregates(day)
        if aggregates:
            return max(aggregates['max'])
        else:
            return None

    def get_min(self, day):
        aggregates = self.get_aggregates(day)
        if aggregates:
            return min(aggregates['min'])
        else:
