        if len(self.data) < self.max_days:
            self.data.append((date, value))
            self.index_map[date] = len(self.data) - 1
        else:
            raise ValueError("Maximum days reached")

    def get_aggregate(self, day):
        try:
            return self.data[self.index_map[day]]
        except KeyError:
            raise ValueError("Day not found in the data")


