import heapq

class MinHeap:
    def __init__(self, k):
        self.k = k
        self.min_heap = []
        self.size = 0

    def insert(self, num):
        if len(self.min_heap) < self.k:
            heapq.heappush(self.min_heap, num)
            self.size += 1
        elif num < self.min_heap[0]:
            self._shift_up(num)

    def get_kth_smallest(self):
        if self.size == 0:
            return None
        return self.min_heap[0]

    def _shift_up(self, num):
        parent_idx = (len(self.min_heap) - 1) // 2
        while parent_idx >= 0 and num < self.min_heap[parent_idx]:
            self.min_heap[parent_idx + 1] = self.min_heap[parent_idx]
            parent_idx = (parent_idx - 1) // 2
        self.min_heap[parent_idx + 1] = num


class KthSmallestMinHeap:
    def __init__(self, k):
        self.k = k
        self.min_heap = MinHeap(k)

    def insert(self, num):
        self.min_heap.insert(num)

    def get_kth_smallest(self):
        return self.min_heap.get_kth_smallest()


