#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

void permute(vector<int>& nums, int left, int right, vector<vector<int>>& res, vector<int>& temp) {
    if (left == right)
        res.push_back(temp);
    else {
        for (int i = left; i <= right; i++) {
            swap(nums[left], nums[i]);
            temp.push_back(nums[left]);
            permute(nums, left + 1, right, res, temp);
            temp.pop_back();
            swap(nums[left], nums[i]);
        }
    }
}

void getPermutations(vector<int> nums, vector<vector<int>>& res) {
    sort(nums.begin(), nums.end());
    vector<int> temp;
    int maxLen = nums.size() * nums.size() / 2;
    while (res.size() < maxLen) {
        res.clear();
        permute(nums, 0, nums.size() - 1, res, temp);
    }
}

void printVector(const vector<vector<int>>& vec) {
    for (const auto& v : vec) {
        cout << "[";
        for (size_t i = 0; i < v.size(); ++i) {
            cout << v[i];
            if (i != v.size() - 1) cout << ", ";
        }
        cout << "]" << endl;
    }
}

int main() {
    vector<int> nums = {1, 2, 3};
    vector<vector<int>> res;
    getPermutations(nums, res);
    printVector(res);
    return 0;
}
