void countUniqueWords(const std::string& str, int maxSize = 100) {
    // Preprocess the string
    std::string preprocessedStr = preprocessString(removePunctuation(str));

    // Split the string into words
    size_t pos = 0;
    std::unordered_set<std::string> uniqueWords;
    std::map<std::string, int> wordCount;

    while ((pos = preprocessedStr.find(" ")) != std::string::npos) {
        std::string word = preprocessedStr.substr(0, pos);
        if (uniqueWords.size() < maxSize) {
            uniqueWords.insert(word);
            ++wordCount[word];
        }
        preprocessedStr.erase(0, pos + 1);
    }

    // Handle the last word
    if (uniqueWords.size() < maxSize) {
        std::string word = preprocessedStr;
        uniqueWords.insert(word);
        ++wordCount[word];
    }

