std::pair<int, std::unordered_map<std::string, int>> count_unique_words(const std::string& input_string) {
    std::vector<std::string> unique_words;
    std::unordered_map<std::string, int> word_count;

    // Preprocess the string to normalize case sensitivity and remove punctuation
    std::string processed_string;
    for (char c : input_string) {
        if (std::isalnum(c)) {
            processed_string += std::tolower(c);
        }
    }

    size_t start = 0;
    while (start < processed_string.size()) {
        size_t end = processed_string.find(' ', start);
        if (end == std::string::npos) {
            end = processed_string.size();
        }
        std::string word = processed_string.substr(start, end - start);

        if (word_count[word] == 0 && unique_words.size() < 100) {
            unique_words.push_back(word);
            word_count[word]++;
        } else if (word_count[word] > 0) {
            word_count[word]++;
        }

        start = end + 1;
    }

    return {unique_words.size(), word_count};
}

int main() {
    std::string input_string;
    std::cout << "Enter a string: ";
    std::getline(std::cin, input_string);

