import java.util.PriorityQueue;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicInteger;

public class EmergencyAlertsSystem {
    private PriorityQueue<Alert> alertQueue;
    private ConcurrentLinkedQueue<Alert> displayQueue;
    private AtomicInteger alertId;

    public EmergencyAlertsSystem() {
        alertQueue = new PriorityQueue<>((a, b) -> Integer.compare(b.severity, a.severity));
        displayQueue = new ConcurrentLinkedQueue<>();
        alertId = new AtomicInteger(1);
    }

    public void addAlert(int severity) {
        Alert alert = new Alert(alertId.incrementAndGet(), severity);
        alertQueue.add(alert);
        displayAlert(alert);
    }

    public void processAlerts() {
        while (!alertQueue.isEmpty()) {
            Alert alert = alertQueue.poll();
            displayAlert(alert);
        }
    }

    private void displayAlert(Alert alert) {
        System.out.println("Alert ID: " + alert.id + ", Severity: " + alert.severity + ", Timestamp: " + alert.timestamp);
    }

    public static class Alert {
        int id;
        int severity;
        long timestamp;

        public Alert(int id, int severity) {
            this.id = id;
            this.severity = severity;
            this.timestamp = System.currentTimeMillis();
        }
    }

    public static void main(String[] args) {
        EmergencyAlertsSystem system = new EmergencyAlertsSystem();
        system.addAlert(3);
        system.addAlert(2);
        system.addAlert(1);
        system.processAlerts();
    }
}
