            System.out.println("3. Remove Alert");
            System.out.println("4. Exit");
            System.out.print("Choose an option: ");
            int option = Integer.parseInt(scanner.nextLine());

            switch (option) {
                case 1:
                    addAlert();
                    break;
                case 2:
                    peekAtAlerts();
                    break;
                case 3:
                    removeAlert();
                    break;
                case 4:
                    System.exit(0);
                    break;
                default:
                    System.out.println("Invalid option. Please choose a valid option.");
            }
        }
    }

