        long timestamp = scanner.nextLong();
        scanner.nextLine(); // Consume newline left-over

        if (alertQueue.size() < 10) {
            alertQueue.add(new Alert(severity, timestamp));
            System.out.println("Alert added successfully.");
        } else {
            System.out.println("The alert queue is full. Cannot add more alerts.");
        }
    }

