            System.out.println("Timestamp: " + alert.timestamp);
        } else {
            System.out.println("No alerts in the queue.");
        }
    }

    private static void removeAlert() {
        if (!alertQueue.isEmpty()) {
            alertQueue.poll();
            System.out.println("Alert removed successfully.");
        } else {
            System.out.println("No alerts in the queue.");
        }
    }

