import java.util.concurrent.atomic.AtomicInteger;

public class EmergencyAlertSystem {
    private PriorityQueue<Alert> alertQueue;
    private AtomicInteger alertCount;

    public EmergencyAlertSystem() {
        this.alertQueue = new PriorityQueue<>();
        this.alertCount = new AtomicInteger(0);
    }

    public void addAlert(String severity, String timestamp) {
        if (alertCount.get() < 10) {
            Alert alert = new Alert(severity, timestamp);
            alertQueue.add(alert);
            alertCount.incrementAndGet();
            System.out.println("Added alert: " + alert.toString());
        } else {
            System.out.println("Maximum alerts reached. Cannot add more.");
        }
    }

    public void processAlerts() {
        while (!alertQueue.isEmpty()) {
            Alert alert = alertQueue.poll();
            System.out.println("Processing alert: " + alert.toString());
        }
    }

    private static class Alert implements Comparable<Alert> {
        private final String severity;
        private final String timestamp;

        public Alert(String severity, String timestamp) {
            this.severity = severity;
            this.timestamp = timestamp;
        }

        @Override
        public int compareTo(Alert other) {
            // Prioritize based on severity level (higher is more critical)
            return -severity.compareTo(other.severity);
        }

        @Override
        public String toString() {
            return "Severity: " + severity + ", Timestamp: " + timestamp;
        }
    }

    public static void main(String[] args) {
        EmergencyAlertSystem system = new EmergencyAlertSystem();

        // Add alerts dynamically
        system.addAlert("CRITICAL", "2023-03-01 12:00:00");
        system.addAlert("WARNING", "2023-03-01 12:05:00");
        system.addAlert("INFO", "2023-03-01 12:10:00");

        // Process alerts sequentially
        system.processAlerts();
    }
}
