#include <iostream>
#include <stack>
#include <algorithm>

class HighScoreStack {
private:
    std::stack<int> highScores;
    int maxElements;

public:
    HighScoreStack() : maxElements(10) {}

    void loadHighScores(int scores[]) {
        for (int score : scores) {
            if (highScores.size() < maxElements) {
                highScores.push(score);
            } else if (score > *highScores.top()) {
                highScores.pop();
                highScores.push(score);
            }
        }
    }

    void sortHighScores() {
        std::vector<int> sortedScores;
        while (!highScores.empty()) {
            sortedScores.push_back(highScores.top());
            highScores.pop();
        }
        std::sort(sortedScores.rbegin(), sortedScores.rend());
        for (int score : sortedScores) {
            highScores.push(score);
        }
    }

    bool searchScore(int targetScore) {
        while (!highScores.empty()) {
            if (highScores.top() == targetScore) {
                return true;
            }
            highScores.pop();
        }
        return false;
    }

    void pushScore(int score) {
        if (highScores.size() < maxElements) {
            highScores.push(score);
        } else {
            while (!highScores.empty()) {
                if (score > highScores.top()) {
                    break;
                }
                highScores.pop();
            }
            highScores.push(score);
        }
    }
};

void printHighScores(const std::stack<int>& highScores) {
    std::cout << "[";
    while (!highScores.empty()) {
        std::cout << highScores.top() << ", ";
        highScores.pop();
    }
    std::cout << "]" << std::endl;
}

int main() {
    int highScores[] = {100, 50, 200, 150, 250, 300, 400, 500, 600, 700};
    HighScoreStack highScoreStack;
    highScoreStack.loadHighScores(highScores);
    highScoreStack.sortHighScores();
    printHighScores(highScoreStack.highScores);

    std::cout << std::boolalpha << highScoreStack.searchScore(250) << std::endl; // Output: true

    highScoreStack.pushScore(800);
    printHighScores(highScoreStack.highScores);

    return 0;
}
