                default:
                    price := float64(math.Round(float64(rand.Intn(100)) / 10.0))
                    mu.Lock()
                    if _, ok := stockPrices[ticker]; ok {
                        stockPrices[ticker] = append(stockPrices[ticker], price)
                    } else {
                        stockPrices[ticker] = []float64{price}
                    }
                    mu.Unlock()
                }
            }
        }(ticker)
    }

    go func() {
        for {
            select {
            case <-wg.Done():
                return
            default:
                total := 0.0
                count := 0
