package main

import (
	"fmt"
	"math/rand"
	"time"
)

func streamStockQuotes() {
	tickers := make(map[string][]float64)
	channels := make(map[string chan float64))

	for ticker := range tickers {
		channels[ticker] = make(chan float64)
		go func(ticker string) {
			for {
				price := rand.Float64() * 100.0
				channels[ticker] <- price
			}
		}(ticker)
	}

	for {
		averages := make(map[string]float64)
		for ticker, channel := range channels {
			if len(tickers[ticker]) < 50 {
				averages[ticker] = accumulatePrices(tickers[ticker], channel)
			} else {
				averages[ticker] = accumulatePrices(tickers[ticker][:len(tickers[ticker])-1], channel)
				tickers[ticker] = append(tickers[ticker], <-channel)
			}
		}

		printAverages(averages)
		time.Sleep(1 * time.Second)
	}
}

func accumulatePrices(prices []float64, newPrice chan float64) float64 {
	var sum float64
	for _, price := range prices {
		sum += price
	}
	sum += <-newPrice
	return sum / (len(prices) + 1)
}

func printAverages(averages map[string]float64) {
	fmt.Println("Average Stock Prices:")
	for ticker, average := range averages {
		fmt.Printf("%s: %.2f\n", ticker, average)
	}
}

func main() {
	streamStockQuotes()
}
