        if let Some(existing_change) = self.changes.get_mut(&product_id) {
            *existing_change += change;
        } else {
            self.add_log(product_id, change);
        }
    }

    pub fn report_changes(&self) -> Vec<(String, i32)> {
        self.changes.into_iter().collect()
    }
}

