use std::collections::BTreeMap;

const MAX_SIZE: usize = 100;

fn track_inventory_changes() -> BTreeMap<i32, i32> {
    let mut inventory_logs: BTreeMap<i32, i32> = BTreeMap::new();

    fn add_log(inventory_logs: &mut BTreeMap<i32, i32>, product_id: i32, change: i32) {
        if inventory_logs.len() < MAX_SIZE {
            *inventory_logs.entry(product_id).or_insert(0) += change;
        } else {
            println!("Inventory log size exceeded the maximum limit of {}.", MAX_SIZE);
        }
    }

    fn update_log(inventory_logs: &mut BTreeMap<i32, i32>, product_id: i32, change: i32) {
        match inventory_logs.get_mut(&product_id) {
            Some(value) => *value += change,
            None => println!("Product ID not found in inventory logs."),
        }
    }

    fn display_aggregated_changes(inventory_logs: &BTreeMap<i32, i32>) {
        for (product_id, change) in inventory_logs {
            println!("Product ID: {}, Inventory Change: {}", product_id, change);
        }
    }

    let mut input_choice = String::new();
    loop {
        println!("1. Add new inventory log");
        println!("2. Update existing inventory log");
        println!("3. Display aggregated changes");
        println!("4. Exit");

        print!("Choose an option: ");
        std::io::stdin().read_line(&mut input_choice)
            .expect("Failed to read line");

        match input_choice.trim() {
            "1" => {
                print!("Enter product ID: ");
                let mut product_id_str = String::new();
                std::io::stdin().read_line(&mut product_id_str)
                    .expect("Failed to read line");
                let product_id: i32 = product_id_str.trim().parse()
                    .expect("Please type a number!");

                print!("Enter inventory change: ");
                let mut change_str = String::new();
                std::io::stdin().read_line(&mut change_str)
                    .expect("Failed to read line");
                let change: i32 = change_str.trim().parse()
                    .expect("Please type a number!");

                add_log(&mut inventory_logs, product_id, change);
            },
            "2" => {
                print!("Enter product ID: ");
                let mut product_id_str = String::new();
                std::io::stdin().read_line(&mut product_id_str)
                    .expect("Failed to read line");
                let product_id: i32 = product_id_str.trim().parse()
                    .expect("Please type a number!");

                print!("Enter inventory change: ");
                let mut change_str = String::new();
                std::io::stdin().read_line(&mut change_str)
                    .expect("Failed to read line");
                let change: i32 = change_str.trim().parse()
                    .expect("Please type a number!");

                update_log(&mut inventory_logs, product_id, change);
            },
            "3" => {
                display_aggregated_changes(&inventory_logs);
            },
            "4" => break,
            _ => println!("Invalid choice. Please choose a valid option."),
        }
    }

    inventory_logs
}

fn main() {
    let inventory_logs = track_inventory_changes();
}
