void detectDuplicateErrors(const std::vector<int>& errorCodes) {
    std::unordered_set<int> uniqueDuplicates;
    std::unordered_map<int, int> errorCodeCounts;

    for (const auto& code : errorCodes) {
        if (errorCodeCounts.find(code) != errorCodeCounts.end()) {
            errorCodeCounts[code]++;
            if (errorCodeCounts[code] == 2) {
                uniqueDuplicates.insert(code);
            }
