#include <iostream>
#include <unordered_set>

class DuplicateErrorDetector {
private:
    int capacity;
    std::unordered_set<int> errorCodes;

public:
    DuplicateErrorDetector() : capacity(10) {}

    void detectDuplicateErrors(int errorCode) {
        if (errorCodes.find(errorCode) != errorCodes.end()) {
            // Error code already exists, increment count
            return;
        }

        if (errorCodes.size() == capacity) {
            // Set is full, remove the oldest error code
            auto it = errorCodes.begin();
            errorCodes.erase(it);
        }

        errorCodes.insert(errorCode);
    }

    void printResults() {
        std::cout << "Number of unique duplicate error codes: " << errorCodes.size() << std::endl;
    }
};

int main() {
    DuplicateErrorDetector detector;
    detector.detectDuplicateErrors(1);
    detector.detectDuplicateErrors(2);
    detector.detectDuplicateErrors(3);
    detector.detectDuplicateErrors(1);  // Duplicate error code
    detector.printResults();

    return 0;
}
