        if (!vipGuestList.contains(id)) {
            if (vipGuestList.size() < MAX_CAPACITY) {
                vipGuestList.add(id);
                System.out.println("VIP guest ID " + id + " added to the list.");
            } else {
                System.out.println("Maximum capacity reached. Cannot add more VIP guests.");
            }
        } else {
            System.out.println("VIP guest ID " + id + " already exists in the list.");
        }
