            patient_id = input("Enter patient ID to reevaluate priority: ")
            queue.reevaluate_priority(patient_id)
        elif choice == "3":
            case = queue.process_next_case()
            if case:
                print(f"Patient ID: {case[0]}, Severity Score: {case[1]}")
            else:
                print("No more cases in the queue.")
        elif choice == "4":
