from collections import deque

class EmergencyQueue:
    def __init__(self, max_size=10):
        self.queue = deque()
        self.max_size = max_size

    def add_patient(self, patient_id, severity_score):
        if len(self.queue) < self.max_size:
            self.queue.append((patient_id, severity_score))
            self.queue.sort(key=lambda x: x[1], reverse=True)
        else:
            print("Maximum queue size reached. Patient added to the end.")

    def reevaluate_priority(self, patient_id):
        for i, (id, score) in enumerate(self.queue):
            if id == patient_id:
                del self.queue[i]
                self.queue.append((patient_id, score))
                self.queue.sort(key=lambda x: x[1], reverse=True)
                return
        print("Patient not found in the queue.")

    def remove_patient(self, patient_id):
        for i, (id, score) in enumerate(self.queue):
            if id == patient_id:
                del self.queue[i]
                return
        print("Patient not found in the queue.")

def manageEmergencyQueue():
    queue = EmergencyQueue()
    while True:
        print("\n1. Add patient")
        print("2. Reevaluate priority")
        print("3. Remove patient")
        print("4. Exit")
