            severity_score = int(input("Enter severity score: "))
            queue.add_patient(patient_id, severity_score)
        elif choice == "2":
            patient_id = input("Enter patient ID: ")
            queue.reevaluate_priority(patient_id)
        elif choice == "3":
            patient_id = input("Enter patient ID: ")
            queue.remove_patient(patient_id)
        elif choice == "4":
            break
        else:
            print("Invalid option. Please choose a valid option.")

if __name__ == "__main__":
