import java.util.concurrent.ConcurrentMap;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class Main {

    private static final Lock lock = new ReentrantLock();

    public static ConcurrentMap<Integer, Integer> safeIncrementCount(ConcurrentMap<Integer, Integer> responseMap, int[] responses) {
        for (int response : responses) {
            lock.lock();
            try {
                responseMap.computeIfAbsent(response, k -> 0);
                responseMap.put(response, responseMap.get(response) + 1);
            } finally {
                lock.unlock();
            }
        }
        return responseMap;
    }

    public static void main(String[] args) {
        ConcurrentMap<Integer, Integer> responseMap = new ConcurrentHashMap<>();
        int[] responses = {1, 2, 2, 3, 3, 3};
        safeIncrementCount(responseMap, responses);
        System.out.println(responseMap);
    }
}
