    public static void safeIncrementCount(int responseId) {
        lock.lock();
        try {
            if (responseCounts.size() >= MAX_SIZE) {
                responseCounts.clear();
            }
            responseCounts.putIfAbsent(responseId, 1);
            responseCounts.compute(responseId, (k, v) -> v == null ? 1 : v + 1);
        } finally {
            lock.unlock();
        }
    }

    public static void main(String[] args) {
        // Example usage:
        safeIncrementCount(1);
        safeIncrementCount(2);
        safeIncrementCount(1);  // This should update the count for response ID 1
    }
