import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class Main {
    private static final int MAX_SIZE = 100;
    private static final Lock lock = new ReentrantLock();

    public static ConcurrentHashMap<Integer, Integer> safeIncrementCount(ConcurrentHashMap<Integer, Integer> responses) {
        lock.lock();
        try {
            if (responses.size() >= MAX_SIZE) {
                responses.clear();
            }
        } finally {
            lock.unlock();
        }

        for (Integer response : responses.keySet()) {
            responses.compute(response, (k, v) -> {
                return (v == null ? 1 : v + 1);
            });
        }

        return responses;
    }

    public static void main(String[] args) {
        ConcurrentHashMap<Integer, Integer> responses = new ConcurrentHashMap<>();
        responses.put(1, null);
        responses.put(2, null);
        responses.put(3, null);

        System.out.println(safeIncrementCount(responses));
    }
}
