def track_inventory_changes(updates):
    inventory = {}
    for update in updates:
        product_id, change = update
        if product_id in inventory:
            if change > 0:
                inventory[product_id].append(change)
            elif change < 0:
                inventory[product_id].remove(change)
        else:
            if change > 0:
                inventory[product_id] = [change]
            elif change < 0:
                inventory[product_id] = [change]

    net_changes = {}
    for product_id, changes in inventory.items():
        net_change = sum(changes)
        net_changes[product_id] = net_change

    return net_changes

# Example usage:
updates = [(1, 5), (2, -3), (1, -2), (3, 7)]
print(track_inventory_changes(updates))
