from collections import OrderedDict

def track_inventory_changes(updates):
    inventory = OrderedDict()
    net_changes = {}

    for update in updates:
        product_id, change = update

        if product_id not in inventory:
            inventory[product_id] = 0
            net_changes[product_id] = change

        else:
            current_quantity = inventory[product_id]
            new_quantity = current_quantity + change

            if new_quantity != current_quantity:
                del inventory[product_id]
                inventory[product_id] = new_quantity
                net_changes[product_id] = change

            else:
                net_changes[product_id] = 0

        # Limit the dictionary to 10 distinct product IDs
        if len(inventory) > 10:
            least_recently_adjusted_product = min(inventory, key=inventory.get)
            del inventory[least_recently_adjusted_product]
            del net_changes[least_recently_adjusted_product]

    return {product_id: quantity for product_id, quantity in inventory.items()}

# Example usage:
updates = [(1, 5), (2, -3), (3, 2), (4, -1), (5, 1), (6, -2)]
print(track_inventory_changes(updates))
