use std::collections::VecDeque;
use std::time::{Duration, Instant};
use std::thread;
use log::{info, error};

struct EmailTask {
    recipient: String,
    subject: String,
    body: String,
}

impl EmailTask {
    fn new(recipient: String, subject: String, body: String) -> Self {
        EmailTask {
            recipient,
            subject,
            body,
        }
    }

    fn process(&self) -> String {
        format!("Processed email for {} on {}.\nSubject: {}\nBody: {}\n", self.recipient, Instant::now(), self.subject, self.body)
    }
}

struct EmailScheduler {
    queue: VecDeque<EmailTask>,
    shuffle_interval: u64,
}

impl EmailScheduler {
    fn new() -> Self {
        EmailScheduler {
            queue: VecDeque::new(),
            shuffle_interval: 10, // seconds
        }
    }

    fn enqueue(&mut self, email_task: EmailTask) {
        self.queue.push_back(email_task);
    }

    fn process_queue(&mut self) {
        for task in self.queue.drain(..) {
            info!("{}", task.process());
            thread::sleep(Duration::from_secs(1)); // Simulate email processing time
        }
    }

    fn shuffle_queue(&mut self) {
        for _ in 0..5 {
            let mut task = self.queue.pop_front().unwrap();
            self.queue.push_back(task);
        }
    }

    fn run(&mut self) {
        loop {
            self.process_queue();
            self.shuffle_queue();
            thread::sleep(Duration::from_secs(self.shuffle_interval)); // Shuffle every 10 seconds
        }
    }
}

fn main() {
    env_logger::init();

    let mut scheduler = EmailScheduler::new();

    let email_task1 = EmailTask::new("John Doe".to_string(), "Test Email".to_string(), "This is a test email.".to_string());
    let email_task2 = EmailTask::new("Jane Doe".to_string(), "Urgent Email".to_string(), "This is an urgent email.".to_string());

    scheduler.enqueue(email_task1);
    scheduler.enqueue(email_task2);

    scheduler.run();
}
