use log::{info, error};

const MAX_EMAILS: usize = 100;

struct EmailTask {
    subject: String,
    timestamp: Instant,
}

fn manage_email_queue() -> Vec<EmailTask> {
    let mut email_queue = VecDeque::new();
    let mut last_shuffle_time = Instant::now();

    loop {
        if email_queue.len() >= MAX_EMAILS {
            break;
        }

        // Add a new email task every second
        email_queue.push_back(EmailTask {
            subject: format!("New Email Task {}", email_queue.len()),
            timestamp: Instant::now(),
