        if Instant::now().duration_since(last_shuffle_time).as_secs_f64() > 5.0 {
            email_queue.shuffle();
            last_shuffle_time = Instant::now();
        }

        // Process the next email task in the queue
        if let Some(email_task) = email_queue.pop_front() {
            info!("Processing email task: {} at {}", email_task.subject, email_task.timestamp);
            // Simulate processing time
            thread::sleep(Duration::from_millis(100));
            info!("Email task processed successfully");
        }
    }

    email_queue
}

