use log::{info, error};

const MAX_EMAILS: usize = 100;

struct Email {
    subject: String,
    timestamp: SystemTime,
}

fn manage_email_queue() -> VecDeque<Email> {
    let mut email_queue = VecDeque::new();

    fn process_emails(email_queue) {
        while let Some(email) = email_queue.pop_front() {
            info!("Processing email: {}", email.subject);
            // Simulate processing time
            std::thread::sleep(Duration::from_secs(1));
            info!("Email processed at: {}", email.timestamp);
        }
    }

    loop {
        if email_queue.len() < MAX_EMAILS {
            // Push new emails to the back of the queue
            email_queue.push_back(Email {
                subject: "New Email".to_string(),
                timestamp: SystemTime::now(),
            });
        } else {
            // Shuffle the queue for prioritizing urgent emails
            email_queue.shuffle();
        }

        // Periodically shuffle the queue
        if SystemTime::now().duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs() % 60 == 0 {
            email_queue.shuffle();
        }

        // Process the oldest emails from the front
        process_emails(email_queue.clone());
    }
}

fn main() {
    env_logger::init();
    manage_email_queue();
}
