use std::collections::VecDeque;
use std::time::{SystemTime, Duration};
use log::{info, error};

const MAX_EMAILS: usize = 100;

struct Email {
    id: u32,
    timestamp: SystemTime,
    urgent: bool,
}

impl Email {
    fn new(id: u32) -> Self {
        let now = SystemTime::now();
        Email {
            id,
            timestamp: now,
            urgent: false,
        }
    }

    fn is_urgent(&self) -> bool {
        self.urgent
    }

    fn process(&self) {
        info!("Processing email {} at {}", self.id, self.timestamp);
    }
}

fn manage_email_queue() {
    let mut email_queue = VecDeque::new();

    loop {
        if email_queue.len() >= MAX_EMAILS {
            break;
        }

        println!("Enter the number of emails to add:");
        let mut input = String::new();
        std::io::stdin().read_line(&mut input).expect("Failed to read line");
        let num_emails: u32 = input.trim().parse().expect("Please type a number");

        for _ in 0..num_emails {
            println!("Enter the ID of the email (1-10):");
            let mut input = String::new();
            std::io::stdin().read_line(&mut input).expect("Failed to read line");
            let id: u32 = input.trim().parse().expect("Please type a number");

            let email = Email::new(id);

            if email.is_urgent() {
                email.urgent = true;
            }

            email_queue.push_back(email);
        }

        // Shuffle the queue occasionally
        if email_queue.len() > 5 {
            email_queue.shuffle();
        }

        // Process the oldest email
        if let Some(email) = email_queue.pop_front() {
            email.process();
        } else {
            break;
        }

        std::thread::sleep(Duration::from_secs(1));
    }
}

fn main() {
    manage_email_queue();
}
