use smallvec::{SmallVec, SmallVecBuilder};

pub fn combine_small_data_streams(streams: Vec<Vec<u8>>) -> Vec<u8> {
    let mut combined_stream = SmallVec::<Vec<u8>::with_capacity(streams.iter().map(|s| s.len()).sum::<usize>())?;
