func logEvents(ctx context.Context, buffer *sync.Buffer, maxSize int) {
    for {
        select {
        case event := <-ctx.Done():
            return
        case msg, ok := <-buffer.Read():
            if !ok {
                return
            }
            fmt.Println(msg)
            // Process the event here
            event := &Event{
                ID:     uuid.NewString(),
                Message: msg,
            }
            fmt.Println(event)
        }
    }
}

func main() {
    ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
    defer cancel()

    var buffer sync.Buffer
    buffer.Grow(1024 * 1024) // Set buffer size to 1MB

    logEvents(ctx, &buffer, 1024*1024) // Flush the buffer when it surpasses 1MB
}
