const (
	bufferSize = 1024
)

type EventBuffer struct {
	buf []byte
	mu   sync.Mutex
}

func NewEventBuffer() *EventBuffer {
	return &EventBuffer{
		buf: make([]byte, bufferSize),
	}
}

func (eb *EventBuffer) Read(p []byte) (n int, err error) {
	eb.mu.Lock()
	defer eb.mu.Unlock()

	n, err = copy(p, eb.buf)
	if n == len(eb.buf) {
		return 0, fmt.Errorf("buffer is full")
	}
	return
}

func (eb *EventBuffer) Write(data []byte) error {
	eb.mu.Lock()
	defer eb.mu.Unlock()

	if len(eb.buf) + len(data) > bufferSize {
		return fmt.Errorf("buffer capacity exceeded")
	}

	copy(eb.buf[len(eb.buf):len(eb.buf)+len(data)], data)
	return nil
}

func logEvents(events chan []byte, buffer *EventBuffer) {
	for event := range events {
		err := buffer.Write(event)
		if err != nil {
			fmt.Println(err)
			return
		}
		if len(buffer.buf) >= bufferSize*2 {
			fmt.Println("Flushing buffer...")
			buffer.buf = buffer.buf[:0]
		}
	}
}

func main() {
	events := make(chan []byte)
	go func() {
		for i := 0; i < 10000; i++ {
			event := []byte(fmt.Sprintf("Event %d", i))
			events <- event
		}
		close(events)
	}()

	buffer := NewEventBuffer()
	logEvents(events, buffer)
}
