package main

import (
	"fmt"
	"sync"
)

const maxBufferSize = 1000

type EventBuffer struct {
	buffer []string
	mu     sync.RWMutex
	size   int
}

func NewEventBuffer() *EventBuffer {
	return &EventBuffer{
		buffer: make([]string, maxBufferSize),
	}
}

func (eb *EventBuffer) AddEvent(event string) error {
	eb.mu.Lock()
	defer eb.mu.Unlock()

	if eb.size >= maxBufferSize {
		return fmt.Errorf("buffer capacity exceeded")
	}

	eb.buffer[eb.size] = event
	eb.size++

	return nil
}

func (eb *EventBuffer) Flush() ([]string, error) {
	var events []string
	eb.mu.Lock()
	defer eb.mu.Unlock()

	events = append(events, eb.buffer...)
	eb.buffer = eb.buffer[:eb.size]
	eb.size = 0

	return events, nil
}

func logEvents(buffer *EventBuffer, chunkSize int) {
	for i := 0; i < maxBufferSize; i++ {
		event := fmt.Sprintf("Event %d", i)
		if err := buffer.AddEvent(event); err != nil {
			fmt.Println(err)
			break
		}

		if (i+1)%chunkSize == 0 || i == maxBufferSize-1 {
			events, err := buffer.Flush()
			if err != nil {
				fmt.Println(err)
				break
			}
			for _, event := range events {
				fmt.Println(event)
			}
		}
	}
}

func main() {
	buffer := NewEventBuffer()
	logEvents(buffer, 10)
}
