std::vector<std::pair<int, int>> mergeMeetingTimes(std::vector<std::pair<int, int>>& intervals) {
    if (intervals.size() < 2) return intervals;

    std::priority_queue<std::pair<int, std::pair<int, int>>> pq;
    for (const auto& interval : intervals) {
        pq.push({interval.first, interval});
    }

    std::vector<std::pair<int, int>> merged;
    while (!pq.empty()) {
        auto [start, meeting] = pq.top();
        pq.pop();

        if (!merged.empty() && start <= merged.back().second.first) {
            merged.back().second.second = std::max(meeting.second.second, merged.back().second.second);
        } else {
            merged.push_back({start, meeting.second});
        }

        if (!pq.empty() && pq.top().first == start) {
            pq.pop();
            pq.push({pq.top().first, pq.top().second});
        }
    }

    return merged;
}
