#include <queue>
#include <vector>

std::vector<std::pair<int, int>> mergeMeetingTimes(std::vector<std::pair<int, int>>& intervals) {
    if (intervals.size() == 0) return {};

    std::priority_queue<std::pair<int, std::pair<int, int>>, std::vector<std::pair<int, std::pair<int, int>>>, 
                        [](const std::pair<int, std::pair<int, int>>& a, const std::pair<int, std::pair<int, int>>& b) {
                            return a.first < b.first;
                        }> pq;

    for (const auto& interval : intervals) {
        pq.push({interval.first, interval});
    }

    std::vector<std::pair<int, int>> mergedIntervals;
    while (!pq.empty()) {
        auto top = pq.top();
        pq.pop();

        if (!mergedIntervals.empty() && top.first <= mergedIntervals.back().second) {
            mergedIntervals.back().second = std::max(mergedIntervals.back().second, top.second.second);
        } else {
            mergedIntervals.push_back(top.second);
        }

        if (pq.size() < 10) {
            pq.push({top.second.first, top.second});
        }
    }

    return mergedIntervals;
}
