type Inventory struct {
	inventory map[string]int
	maxSize  int
}

func NewInventory(maxSize int) *Inventory {
	return &Inventory{
		inventory: make(map[string]int),
		maxSize:   maxSize,
	}
}

func (i *Inventory) trackInventoryStatus(productID string, operation string, quantity int) error {
	if i.maxSize < 0 {
		return fmt.Errorf("max size cannot be negative")
	}

	switch operation {
	case "add":
		if _, ok := i.inventory[productID]; ok {
			i.inventory[productID] += quantity
		} else {
			if len(i.inventory) >= i.maxSize {
				return fmt.Errorf("inventory is full")
			}
			i.inventory[productID] = quantity
		}
	case "remove":
		if _, ok := i.inventory[productID]; ok {
			if quantity > i.inventory[productID] {
				return fmt.Errorf("not enough quantity to remove")
			}
			i.inventory[productID] -= quantity
			if i.inventory[productID] == 0 {
				delete(i.inventory, productID)
			}
		} else {
			return fmt.Errorf("product not found")
		}
	case "modify":
		if _, ok := i.inventory[productID]; ok {
			i.inventory[productID] = quantity
		} else {
			return fmt.Errorf("product not found")
		}
	default:
		return fmt.Errorf("invalid operation")
	}

	return nil
}

func (i *Inventory) getInventory() map[string]int {
	return i.inventory
}

func main() {
	inventory := NewInventory(100)
	fmt.Println(inventory.trackInventoryStatus("P001", "add", 10))
	fmt.Println(inventory.trackInventoryStatus("P002", "add", 20))
	fmt.Println(inventory.trackInventoryStatus("P001", "remove", 5))
	fmt.Println(inventory.trackInventoryStatus("P003", "add", 30)) // inventory is full
	fmt.Println(inventory.trackInventoryStatus("P001", "remove", 15)) // not enough quantity to remove
	fmt.Println(inventory.trackInventoryStatus("P004", "add", 40)) // product not found
	fmt.Println(inventory.getInventory())
