type Inventory struct {
	inventory map[string]int
	maxSize  int
}

func NewInventory(maxSize int) *Inventory {
	return &Inventory{
		inventory: make(map[string]int),
		maxSize:   maxSize,
	}
}

func (i *Inventory) trackInventoryStatus(operation string, productId string, quantity int) error {
	if operation != "add" && operation != "remove" && operation != "modify" && operation != "check" {
		return errors.New("invalid operation")
	}

	if i.maxSize < 0 {
		return errors.New("max size cannot be negative")
	}

	switch operation {
	case "add":
		if _, ok := i.inventory[productId]; ok {
			return fmt.Errorf("product ID already exists in inventory")
		}
		if len(i.inventory) >= i.maxSize {
			return fmt.Errorf("inventory is full, cannot add more items")
		}
		i.inventory[productId] = quantity
	case "remove":
		if _, ok := i.inventory[productId]; !ok {
			return fmt.Errorf("product ID does not exist in inventory")
		}
		if quantity > i.inventory[productId] {
			return fmt.Errorf("cannot remove more items than available")
		}
		i.inventory[productId] -= quantity
	case "modify":
		if _, ok := i.inventory[productId]; !ok {
			return fmt.Errorf("product ID does not exist in inventory")
		}
		if quantity == 0 {
			delete(i.inventory, productId)
		} else {
			i.inventory[productId] = quantity
		}
	case "check":
		return nil
	default:
		return errors.New("unknown error")
	}

	return nil
}

func (i *Inventory) getQuantity(productId string) (int, error) {
	if _, ok := i.inventory[productId]; !ok {
		return 0, fmt.Errorf("product ID does not exist in inventory")
	}
	return i.inventory[productId], nil
}

