	fmt.Println(inventory.trackInventoryStatus("add", "P001", 10)) // No error
	fmt.Println(inventory.trackInventoryStatus("add", "P002", 20)) // No error
	fmt.Println(inventory.trackInventoryStatus("remove", "P001", 5)) // No error
	fmt.Println(inventory.trackInventoryStatus("check", "", ""))     // No error
	fmt.Println(inventory.trackInventoryStatus("modify", "P001", 15)) // No error
	fmt.Println(inventory.trackInventoryStatus("remove", "P002", 30)) // Error: product ID does not exist in inventory
	fmt.Println(inventory.trackInventoryStatus("add", "P003", 40)) // Error: inventory is full, cannot add more items
