std::vector<std::string> filterUniqueEmails(const std::vector<std::string>& emails) {
    // Preprocess each email by converting to lowercase and normalizing dots
    std::vector<std::string> preprocessedEmails;
    for (const auto& email : emails) {
        size_t atPos = email.find('@');
        if (atPos != std::string::npos) {
            std::string localPart = email.substr(0, atPos);
            std::string domain = email.substr(atPos + 1);

            // Normalize dots before the "@" symbol
            size_t dotPos = localPart.find('.');
            while (dotPos != std::string::npos) {
                localPart.replace(dotPos, 1, ".");
                dotPos = localPart.find('.', dotPos + 1);
            }

            // Convert to lowercase
            for (char& c : localPart) {
                c = std::tolower(c);
            }

            std::string normalizedEmail = localPart + "." + domain;
            preprocessedEmails.push_back(normalizedEmail);
        }
    }

    // Store unique emails in a set
    std::set<std::string> uniqueEmails(preprocessedEmails.begin(), preprocessedEmails.end());

    // Convert set back to list, sort alphabetically, and limit to 50 items
    std::vector<std::string> result(uniqueEmails.begin(), uniqueEmails.end());
    std::sort(result.begin(), result.end());
    result.resize(50);

    return result;
}

int main() {
    std::vector<std::string> emails = {"test@example.com", "Test@EXAMPLE.COM", "test2@example.com", "test3@example.com"};
    std::vector<std::string> filteredEmails = filterUniqueEmails(emails);

    for (const auto& email : filteredEmails) {
        std::cout << email << std::endl;
    }

