void sortLogsByTimestamp(std::deque<std::pair<std::string, std::string>>& logQueue) {
    while (true) {
        std::string logEntry;
        std::cout << "Enter log entry (or 'exit' to stop): ";
        std::getline(std::cin, logEntry);

        if (logEntry == "exit") {
            break;
        }

        size_t spacePos = logEntry.find(' ');
        if (spacePos != std::string::npos) {
            std::string timestamp = logEntry.substr(0, spacePos);
            std::string content = logEntry.substr(spacePos + 1);

            // Check if the timestamp already exists in the queue
            auto it = logQueue.begin();
            while (it != logQueue.end()) {
                if (it->first == timestamp) {
                    // Merge the new log with the existing one
                    it->second += ", " + content;
                    break;
                }
                ++it;
            }

            if (logQueue.size() >= 100) {
                // Remove the oldest log entry if the queue is full
                logQueue.pop_front();
            }
        } else {
            std::cout << "Invalid log format. Please use 'timestamp content'" << std::endl;
        }
    }
}

int main() {
    std::deque<std::pair<std::string, std::string>> logQueue;

    sortLogsByTimestamp(logQueue);

    for (const auto& log : logQueue) {
        std::cout << log.first << ": " << log.second << std::endl;
    }

