#include <iostream>
#include <deque>
#include <map>

class Log {
public:
    std::string timestamp;
    std::string content;

    Log(std::string ts, std::string c) : timestamp(ts), content(c) {}
};

std::deque<Log> sortLogsByTimestamp(const std::deque<Log>& logs) {
    std::deque<Log> sortedLogs;
    std::map<std::string, int> timestampCount;

    for (const auto& log : logs) {
        if (timestampCount.find(log.timestamp) != timestampCount.end()) {
            timestampCount[log.timestamp]++;
        } else {
            timestampCount[log.timestamp] = 1;
        }
    }

    for (const auto& pair : timestampCount) {
        for (int i = 0; i < pair.second; ++i) {
            sortedLogs.push_back(pair.first);
        }
    }

    while (sortedLogs.size() > 100) {
        sortedLogs.pop_front();
    }

    return sortedLogs;
}

void printSortedLogs(const std::deque<Log>& sortedLogs) {
    for (const auto& log : sortedLogs) {
        std::cout << "Timestamp: " << log.timestamp << ", Content: " << log.content << std::endl;
    }
}

int main() {
    // Example usage
    std::deque<Log> logs = {{"2022-01-01 12:00:00", "Log 1"}, {"2022-01-01 12:05:00", "Log 2"}, 
                            {"2022-01-01 12:10:00", "Log 3"}, {"2022-01-01 12:15:00", "Log 4"}, 
                            {"2022-01-01 12:20:00", "Log 5"}};

    std::deque<Log> sortedLogs = sortLogsByTimestamp(logs);

    printSortedLogs(sortedLogs);

