                std::io::stdin().read_line(&mut quantity).expect("Failed to read line");
                quantity = quantity.trim().to_string();

                let quantity: i32 = quantity.parse().expect("Invalid quantity");
                let product_id = product_id.parse::<i32>().expect("Invalid product ID");

                if let Some(existing_product) = inventory.iter().find(|&x| x.0 == product_id) {
                    let new_quantity = existing_product.1 + quantity;
                    inventory.push((product_id, new_quantity));
                } else {
                    inventory.push((product_id, quantity));
