                let mut updated = false;
                for (i, (id, quantity)) in inventory.iter_mut().enumerate() {
                    if *id == product_id {
                        if *quantity >= quantity {
                            *quantity -= quantity;
                            updated = true;
                        } else {
                            println!("Not enough quantity in stock.");
                        }
                        break;
                    }
                }

                if !updated {
                    println!("Product not found in inventory.");
                }
            },
            "3" => {
                println!("Current Inventory:");
                for (id, quantity) in &inventory {
                    println!("Product ID: {}, Quantity: {}", id, quantity);
                }
            },
            "4" => {
                break;
            },
            _ => println!("Invalid choice. Please try again."),
        }
    }
