import queue

class PrintQueue:
    def __init__(self):
        self.queue = queue.Queue(maxsize=10)
        self.pending_tasks = 0

    def put(self, task):
        if self.queue.qsize() < 10:
            self.queue.put(task)
            self.pending_tasks += 1
            print(f"Task added to the queue. Current pending tasks: {self.pending_tasks}")
        else:
            print("Queue is full. Cannot add more tasks.")

    def get(self):
        if not self.queue.empty():
            task = self.queue.get()
            self.pending_tasks -= 1
            print(f"Task processed. Current pending tasks: {self.pending_tasks}")
            return task
        else:
            print("No tasks in the queue.")
