class Task {
public:
    int id;
    std::string status;

    Task(int id, std::string status) : id(id), status(status) {}
};

class BatchProcessor {
private:
    std::vector<Task> tasks;

public:
    void addTask(const Task& task) {
        tasks.push_back(task);
    }

    void completeTask(int taskId, const std::string& status) {
        for (auto& task : tasks) {
            if (task.id == taskId) {
                task.status = status;
                return;
            }
        }
    }

    void printTasks() const {
        for (const auto& task : tasks) {
            std::cout << "ID: " << task.id << ", Status: " << task.status << std::endl;
        }
    }
};

void batchProcessTasks(const std::vector<int>& taskIds, const std::vector<std::string>& statuses) {
    BatchProcessor processor;
    for (size_t i = 0; i < taskIds.size(); ++i) {
        processor.addTask(Task(taskIds[i], statuses[i]));
    }

    for (size_t i = 0; i < taskIds.size(); ++i) {
        processor.completeTask(taskIds[i], statuses[i]);
    }

    processor.printTasks();
}

int main() {
    std::vector<int> taskIds = {1, 2, 3, 4, 5};
    std::vector<std::string> statuses = {"pending", "pending", "pending", "completed", "pending"};
    batchProcessTasks(taskIds, statuses);
    return 0;
}
