#include <iostream>
#include <vector>
#include <list>

class TaskManager {
public:
    void batchProcessTasks(const std::vector<int>& taskIds, const std::vector<std::string>& statuses) {
        // Limit the list to a maximum of 50 tasks
        while (tasks.size() > 50) {
            tasks.pop_back();
        }

        // Process each task
        for (size_t i = 0; i < taskIds.size(); ++i) {
            // Check if the task exists in the list
            auto it = tasks.begin();
            while (it != tasks.end()) {
                if (*it == taskIds[i]) {
                    // Update the task status
                    it->second = statuses[i];
                    break;
                }
                ++it;
            }

            // If the task is not found, add it to the end
            if (it == tasks.end()) {
                tasks.push_back({taskIds[i], statuses[i]});
            }
        }

        // Remove completed tasks
        for (auto it = tasks.begin(); it != tasks.end();) {
            if (it->second == "completed") {
                it = tasks.erase(it);
            } else {
                ++it;
            }
        }
    }

private:
    std::list<std::pair<int, std::string>> tasks;
};

int main() {
    TaskManager manager;
    std::vector<int> taskIds = {1, 2, 3, 4, 5};
    std::vector<std::string> statuses = {"pending", "pending", "pending", "completed", "pending"};

    manager.batchProcessTasks(taskIds, statuses);

    // Print the updated tasks
    for (const auto& task : manager.tasks) {
        std::cout << "(" << task.first << ", " << task.second << ")" << std::endl;
    }

    return 0;
}
