def compare_string_sequences(seq1, seq2):
    if len(seq1) != 4 or len(seq2) != 4:
        raise ValueError("Both sequences must contain exactly 4 strings")

    report = {
        "seq1": {"proper_case": True, "matches": 0, "mismatches": 0, "differences": []},
        "seq2": {"proper_case": True, "matches": 0, "mismatches": 0, "differences": []}
    }

    for i in range(4):
        if not all(char.isupper() for char in seq1[i]):
            report["seq1"]["proper_case"] = False
        if not all(char.isupper() for char in seq2[i]):
            report["seq2"]["proper_case"] = False

        if seq1[i] == seq2[i]:
            report["seq1"]["matches"] += 1
            report["seq2"]["matches"] += 1
        else:
            report["seq1"]["mismatches"] += 1
            report["seq2"]["mismatches"] += 1
            report["seq1"]["differences"].append(i)
            report["seq2"]["differences"].append(i)

    return report
