#include <vector>

std::unordered_map<std::string, std::vector<std::string>> categorizeStudentGrades(const std::unordered_map<std::string, double>& studentGrades) {
    std::unordered_map<std::string, std::vector<std::string>> categorizedGrades;

    // Define grade ranges and corresponding tiers
    std::unordered_map<std::string, std::string> gradeRanges = {
        {"A", "90-100"},
        {"B", "80-89"},
        {"C", "70-79"},
        {"D", "60-69"},
        {"F", "Below 60"}
    };

    // Iterate over each student grade
    for (const auto& pair : studentGrades) {
        const std::string& studentId = pair.first;
        double grade = pair.second;

        // Find the tier for the current grade
        for (const auto& rangeTier : gradeRanges) {
            if (grade >= std::stod(rangeTier.second.substr(0, rangeTier.second.find('-')))) {
                categorizedGrades[rangeTier.first].push_back(studentId);
                break;
            }
        }
    }

    return categorizedGrades;
}

int main() {
    // Example usage
    std::unordered_map<std::string, double> studentGrades = {
        {"S1", 85},
        {"S2", 92},
        {"S3", 67},
        {"S4", 58},
        {"S5", 31}
    };

    std::unordered_map<std::string, std::vector<std::string>> categorizedGrades = categorizeStudentGrades(studentGrades);

    // Print the categorized grades
    for (const auto& pair : categorizedGrades) {
        const std::string& tier = pair.first;
        const std::vector<std::string>& studentIds = pair.second;

        std::cout << tier << ": ";
        for (const std::string& studentId : studentIds) {
            std::cout << studentId << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
