        {90, "A"},
        {80, "B"},
        {70, "C"},
        {60, "D"},
        {0, "F"}
    };

    // Initialize an unordered_map with a reserve of 50 entries to avoid frequent rehashes
    std::unordered_map<std::string, std::vector<int>, std::hash<std::string>> categorizedGrades;
    categorizedGrades.reserve(50);

    // Iterate over each student ID and grade pair in the input vector
    for (const auto& [studentId, grade] : gradePairs) {
        // Determine the grade tier based on the predefined ranges
        const auto& gradeTier = gradeRanges.find(grade);
        if (gradeTier != gradeRanges.end()) {
            // Insert or append the student ID to the corresponding grade tier in the map
            categorizedGrades[gradeTier->second].push_back(studentId);
        }
    }

    // Restrict the size of the unordered_map to hold no more than 100 entries
    categorizedGrades.max_size(100);

    return categorizedGrades;
}

