#include <iostream>
#include <unordered_map>
#include <vector>

class TieredMap {
private:
    std::unordered_map<std::string, std::vector<int>> grades;
    int maxEntries;

public:
    TieredMap() : maxEntries(100) {}

    void insert(const std::pair<int, char>& gradePair) {
        if (grades.size() >= maxEntries) {
            throw std::runtime_error("Map is full. Cannot insert more entries.");
        }

        auto& tier = grades[gradePair.second];
        if (tier.empty()) {
            tier.push_back(gradePair.first);
        } else {
            for (int studentId : tier) {
                if (studentId <= gradePair.first) {
                    tier.push_back(gradePair.first);
                    break;
                }
            }
        }
    }

    void clear() {
        grades.clear();
    }

    void reserve(int size) {
        if (size > maxEntries) {
            throw std::invalid_argument("Size exceeds the maximum allowed entries.");
        }
        grades.reserve(size);
    }

    void printGrades() const {
        for (const auto& pair : grades) {
            std::cout << "Grade: " << pair.first << ", Students: ";
            for (int studentId : pair.second) {
                std::cout << studentId << " ";
            }
            std::cout << std::endl;
        }
    }
};

TieredMap categorizeStudentGrades() {
    TieredMap map;
    map.reserve(50);

    // Example usage:
    map.insert({90, 'A'});
    map.insert({80, 'B'});
    map.insert({70, 'C'});
    map.insert({60, 'D'});
    map.insert({50, 'F'});

    return map;
}

int main() {
    TieredMap categorizedGrades = categorizeStudentGrades();
    categorizedGrades.printGrades();

    return 0;
}
