            self.grades.push_back((student_id, grade));
        } else {
            panic!("Maximum grade entries reached.");
        }
    }

    fn update_grade(&mut self, student_id: i32, grade: i32) {
        for (id, existing_grade) in &mut self.grades {
            if *id == student_id {
                *existing_grade = grade;
                return;
            }
        }
        panic!("Student ID not found.");
    }

    fn delete_grade(&mut self, student_id: i32) {
        for index in (0..self.grades.len()).rev() {
            let (id, _) = &self.grades[index];
            if *id == student_id {
                self.grades.remove_at(index);
                return;
            }
        }
        panic!("Student ID not found.");
    }

    fn average_grade(&self) -> f64 {
        if self.grades.is_empty() {
            0.0
        } else {
            let sum: i32 = self.grades.iter().map(|(_, grade)| *grade).sum();
            (sum as f64) / self.grades.len() as f64
        }
    }
