#include <stack>
#include <string>
#include <unordered_map>

bool validateBrackets(const std::string& s) {
    std::stack<char> stack;
    std::unordered_map<char, char> bracketMap = {
        {'(', ')'},
        {'[', ']'},
        {'{', '}'}
    };

    for (char c : s) {
        if (bracketMap.find(c) != bracketMap.end()) {
            stack.push(c);
        } else if (!stack.empty() && stack.top() == bracketMap.at(c)) {
            stack.pop();
        } else {
            return false;
        }
    }

    return stack.empty();
}
