    for (char bracket : s) {
        if (bracket == '(' || bracket == '{' || bracket == '[') {
            stack.push(bracket);
        } else if (bracket == ')' || bracket == '}' || bracket == ']') {
            if (stack.empty()) {
                return false;
            }
            char top = stack.top();
            stack.pop();
            if ((top == '(' && bracket != ')') ||
                (top == '{' && bracket != '}') ||
                (top == '[' && bracket != ']')) {
                return false;
            }
        }
        if (stack.size() >= 10) {
            return false;
        }
    }
    return stack.empty();
}
