package main

import (
	"sync"
)

type ResourceStatus struct {
	Status string `json:"status"`
}

type ResourceMonitor struct {
	mu    sync.Map
	count int
	max   int
}

func NewResourceMonitor(maxResources int) *ResourceMonitor {
	return &ResourceMonitor{
		max: maxResources,
	}
}

func (r *ResourceMonitor) Load(resource string, status string) error {
	if r.mu.LoadOrStore(resource, status) == nil {
		return fmt.Errorf("resource already exists")
	}
	return nil
}

func (r *ResourceMonitor) Store(resource string, status string) error {
	if _, ok := r.mu.Load(resource); ok {
		return fmt.Errorf("resource does not exist")
	}
	if r.count >= r.max {
		return fmt.Errorf("maximum resources reached")
	}
	r.mu.Store(resource, status)
	r.count++
	return nil
}

func (r *ResourceMonitor) Delete(resource string) error {
	if _, ok := r.mu.Load(resource); !ok {
		return fmt.Errorf("resource does not exist")
	}
	delete(r.mu, resource)
	r.count--
	return nil
}

func (r *ResourceMonitor) GetCount() int {
	return r.count
}

func (r *ResourceMonitor) IsEnabled(resource string) bool {
	status, _ := r.mu.Load(resource)
	return status != ""
}

func cacheResourceStatus(maxResources int) *ResourceMonitor {
	return NewResourceMonitor(maxResources)
}
