import java.util.regex.Pattern;

public class Main {
    public static void main(String[] args) {
        String article = "The quick brown fox jumps over the lazy dog. The dog is very lazy.";
        List<String> wordsToCheck = Arrays.asList("fox", "dog");
        Map<String, Integer> anagramOccurrences = detectAnagramOccurrences(article, wordsToCheck);
        System.out.println(anagramOccurrences);
    }

    public static Map<String, Integer> detectAnagramOccurrences(String article, List<String> wordsToCheck) {
        // Normalize words for accurate anagram identification
        Map<String, String> normalizedWords = new HashMap<>();
        for (String word : wordsToCheck) {
            char[] chars = word.toLowerCase().toCharArray();
            Arrays.sort(chars);
            normalizedWords.put(word, new String(chars));
        }

        // Create a HashMap to store anagram occurrences
        Map<String, Integer> anagramOccurrences = new HashMap<>();

        // Split the article into words and count anagrams
        Pattern pattern = Pattern.compile("\\b\\w+\\b");
        Matcher matcher = pattern.matcher(article);
        while (matcher.find()) {
            String word = matcher.group().toLowerCase();
            char[] chars = word.toCharArray();
            Arrays.sort(chars);
            String normalizedWord = new String(chars);

            if (normalizedWords.containsKey(normalizedWord)) {
                anagramOccurrences.putIfAbsent(normalizedWords.get(normalizedWord), 0);
                anagramOccurrences.put(normalizedWord, anagramOccurrences.get(normalizedWord) + 1);
            }
        }

        // Limit the HashMap to 10 entries
        return Collections.unmodifiableMap(new LinkedHashMap<>(anagramOccurrences.subMap(0, 10, null, null)));
    }
}
