                int index = c - 'a';
                for (int i = 0; i < limit; i++) {
                    char keyChar = words[i].charAt(0);
                    int keyIndex = keyChar - 'a';
                    if (index == keyIndex) {
                        anagramCount.put(words[i], anagramCount.get(words[i]) + 1);
                    }
                }
            }
        }

        return anagramCount;
    }

    public static void main(String[] args) {
        String text = "The quick brown fox jumps over the lazy dog";
        String[] words = {"fox", "dog", "cat", "sun", "tree"};
        System.out.println(detectAnagramOccurrences(text, words));
