import java.util.HashMap;
import java.util.Map;

public class Main {
    public static Map<String, Integer> detectAnagramOccurrences(String text, String[] words) {
        Map<String, Integer> anagrams = new HashMap<>();
        int limit = Math.min(10, words.length);
        for (int i = 0; i < limit; i++) {
            anagrams.put(words[i], 0);
        }

        for (String word : words) {
            if (anagrams.containsKey(word)) {
                continue;
            }
            for (int j = i + 1; j <= limit && j <= words.length; j++) {
                StringBuilder sb = new StringBuilder(word);
                for (int k = i + 1; k < j; k++) {
                    sb.append(words[k]);
                }
                String sortedWord = sb.toString();
                String sortedText = sortString(text.substring(i).concat(text.substring(j)));
                if (sortedWord.equals(sortedText)) {
                    anagrams.put(word, anagrams.get(word) + 1);
                    break;
                }
            }
        }
        return anagrams;
    }

    private static String sortString(String str) {
        char[] chars = str.toCharArray();
        java.util.Arrays.sort(chars);
        return new String(chars);
    }

    public static void main(String[] args) {
        String text = "abxaba";
        String[] words = {"ab", "ba"};
        System.out.println(detectAnagramOccurrences(text, words));
    }
}
