#include <iostream>
#include <map>
#include <vector>
#include <algorithm>

std::map<int, double> organizeSurveyData(const std::vector<std::pair<int, double>>& responses) {
    // Create a map to store responses
    std::map<int, double> surveyData;

    // Iterate through the responses
    for (const auto& response : responses) {
        // Update the rating for the participant
        surveyData[response.first] = response.second;
    }

    // Sort the ratings by participant ID
    for (auto& pair : surveyData) {
        for (int i = 1; i < pair.first; ++i) {
            if (pair.second > surveyData[i]) {
                std::swap(pair.second, surveyData[i]);
                std::swap(pair.first, i);
            }
        }
    }

    return surveyData;
}

// Function to query the rating for a specific participant
double getRating(const std::map<int, double>& surveyData, int participantId) {
    // Check if the participant ID exists in the map
    if (surveyData.find(participantId) != surveyData.end()) {
        return surveyData[participantId];
    } else {
        return -1; // Return -1 if the participant ID is not found
    }
}

// Function to update the rating for a specific participant
void updateRating(std::map<int, double>& surveyData, int participantId, double newRating) {
    // Check if the participant ID exists in the map
    if (surveyData.find(participantId) != surveyData.end()) {
        surveyData[participantId] = newRating;
    } else {
        std::cout << "Participant ID not found." << std::endl;
    }
}

int main() {
    // Example usage
    std::vector<std::pair<int, double>> responses = {{1, 5}, {2, 4}, {1, 3}, {3, 5}, {2, 4}, {3, 5}};
    std::map<int, double> surveyData = organizeSurveyData(responses);

    std::cout << "Survey Data:" << std::endl;
    for (const auto& pair : surveyData) {
        std::cout << "Participant ID: " << pair.first << ", Rating: " << pair.second << std::endl;
    }

    std::cout << "\nGet Rating for Participant 2:" << std::endl;
    std::cout << getRating(surveyData, 2) << std::endl;

    std::cout << "\nUpdate Rating for Participant 1:" << std::endl;
    updateRating(surveyData, 1, 4);

    std::cout << "\nUpdated Survey Data:" << std::endl;
    for (const auto& pair : surveyData) {
        std::cout << "Participant ID: " << pair.first << ", Rating: " << pair.second << std::endl;
    }

    return 0;
}
