    let mut word_freq: HashMap<String, usize> = HashMap::new();

    for word in words {
        *word_freq.entry(word.to_string()).or_insert(0) += 1;
    }

    // Limit the map to 50 entries
    let mut limited_word_freq: HashMap<String, usize> = HashMap::new();
    for (word, freq) in word_freq.drain() {
        if limited_word_freq.len() < 50 {
            limited_word_freq.insert(word.clone(), freq);
        } else {
            break;
        }
    }

    limited_word_freq
