func (h *HRSystem) push(id int, name string, position string, salary float64) {
	if h.top < len(h.records)-1 {
		h.records[h.top].id = id
		h.records[h.top].name = name
		h.records[h.top].position = position
		h.records[h.top].salary = salary
		h.top++
	} else {
		fmt.Println("Maximum capacity reached.")
	}
}

func (h *HRSystem) pop() (int, string, string, float64) {
	if h.bottom == h.top {
		return -1, "", "", 0.0
	}
	employee := h.records[h.bottom]
	h.bottom++
	return employee.id, employee.name, employee.position, employee.salary
}

