)

type Employee struct {
	name     string
	id       int
	position string
	salary   float64
}

type HRSystem struct {
	records []Employee
	size    int
}

func NewHRSystem() *HRSystem {
	return &HRSystem{
		records: make([]Employee, 0),
		size:    100,
	}
}

func (h *HRSystem) push(record Employee) error {
	if len(h.records) >= h.size {
		return errors.New("system is full")
	}
	h.records = append(h.records, record)
	return nil
}

func (h *HRSystem) pop(id int) (Employee, error) {
	for i, record := range h.records {
		if record.id == id {
			employee := record
			h.records = append(h.records[:i], h.records[i+1:]...)
			return employee, nil
		}
	}
	return Employee{}, errors.New("employee not found")
}

func (h *HRSystem) update(id int, record Employee) error {
	for i, existingRecord := range h.records {
		if existingRecord.id == id {
			h.records[i] = record
			return nil
		}
	}
	return errors.New("employee not found")
}

func manageEmployeeRecords() {
	hR := NewHRSystem()

	addRecord := func(name string, id int, position string, salary float64) {
		record := Employee{name, id, position, salary}
		if err := hR.push(record); err != nil {
			fmt.Println(err)
		} else {
			fmt.Printf("Added employee with ID %d: %v\n", id, record)
		}
	}

	updateRecord := func(id int, name string, position string, salary float64) {
