			fmt.Println(err)
		} else {
			fmt.Printf("Updated employee with ID %d: %v\n", id, Employee{name, id, position, salary})
		}
	}

	retrieveRecord := func(id int) {
		var record Employee
		if err := hR.pop(id); err != nil {
			fmt.Println(err)
		} else {
			fmt.Printf("Retrieved employee with ID %d: %v\n", id, record)
		}
	}

	// Example usage:
	addRecord("John Doe", 1, "Software Engineer", 80000.0)
	addRecord("Jane Smith", 2, "Data Scientist", 120000.0)
	retrieveRecord(1)
	updateRecord(1, "John Doe", "Senior Software Engineer", 90000.0)
