std::vector<double> computeRollingAverages(const std::vector<int>& temperatures, int windowSize) {
    std::vector<double> rollingAverages;
    std::deque<int> window;

    for (int temp : temperatures) {
        while (!window.empty() && window.front() <= 0) {
            window.pop_front();
        }

        if (!window.empty()) {
            window.push_back(temp);
        } else {
            window.push_back(temp);
        }

        if (window.size() > windowSize) {
            window.pop_back();
        }

        double sum = 0.0;
        for (int num : window) {
            sum += num;
        }
        double average = static_cast<double>(sum) / window.size();

        rollingAverages.push_back(average);
    }

    return rollingAverages;
}
