std::vector<double> computeRollingAverages(const std::vector<int>& temperatures, int windowSize) {
    if (windowSize > temperatures.size()) {
        throw std::invalid_argument("Window size cannot be larger than the number of temperatures.");
    }

    std::vector<double> rollingAverages;
    std::vector<double> intermediateCalculations;

    for (int i = 0; i < temperatures.size(); ++i) {
        double sum = 0.0;
        for (int j = std::max(0, i - windowSize + 1); j <= std::min(i, windowSize - 1); ++j) {
            sum += temperatures[j];
        }
        double average = sum / windowSize;

        if (intermediateCalculations.size() == 10) {
            intermediateCalculations.erase(intermediateCalculations.begin());
        }
        intermediateCalculations.push_back(average);

        if (rollingAverages.size() == 10) {
            rollingAverages.pop_back();
        }
        rollingAverages.push_back(average);
    }

    return rollingAverages;
}
