        for (List<String> list : contactLists) {
            uniqueContacts.addAll(list);
        }

        // Convert the set back to a list and sort it alphabetically
        List<String> sortedUniqueContacts = new ArrayList<>(uniqueContacts);
        Collections.sort(sortedUniqueContacts);

        // Limit the list to 100 unique contacts
        if (sortedUniqueContacts.size() > 100) {
            sortedUniqueContacts.subList(100, sortedUniqueContacts.size()).clear();
        }

        // Create a linked list from the sorted list of unique contacts
        LinkedList<String> mergedLinkedList = new LinkedList<>(sortedUniqueContacts);

        return mergedLinkedList;
