package main

import (
	"fmt"
	"sync"
)

type LogEntry struct {
	Timestamp string
	Message   string
}

type Buffer struct {
	entries []LogEntry
	mu      sync.Mutex
	size    int
}

func NewBuffer(size int) *Buffer {
	return &Buffer{
		entries: make([]LogEntry, 0, size),
		size:    size,
	}
}

func (b *Buffer) Add(entry LogEntry) {
	b.mu.Lock()
	defer b.mu.Unlock()

	if len(b.entries) >= b.size {
		b.entries = b.entries[1:]
	}
	b.entries = append(b.entries, entry)
}

func (b *Buffer) Search(pattern string) map[string]int {
	b.mu.Lock()
	defer b.mu.Unlock()

	var errors map[string]int
	for _, entry := range b.entries {
		if strings.Contains(entry.Message, pattern) {
			errors[entry.Timestamp] = 1 + errors[entry.Timestamp]
		} else if _, ok := errors[entry.Timestamp]; ok {
			errors[entry.Timestamp]++
		}
	}
	return errors
}

func processLogFile() {
	buffer := NewBuffer(1000)

	go func() {
		for i := 0; i < 5000; i++ {
			timestamp := fmt.Sprintf("%d-%02d-00:00:00", i/100, i%100)
			message := fmt.Sprintf("Error %d: Something went wrong.", i)
			buffer.Add(LogEntry{Timestamp: timestamp, Message: message})
			time.Sleep(10 * time.Millisecond)
		}
	}()

	errors := buffer.Search("Error")
	for timestamp, count := range errors {
		fmt.Printf("Timestamp: %s, Error Count: %d\n", timestamp, count)
	}
}

func main() {
	processLogFile()
}
