package main

import (
	"fmt"
	"sync"
)

type LogEntry struct {
	Timestamp string
	Message   string
}

type Buffer struct {
	logs    []LogEntry
	mu      sync.Mutex
	size    int
	maxSize int
}

func NewBuffer(maxSize int) *Buffer {
	return &Buffer{
		logs: make([]LogEntry, 0),
		size: 0,
		maxSize: maxSize,
	}
}

func (b *Buffer) Push(log LogEntry) {
	b.mu.Lock()
	defer b.mu.Unlock()

	if b.size >= b.maxSize {
		b.pop()
	}

	b.logs = append(b.logs, log)
	b.size++
}

func (b *Buffer) Pop() LogEntry {
	b.mu.Lock()
	defer b.mu.Unlock()

	if b.size == 0 {
		return LogEntry{}
	}

	log := b.logs[0]
	b.logs = b.logs[1:]
	b.size--
	return log
}

func processLogFile(buffer *Buffer, searchPattern string) map[string]int {
	var errorReport = make(map[string]int)

	for i := 0; i < buffer.size; i++ {
		log := buffer.logs[i]
		if strings.Contains(log.Message, searchPattern) {
			errorReport[log.Timestamp] = errorReport[log.Timestamp] + 1
		}
	}

	return errorReport
}

func main() {
	buffer := NewBuffer(1000)

	log1 := LogEntry{"2022-01-01", "Error occurred at 10:00 AM"}
	log2 := LogEntry{"2022-01-02", "Error occurred at 11:00 AM"}
	log3 := LogEntry{"2022-01-03", "Error occurred at 12:00 PM"}

	buffer.Push(log1)
	buffer.Push(log2)
	buffer.Push(log3)

	searchPattern := "Error occurred"
	errorReport := processLogFile(buffer, searchPattern)

