use std::collections::HashSet;

fn detect_cycle_in_graph(graph: &Vec<Vec<i32>>) -> bool {
    let mut visited = HashSet::new();
    let mut current_path = HashSet::new();

    for node in 0..graph.len() {
        if !visited.contains(&node) {
            if dfs(graph, node, &mut visited, &mut current_path) {
                return true;
            }
        }
    }

    false
}

fn dfs(graph: &Vec<Vec<i32>>, node: i32, visited: &mut HashSet<i32>, current_path: &mut HashSet<i32>) -> bool {
    visited.insert(node);
    current_path.insert(node);

    for neighbor in graph[node as usize].clone() {
        if !visited.contains(&neighbor) {
            if dfs(graph, neighbor as i32, visited, current_path) {
                return true;
            }
        } else if current_path.contains(&neighbor) {
            return true;
        }
    }

    current_path.remove(&node);
    false
}

fn main() {
    let graph = vec![
        vec![1, 2],
        vec![0, 3],
        vec![0],
        vec![2],
        vec![3],
    ];

    let result = detect_cycle_in_graph(&graph);
    println!("Cyclic loop detected: {}", result);
}
