```rust
use std::collections::HashSet;

struct Graph {
    adjacency_list: Vec<Vec<usize>>,
}

impl Graph {
    fn new(n_nodes: usize) -> Self {
        Graph {
            adjacency_list: vec![Vec::new(); n_nodes],
        }
    }

    fn add_edge(&mut self, node1: usize, node2: usize) {
        self.adjacency_list[node1].push(node2);
    }

    fn detect_cycle_in_graph(&self) -> bool {
        let mut visited = HashSet::with_capacity(10);
        let mut current_path = HashSet::with_capacity(10);

        for i in 0..self.adjacency_list.len() {
            if !visited.contains(&i) {
                if self._detect_cycle_in_graph_util(i, &mut visited, &mut current_path) {
                    return true;
                }
            }
        }

        false
    }

    fn _detect_cycle_in_graph_util(
        &self,
        node: usize,
        visited: &mut HashSet<usize>,
        current_path: &mut HashSet<usize>,
    ) -> bool {
        visited.insert(node);
        current_path.insert(node);

        for neighbor in &self.adjacency_list[node] {
            if !visited.contains(neighbor) {
                if self._detect_cycle_in_graph_util(*neighbor, visited, current_path) {
                    return true;
                }
            } else if current_path.contains(neighbor) {
                return true;
            }
        }

        current_path.remove(&node);
        false
    }
}

fn main() {
    let graph = Graph::new(5);
    graph.add_edge(0, 1);
    graph.add_edge(1, 2);
    graph.add_edge(2, 3);
    graph.add_edge(3, 4);
    graph.add_edge(4, 0); // This edge creates a cycle

    println!("{}", graph.detect_cycle_in_graph()); // Output: true
}
