        Map<String, List<String>> scoreRanges = new HashMap<>();
        for (int i = 0; i < scores.size(); i++) {
            String key = getScoreRange(scores.get(i));
            if (!scoreRanges.containsKey(key)) {
                scoreRanges.put(key, new ArrayList<>());
            }
            scoreRanges.get(key).add(studentNames.get(i));
        }

        // Restrict the HashMap size to a maximum of 5 elements
        while (scoreRanges.size() > 5) {
            Map.Entry<String, List<String>> entry = Collections.max(scoreRanges.entrySet(), Comparator.comparingInt(Map.Entry::getFirst));
            scoreRanges.remove(entry.getKey());
        }

        System.out.println(scoreRanges);
    }

    private static String getScoreRange(int score) {
        if (score >= 90 && score <= 100) {
            return "[90-100]";
        } else if (score >= 80 && score < 90) {
            return "[80-90)";
        } else if (score >= 70 && score < 80) {
            return "[70-80)";
        } else if (score >= 60 && score < 70) {
            return "[60-70)";
        } else if (score >= 50 && score < 60) {
            return "[50-60)";
        } else if (score >= 40 && score < 50) {
            return "[40-50)";
        } else if (score >= 30 && score < 40) {
            return "[30-40)";
        } else if (score >= 20 && score < 30) {
            return "[20-30)";
        } else if (score >= 10 && score < 20) {
            return "[10-20)";
        } else {
