public class Main {
    private static final Map<String, String[]> scoreRanges = new HashMap<>();

    static {
        for (int i = 0; i < 5; i++) {
            int minScore = 100 - i * 10;
            int maxScore = minScore + 9;
            scoreRanges.put(String.format("%d-%d", minScore, maxScore), new String[0]);
        }
    }

    public static void categorizeStudentScores(String[] studentNames, int[] scores) {
        for (int i = 0; i < studentNames.length; i++) {
            int score = scores[i];
            if (score >= 90 && score <= 100) {
                String[] studentsInTier = scoreRanges.get("90-100");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("90-100", newStudentsInTier);
            } else if (score >= 80 && score < 90) {
                String[] studentsInTier = scoreRanges.get("80-90");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("80-90", newStudentsInTier);
            } else if (score >= 70 && score < 80) {
                String[] studentsInTier = scoreRanges.get("70-80");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("70-80", newStudentsInTier);
            } else if (score >= 60 && score < 70) {
                String[] studentsInTier = scoreRanges.get("60-70");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("60-70", newStudentsInTier);
            } else if (score >= 50 && score < 60) {
                String[] studentsInTier = scoreRanges.get("50-60");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("50-60", newStudentsInTier);
            } else if (score >= 40 && score < 50) {
                String[] studentsInTier = scoreRanges.get("40-50");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("40-50", newStudentsInTier);
            } else if (score >= 30 && score < 40) {
                String[] studentsInTier = scoreRanges.get("30-40");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("30-40", newStudentsInTier);
            } else if (score >= 20 && score < 30) {
                String[] studentsInTier = scoreRanges.get("20-30");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("20-30", newStudentsInTier);
            } else if (score >= 10 && score < 20) {
                String[] studentsInTier = scoreRanges.get("10-20");
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put("10-20", newStudentsInTier);
            } else {
                String[] studentsInTier = scoreRanges.get(String.format("%d-%d", score, score));
                String[] newStudentsInTier = addStudent(studentsInTier, studentNames[i]);
                scoreRanges.put(String.format("%d-%d", score, score), newStudentsInTier);
            }
        }
    }

    private static String[] addStudent(String[] students, String studentName) {
        String[] newStudents = new String[students.length + 1];
        System.arraycopy(students, 0, newStudents, 0, students.length);
        newStudents[newStudents.length - 1] = studentName;
        return newStudents;
    }

    public static void main(String[] args) {
        String[] studentNames = {"Alice", "Bob", "Charlie", "David", "Eve"};
        int[] scores = {95, 85, 75, 65, 55};
        categorizeStudentScores(studentNames, scores);

        for (Map.Entry<String, String[]> entry : scoreRanges.entrySet()) {
            System.out.println(entry.getKey() + ": " + String.join(", ", entry.getValue()));
        }
    }
}
