    public static ArrayList<Meeting> organizeMeetings(ArrayList<Meeting> meetings) {
        Collections.sort(meetings, new Comparator<Meeting>() {
            @Override
            public int compare(Meeting m1, Meeting m2) {
                return Integer.compare(m2.urgency, m1.urgency);
            }
        });

        ArrayList<Meeting> processedMeetings = new ArrayList<>();
        PriorityQueue<Meeting> pq = new PriorityQueue<>(Collections.reverseOrder());

        for (Meeting meeting : meetings) {
            pq.add(meeting);
        }

        while (!pq.isEmpty()) {
            Meeting currentMeeting = pq.poll();
            processedMeetings.add(currentMeeting);
        }

        return processedMeetings;
    }

    public static void main(String[] args) {
