        meetings.add(new Meeting("Meeting 1", 3));
        meetings.add(new Meeting("Meeting 2", 1));
        meetings.add(new Meeting("Meeting 3", 2));
        meetings.add(new Meeting("Meeting 4", 4));

        ArrayList<Meeting> processedMeetings = organizeMeetings(meetings);

        for (Meeting meeting : processedMeetings) {
            System.out.println("(" + meeting.name + ", " + meeting.urgency + ")");
