#include <iostream>
#include <vector>
#include <unordered_set>

class Deque {
public:
    void push_back(const std::string& email) {
        back.push(email);
    }

    void pop_front() {
        if (!front.empty()) {
            front.pop();
        }
    }

    bool empty() const {
        return front.empty() && back.empty();
    }

    size_t size() const {
        return front.size() + back.size();
    }

private:
    std::vector<std::string> front;
    std::vector<std::string> back;
};

std::pair<std::vector<std::string>, size_t> deduplicateEmailAddresses(const std::vector<std::string>& emails) {
    std::unordered_set<std::string, std::hash<std::string>> unique_emails;
    Deque email_deque;

    size_t removed_count = 0;

    for (const auto& email : emails) {
        if (unique_emails.find(email) != unique_emails.end()) {
            email_deque.push_back(email);
            removed_count++;
        } else {
            unique_emails.insert(email);
            email_deque.push_back(email);
        }

        if (email_deque.size() > 100) {
            while (!email_deque.empty()) {
                email_deque.pop_front();
            }
        }
    }

    std::vector<std::string> result;
    while (!email_deque.empty()) {
        result.push_back(email_deque.front());
        email_deque.pop_front();
    }

    return {result, removed_count};
}

