std::pair<std::vector<std::string>, int> deduplicateEmailAddresses(const std::vector<std::string>& emailList) {
    int removedCount = 0;
    std::unordered_set<std::string, std::hash<std::string>> uniqueSet;

    if (emailList.size() > 150) {
        for (const auto& email : emailList) {
            if (uniqueSet.find(email) != uniqueSet.end()) {
                removedCount++;
            } else {
                uniqueSet.insert(email);
